const tkp_PelayananPublik = [
{ text: "Anda sedang bertugas di loket pelayanan terpadu saat sistem basis data nasional mengalami gangguan teknis yang mengakibatkan proses verifikasi berkas menjadi sangat lambat, sementara di luar ruangan terjadi penumpukan pemohon yang mulai tidak sabar karena cuaca sangat panas dan sebagian besar dari mereka telah datang dari luar kota. Di saat yang sama, pimpinan sedang mengikuti rapat koordinasi darurat dan memberikan instruksi melalui pesan singkat agar semua staf tetap mengikuti prosedur digital demi validitas data, namun situasi di lapangan semakin tegang dengan adanya beberapa warga yang mulai memicu keributan. Menghadapi kondisi dilematis antara kepatuhan prosedur dan kondusivitas pelayanan ini, tindakan yang paling mencerminkan profesionalisme Anda adalah...", options: [{text: "Menjelaskan secara transparan mengenai gangguan sistem kepada warga dan meminta mereka kembali lagi esok hari agar data tetap valid sesuai instruksi.", val: 2}, {text: "Tetap melayani warga sesuai urutan meskipun sangat lambat dan meminta bantuan petugas keamanan untuk menenangkan kerumunan agar tidak rusuh.", val: 3}, {text: "Menginisiasi pendataan manual secara cermat sebagai cadangan sembari menyediakan ruang tunggu yang lebih nyaman dan air minum bagi warga.", val: 5}, {text: "Mengambil kebijakan untuk memprioritaskan warga yang datang dari jauh agar mereka bisa segera pulang tanpa harus menunggu sistem pulih.", val: 4}, {text: "Menutup loket sementara waktu untuk berkoordinasi dengan tim IT agar sistem bisa segera diperbaiki tanpa gangguan dari keluhan warga.", val: 1}] },
{ text: "Instansi Anda baru saja meluncurkan aplikasi pelayanan mandiri untuk mempercepat proses perizinan, namun dalam praktiknya, banyak kelompok masyarakat lanjut usia dan penyandang disabilitas yang merasa kesulitan menggunakan teknologi tersebut dan tetap datang ke kantor dengan membawa berkas fisik. Rekan kerja Anda menyarankan agar mereka diarahkan untuk meminta bantuan kerabat di rumah atau menggunakan jasa warnet demi konsistensi digitalisasi yang sedang dicanangkan pimpinan, namun hal ini justru menambah beban biaya dan waktu bagi kelompok rentan tersebut. Sebagai bagian dari tim transformasi digital yang juga bertugas di front desk, sikap yang Anda ambil untuk memastikan inklusivitas pelayanan adalah...", options: [{text: "Menyiapkan pojok bantuan digital (helpdesk) khusus untuk mendampingi mereka mengoperasikan aplikasi hingga proses perizinan selesai.", val: 5}, {text: "Memberikan pengecualian dengan tetap memproses berkas fisik mereka secara manual agar kelompok rentan tidak merasa kesulitan.", val: 3}, {text: "Memberikan brosur panduan penggunaan aplikasi yang sangat detail agar mereka bisa mempelajarinya secara mandiri di rumah.", val: 2}, {text: "Menyarankan kepada pimpinan agar aplikasi tersebut diperbaiki UI/UX-nya agar lebih ramah bagi lansia dan penyandang disabilitas.", val: 4}, {text: "Mengikuti saran rekan kerja untuk mengarahkan mereka meminta bantuan pihak ketiga agar target digitalisasi instansi tercapai.", val: 1}] },
{ text: "Anda adalah seorang petugas layanan medis di RSUD yang sedang menangani pasien dalam kondisi darurat di ruang IGD, namun secara tiba-tiba seorang tokoh masyarakat setempat datang bersama keluarganya dan menuntut untuk segera dilayani lebih dahulu karena merasa memiliki pengaruh dan sering membantu operasional rumah sakit. Tokoh tersebut mulai menggunakan pengaruhnya dengan mengancam akan melaporkan kualitas pelayanan Anda ke media massa jika tidak segera diprioritaskan, sementara staf medis lainnya merasa tertekan dan cenderung ingin mengalah demi menghindari konflik berkepanjangan yang dapat merusak citra rumah sakit. Dalam kondisi tekanan publik dan etika profesi seperti ini, tindakan yang paling mencerminkan integritas pelayanan Anda adalah...", options: [{text: "Segera melayani tokoh masyarakat tersebut setelah pasien darurat tertangani demi menjaga hubungan baik dengan tokoh setempat.", val: 4}, {text: "Menjelaskan standar prosedur triase (skala prioritas medis) secara sopan dan tetap fokus menangani pasien yang kondisinya lebih mengancam nyawa.", val: 5}, {text: "Meminta rekan medis lain untuk menangani keluarga tokoh tersebut di ruangan berbeda agar tidak terjadi keributan di ruang IGD.", val: 3}, {text: "Meminta maaf kepada tokoh tersebut dan menjelaskan bahwa Anda hanya menjalankan perintah atasan terkait urutan pelayanan.", val: 2}, {text: "Melaporkan tindakan ancaman tokoh tersebut kepada pihak keamanan rumah sakit untuk segera dikeluarkan karena mengganggu ketertiban.", val: 1}] },
{ text: "Anda sedang bertugas di unit pelayanan perizinan yang sedang menerapkan sistem antrean digital sepenuhnya, namun pada saat jam sibuk, terjadi gangguan koneksi internet massal yang menyebabkan mesin antrean mati dan aplikasi pendaftaran tidak dapat diakses, sementara puluhan warga yang sudah datang sejak pagi mulai melayangkan protes keras karena merasa waktu mereka terbuang sia-sia. Di tengah situasi yang mulai tidak terkendali dan staf lain yang hanya diam menunggu teknisi datang memperbaiki jaringan, tindakan yang paling menunjukkan tanggung jawab Anda sebagai pelayan publik adalah...", options: [{text: "Meminta maaf kepada warga dan menyarankan mereka kembali lagi saat jaringan sudah stabil agar data tidak error.", val: 2}, {text: "Membagikan formulir manual dan mencatat identitas warga sesuai urutan kedatangan agar pelayanan tetap berjalan.", val: 5}, {text: "Memberikan penjelasan mengenai kendala teknis secara detail dan meminta warga untuk bersabar menunggu perbaikan.", val: 3}, {text: "Mengajak perwakilan warga untuk melihat ruang server agar mereka memahami bahwa gangguan memang terjadi secara teknis.", val: 1}, {text: "Berkoordinasi dengan tim IT untuk mempercepat perbaikan sambil membagikan nomor antrean manual sementara.", val: 4}] },
{ text: "Instansi Anda baru saja merilis layanan pengaduan berbasis media sosial untuk mempercepat respon, namun Anda mendapati bahwa banyak laporan yang masuk menggunakan bahasa yang emosional, kasar, bahkan beberapa mengandung informasi yang belum terverifikasi secara akurat terkait kinerja rekan kerja di unit lain. Jika Anda adalah admin yang bertanggung jawab mengelola akun tersebut dan dituntut untuk menjaga citra instansi sekaligus memberikan kepuasan pada pelapor yang sedang marah tersebut, maka langkah strategis yang Anda ambil adalah...", options: [{text: "Membalas komentar tersebut dengan bahasa yang sopan dan meminta pelapor menyampaikan data pendukung melalui saluran resmi.", val: 4}, {text: "Menghapus komentar yang mengandung kata-kata kasar demi menjaga etika di ruang publik dan citra instansi pemerintah.", val: 1}, {text: "Memberikan tanggapan yang empati, memvalidasi keluhan mereka, serta segera mengoordinasikan fakta lapangan dengan unit terkait.", val: 5}, {text: "Mengabaikan laporan yang tidak sopan dan hanya merespons laporan yang disampaikan dengan bahasa yang baik dan jelas datanya.", val: 2}, {text: "Membuat postingan klarifikasi umum untuk menjawab semua keluhan yang masuk tanpa harus membalas komentar satu per satu.", val: 3}] },
{ text: "Anda sedang melayani seorang ibu lanjut usia yang kesulitan memahami prosedur pengisian formulir digital di layar sentuh kantor Anda, namun di saat yang sama, atasan Anda memanggil melalui interkom untuk segera menyerahkan laporan evaluasi yang harus dipresentasikan dalam rapat pimpinan lima menit lagi. Melihat antrean di belakang ibu tersebut mulai memanjang dan beberapa pemohon muda mulai menunjukkan gestur tidak sabar, tindakan yang paling mencerminkan prinsip keadilan dan profesionalisme Anda adalah...", options: [{text: "Memohon izin kepada ibu tersebut untuk meninggalkan loket sejenak guna menyerahkan laporan kepada atasan Anda.", val: 2}, {text: "Meminta warga di antrean belakang yang lebih muda untuk membantu ibu tersebut mengisi formulir agar antrean cepat bergerak.", val: 1}, {text: "Membantu ibu tersebut menyelesaikan pengisian formulir dengan cepat sembari meminta rekan sebelah untuk mengantarkan laporan ke atasan.", val: 5}, {text: "Menyerahkan laporan kepada atasan terlebih dahulu secara cepat, lalu kembali lagi untuk fokus membantu ibu tersebut hingga selesai.", val: 3}, {text: "Memberikan panduan singkat kepada ibu tersebut dan memintanya mencoba kembali agar Anda bisa segera melapor ke atasan.", val: 4}] },
{ text: "Sebagai petugas di loket layanan kependudukan yang sangat padat, Anda mendapati sistem pusat sedang mengalami gangguan sinkronisasi data nasional yang mengakibatkan waktu tunggu meningkat tiga kali lipat dari biasanya, sementara puluhan warga di ruang tunggu mulai menunjukkan keresahan bahkan ada yang mencoba memprovokasi warga lain untuk melakukan aksi protes secara langsung kepada petugas loket. Di tengah tekanan situasi yang mulai memanas dan minimnya informasi kapan sistem akan pulih sepenuhnya, tindakan yang paling mencerminkan integritas Anda sebagai pelayan masyarakat adalah...", options: [{text: "Meminta maaf secara personal kepada warga yang paling vokal dan menjanjikan prioritas layanan esok hari.", val: 2}, {text: "Keluar menemui warga secara langsung untuk menjelaskan kendala sistem dan memberikan kepastian proses manual tetap berjalan.", val: 5}, {text: "Tetap tenang bekerja di balik loket agar tidak terpengaruh emosi warga sembari menunggu teknisi memperbaiki sistem.", val: 3}, {text: "Mengajak perwakilan warga berdiskusi di ruang tertutup untuk meredam ketegangan agar tidak mengganggu fokus staf lain.", val: 4}, {text: "Menutup loket sementara waktu demi keamanan petugas sampai suasana kondusif dan sistem kembali normal.", val: 1}] },
{ text: "Instansi Anda baru saja merilis aplikasi pelayanan mandiri untuk memangkas birokrasi, namun Anda memperhatikan bahwa kelompok masyarakat rentan seperti penyandang disabilitas dan lansia seringkali merasa kebingungan dan justru menghabiskan waktu lebih lama di depan mesin mandiri tersebut tanpa ada yang membantu, sementara rekan-rekan Anda cenderung mengabaikan mereka karena merasa tugas tersebut sudah digantikan oleh mesin dan ingin fokus pada target administrasi internal. Sebagai bagian dari tim yang bertanggung jawab atas kenyamanan pengguna, langkah strategis yang harus Anda ambil untuk memastikan asas keadilan dalam pelayanan adalah...", options: [{text: "Mengusulkan kepada pimpinan untuk menambah petugas khusus pendamping di area mesin mandiri bagi kelompok rentan.", val: 4}, {text: "Memberikan bantuan secara langsung kepada setiap warga yang terlihat kesulitan hingga urusan mereka selesai.", val: 3}, {text: "Membuat petunjuk penggunaan aplikasi dalam bentuk gambar yang lebih sederhana dan berukuran besar di area mesin.", val: 2}, {text: "Menginisiasi pembentukan unit 'Mobile Service' bagi lansia agar mereka tidak perlu datang ke kantor.", val: 1}, {text: "Mengevaluasi alur layanan dan menetapkan pendampingan aktif sebagai standar operasional bagi pengguna berkebutuhan khusus.", val: 5}] },
{ text: "Anda sedang menangani proses administrasi yang sangat mendesak milik seorang pemohon yang juga merupakan relawan sosial yang sangat berjasa di daerah Anda, namun di saat verifikasi berlangsung, Anda menemukan bahwa salah satu dokumen pendukungnya tidak memenuhi kriteria terbaru yang baru saja ditetapkan pimpinan pusat pagi ini, padahal pemohon tersebut sudah menunggu lama dan dokumen lamanya sebenarnya masih sah secara aturan lama. Jika Anda menolak, prosesnya akan tertunda jauh lebih lama dan menghambat kegiatan sosialnya, sementara jika Anda menerimanya, Anda berisiko menyalahi arahan terbaru pimpinan, maka sikap profesional yang Anda tunjukkan adalah...", options: [{text: "Memproses dokumen tersebut mengingat jasa sosial pemohon sangat besar bagi masyarakat luas di daerah Anda.", val: 1}, {text: "Menjelaskan perubahan aturan tersebut dengan empati dan membantu pemohon melakukan perbaikan dokumen saat itu juga.", val: 5}, {text: "Berkonsultasi dengan atasan untuk meminta diskresi khusus bagi pemohon tersebut agar proses tetap dapat berjalan lancar.", val: 4}, {text: "Menolak dokumen tersebut sesuai aturan baru dan meminta pemohon untuk mengurusnya kembali sesuai prosedur yang berlaku.", val: 3}, {text: "Memberikan tanda terima sementara sambil meminta pemohon melengkapi kekurangan dokumennya dalam waktu satu minggu.", val: 2}] },
{ text: "Instansi Anda baru saja menerapkan sistem antrean terintegrasi berbasis aplikasi untuk meminimalisir kerumunan, namun pada pelaksanaannya, seorang warga datang dari wilayah pelosok dengan menempuh perjalanan jauh dan tidak memiliki ponsel pintar untuk mendaftar di aplikasi tersebut. Di sisi lain, kuota layanan tatap muka untuk hari itu sudah habis terisi oleh pendaftar daring, sementara Anda sedang diawasi ketat oleh sistem audit kinerja yang mencatat setiap pelayanan di luar prosedur sebagai pelanggaran administrasi. Menghadapi kondisi di mana warga tersebut memohon bantuan karena keterbatasan akses teknologi dan jarak tempuh, tindakan yang paling tepat Anda lakukan adalah...", options: [{text: "Meminta maaf dan menjelaskan bahwa kuota pendaftaran telah penuh demi menjaga keadilan bagi pengguna aplikasi lain.", val: 2}, {text: "Membantu warga tersebut mendaftar aplikasi menggunakan perangkat kantor untuk jadwal pelayanan di hari berikutnya.", val: 3}, {text: "Memberikan penjelasan mengenai sistem pendaftaran online dan membantu mencarikan penginapan terdekat bagi warga tersebut.", val: 1}, {text: "Mengupayakan pelayanan saat itu juga dengan berkoordinasi dengan atasan terkait adanya urgensi keterbatasan akses teknologi.", val: 5}, {text: "Menyarankan warga tersebut untuk pulang dan meminta bantuan kerabat di rumah agar didaftarkan secara online terlebih dahulu.", val: 4}] },
{ text: "Anda bekerja di unit layanan perizinan yang sangat sibuk, dan sore itu seorang pengusaha besar yang merupakan mitra strategis instansi Anda datang untuk mengurus dokumen penting yang sangat ia butuhkan untuk presentasi di luar negeri esok pagi. Namun, waktu operasional kantor sudah tersisa sepuluh menit lagi dan secara teknis dokumen tersebut baru bisa terbit minimal dalam dua jam kerja karena memerlukan verifikasi bertahap dari beberapa meja. Pengusaha tersebut mulai menjanjikan donasi peralatan kantor terbaru jika Anda bersedia mengusahakan dokumennya selesai sebelum kantor tutup, maka sebagai petugas yang memegang teguh prinsip pelayanan prima, respons Anda adalah...", options: [{text: "Menolak tawaran donasi tersebut dengan tegas namun tetap mengupayakan verifikasi secepat mungkin sesuai prosedur yang berlaku.", val: 4}, {text: "Menjelaskan secara transparan mengenai estimasi waktu proses dan menyarankan pemohon untuk menunggu hingga proses selesai secara reguler.", val: 5}, {text: "Meminta bantuan rekan dari unit verifikasi untuk lembur sejenak guna membantu menyelesaikan dokumen mitra strategis tersebut.", val: 3}, {text: "Menyarankan pengusaha tersebut untuk datang lebih awal esok pagi agar menjadi prioritas utama saat kantor baru dibuka.", val: 2}, {text: "Menerima dokumen tersebut dan menjanjikan akan mengirimkannya via kurir ke bandara saat dokumen selesai diproses malam nanti.", val: 1}] },
{ text: "Instansi Anda baru saja meresmikan sistem pengaduan terpadu berbasis kecerdasan buatan (AI) untuk mempercepat respons terhadap keluhan warga, namun Anda melihat bahwa sistem tersebut seringkali memberikan jawaban otomatis yang kaku dan kurang tepat dalam menangani kasus-kasus sensitif seperti pengaduan terkait kekerasan dalam rumah tangga atau sengketa lahan yang emosional. Sebagai staf yang bertugas mengawasi kualitas layanan, saat Anda melihat volume pengaduan meningkat namun tingkat kepuasan warga justru menurun karena respons robotik tersebut, langkah yang Anda sintesiskan untuk memperbaiki kualitas pelayanan adalah...", options: [{text: "Menyarankan kepada pimpinan untuk menonaktifkan sistem AI dan kembali menggunakan tenaga manusia sepenuhnya.", val: 2}, {text: "Memperbanyak daftar jawaban otomatis (template) pada sistem AI agar mampu mencakup lebih banyak jenis pengaduan.", val: 3}, {text: "Mengusulkan sistem 'Hybrid Service' di mana AI hanya untuk memilah data, sedangkan respons kasus sensitif ditangani manusia.", val: 5}, {text: "Meminta tim IT untuk meng-upgrade versi AI yang lebih canggih agar mampu memahami emosi pengadu dengan lebih baik.", val: 4}, {text: "Melakukan evaluasi mingguan terhadap performa AI dan melaporkan kegagalannya kepada vendor penyedia sistem.", val: 1}] },
{ text: "Instansi Anda sedang mengadakan program layanan jemput bola di wilayah terpencil, namun karena kendala cuaca buruk dan medan yang berat, kendaraan operasional yang membawa peralatan verifikasi digital mengalami kerusakan parah, sementara ratusan warga sudah berkumpul dan menunggu di balai desa sejak pagi. Beberapa tokoh masyarakat mulai menyatakan kekecewaannya karena merasa pemerintah tidak serius memberikan bantuan, sementara tim teknis memperkirakan perbaikan kendaraan membutuhkan waktu setidaknya lima jam. Dalam kondisi keterbatasan sarana dan tekanan ekspektasi massa yang tinggi, tindakan yang paling mencerminkan dedikasi pelayanan Anda adalah...", options: [{text: "Meminta maaf kepada warga dan menjadwalkan ulang kunjungan di lain waktu saat cuaca dan sarana sudah lebih siap.", val: 2}, {text: "Mengumpulkan dokumen warga secara manual untuk diproses di kantor pusat dan menjanjikan pengiriman hasilnya via pos.", val: 5}, {text: "Memberikan penyuluhan dan sosialisasi mengenai program-program instansi agar waktu tunggu warga tetap terisi dengan informasi bermanfaat.", val: 3}, {text: "Mengupayakan peminjaman perangkat komputer milik sekolah atau kantor desa setempat agar proses verifikasi bisa segera dimulai.", val: 4}, {text: "Menenangkan tokoh masyarakat dengan menjelaskan kendala teknis yang terjadi agar mereka dapat membantu meredam kekecewaan warga.", val: 1}] },
{ text: "Anda bertugas di bagian pengaduan masyarakat dan menerima laporan dari seorang warga mengenai dugaan pungutan liar yang dilakukan oleh rekan kerja satu tim Anda yang selama ini dikenal memiliki prestasi kerja sangat baik dan merupakan orang kepercayaan pimpinan. Warga tersebut membawa bukti rekaman suara, namun ia sangat ketakutan identitasnya terbongkar karena ia masih memiliki urusan administrasi yang sedang berjalan di unit Anda. Di sisi lain, rekan kerja Anda tersebut sedang mencalonkan diri sebagai pegawai teladan tahun ini. Menghadapi situasi yang melibatkan integritas tim dan perlindungan pelapor ini, langkah yang paling profesional Anda ambil adalah...", options: [{text: "Menyarankan warga tersebut untuk melaporkan temuannya langsung ke pimpinan agar masalah segera ditangani secara objektif.", val: 3}, {text: "Menerima laporan dan bukti tersebut, menjamin kerahasiaan identitas pelapor, serta meneruskannya ke unit pengawasan internal.", val: 5}, {text: "Menegur rekan kerja Anda secara personal agar ia segera menghentikan tindakannya dan mengembalikan uang milik warga tersebut.", val: 1}, {text: "Melakukan investigasi mandiri terlebih dahulu untuk memastikan kebenaran rekaman tersebut sebelum melaporkannya ke pihak berwenang.", val: 2}, {text: "Mencatat laporan tersebut dalam sistem pengaduan resmi namun meminta pelapor untuk melengkapi identitasnya demi validitas data.", val: 4}] },
{ text: "Dalam rangka meningkatkan efisiensi, instansi Anda mewajibkan seluruh pengajuan perizinan dilakukan melalui portal online, namun Anda menyadari bahwa sistem tersebut sering mengalami bug pada jam-jam tertentu yang menyebabkan data pemohon hilang sebelum sempat tersimpan, sehingga banyak warga harus mengisi ulang formulir berkali-kali. Ketika seorang pemohon yang sudah emosional datang ke kantor Anda karena telah gagal mengunggah dokumen sebanyak lima kali padahal batas waktu pengajuannya berakhir hari ini, sementara sistem pusat masih dalam perbaikan berkala, respons yang paling tepat untuk menjaga kualitas pelayanan adalah...", options: [{text: "Membantu pemohon mengunggah dokumennya secara langsung melalui koneksi internal kantor yang biasanya lebih stabil dari jaringan luar.", val: 5}, {text: "Menyarankan pemohon untuk mencoba kembali di jam-jam sepi seperti tengah malam agar terhindar dari gangguan traffic sistem.", val: 2}, {text: "Mencatat data pemohon secara manual dan menjanjikan akan memasukkannya ke sistem saat perbaikan berkala telah selesai dilakukan.", val: 4}, {text: "Memberikan surat keterangan gangguan sistem kepada pemohon agar ia mendapatkan kompensasi perpanjangan waktu dari unit terkait.", val: 3}, {text: "Menghubungi tim IT pusat untuk memprioritaskan akun pemohon tersebut agar bisa segera menyimpan data di portal perizinan.", val: 1}] },
{ text: "Anda sedang memimpin sebuah tim di unit layanan perizinan yang baru saja menerapkan standar waktu penyelesaian dokumen maksimal tiga hari kerja, namun di saat volume pengajuan sedang melonjak tajam, dua staf inti di bagian verifikasi mendadak jatuh sakit sehingga terjadi penumpukan berkas yang mustahil diselesaikan tepat waktu. Sementara itu, beberapa pengusaha yang merasa dirugikan mulai mengancam akan memviralkan keterlambatan ini ke media sosial karena menganggap instansi Anda tidak konsisten dengan janji layanan. Menghadapi situasi di mana sumber daya manusia terbatas sementara tuntutan transparansi publik sangat tinggi, langkah strategis yang Anda ambil adalah...", options: [{text: "Meminta staf yang tersisa untuk lembur setiap hari agar semua berkas tetap selesai dalam tiga hari sesuai standar.", val: 3}, {text: "Mengumumkan secara transparan mengenai keterlambatan proses dan memprioritaskan izin yang paling mendesak dampaknya bagi ekonomi warga.", val: 5}, {text: "Memberikan penjelasan kepada pengusaha yang mengancam tersebut secara personal agar mereka memahami kondisi internal tim Anda.", val: 2}, {text: "Mengambil alih tugas verifikasi secara langsung dan meminta bantuan tenaga administrasi dari unit lain untuk membantu tugas rutin.", val: 4}, {text: "Menutup sementara pendaftaran baru sampai tumpukan berkas verifikasi selesai ditangani demi menjaga kualitas layanan.", val: 1}] },
{ text: "Sebagai petugas di pusat layanan informasi publik, Anda menerima kedatangan seorang warga yang tampak sangat bingung dan frustrasi karena permohonan bantuan sosialnya ditolak oleh sistem, padahal ia merasa sangat membutuhkan dan sudah memenuhi semua persyaratan yang ia ketahui. Setelah Anda periksa, ternyata ada ketidaksinkronan data antara alamat di KTP dengan data di basis data kemiskinan pusat yang bukan merupakan wewenang instansi Anda untuk mengubahnya. Melihat warga tersebut mulai putus asa dan tidak tahu harus melapor ke mana lagi, tindakan yang paling mencerminkan prinsip pelayanan terpadu adalah...", options: [{text: "Memberikan nomor telepon kantor pusat di Jakarta dan menyarankan warga tersebut untuk menghubungi mereka secara mandiri.", val: 2}, {text: "Menjelaskan bahwa kesalahan bukan pada unit Anda dan menyarankan warga tersebut untuk mengurus perubahan data di dinas kependudukan.", val: 3}, {text: "Membantu warga tersebut membuat laporan pengaduan resmi melalui sistem internal agar data segera diverifikasi ulang oleh pihak terkait.", val: 4}, {text: "Menghubungi rekan lintas instansi secara langsung untuk memastikan prosedur perbaikan data warga tersebut dan mendampinginya hingga tuntas.", val: 5}, {text: "Meminta maaf atas ketidaknyamanan tersebut dan memberikan sembako pribadi sebagai bentuk empati atas kegagalan sistem.", val: 1}] },
{ text: "Instansi Anda meluncurkan fitur live chat untuk konsultasi pajak yang diklaim responsif dalam lima menit, namun Anda menyadari bahwa karena kurangnya jumlah admin, banyak pesan yang hanya dibalas dengan jawaban otomatis 'mohon tunggu' tanpa ada kejelasan lebih lanjut, yang justru memicu kemarahan pengguna di kolom komentar aplikasi. Saat Anda ditugaskan untuk mengevaluasi efektivitas fitur ini, sementara anggaran untuk menambah admin baru telah ditutup untuk tahun ini, inovasi pelayanan yang paling tepat Anda usulkan adalah...", options: [{text: "Menutup fitur live chat untuk sementara dan mengalihkan konsultasi melalui surat elektronik (email) yang lebih mudah dikelola.", val: 2}, {text: "Membuat jadwal piket bergilir bagi seluruh staf di kantor untuk bergantian menjadi admin live chat setiap dua jam sekali.", val: 4}, {text: "Mengintegrasikan daftar pertanyaan yang paling sering ditanyakan (FAQ) ke dalam sistem otomatis agar warga bisa mencari jawaban mandiri.", val: 3}, {text: "Mengusulkan kolaborasi dengan mahasiswa magang untuk membantu memilah pesan yang masuk sebelum dijawab oleh admin ahli.", val: 5}, {text: "Memberikan pengumuman bahwa waktu respons rata-rata kini menjadi satu jam agar masyarakat tidak memiliki ekspektasi terlalu tinggi.", val: 1}] },
{ text: "Anda sedang melayani antrean di loket terakhir menjelang jam istirahat saat seorang warga lanjut usia datang dengan kondisi fisik yang sangat lemas dan memohon agar dokumennya diproses segera karena ia harus mengejar jadwal bus terakhir untuk kembali ke desa yang sangat jauh. Namun, setelah diperiksa, terdapat satu persyaratan administrasi kecil yang kurang dan menurut aturan terbaru, dokumen tersebut mutlak diperlukan agar sistem tidak menolak permohonan tersebut secara otomatis. Di saat rekan-rekan Anda sudah bersiap meninggalkan meja kerja dan warga di belakang mulai memprotes jika Anda memberikan pengecualian, tindakan yang paling menunjukkan etika pelayanan prima Anda adalah...", options: [{text: "Meminta maaf dan menjelaskan aturan terbaru dengan sopan serta menyarankan warga tersebut menginap agar bisa melengkapinya esok pagi.", val: 2}, {text: "Membantu warga tersebut menghubungi kerabatnya untuk mengirimkan foto dokumen yang kurang melalui pesan instan agar bisa Anda cetak dan proses saat itu juga.", val: 5}, {text: "Memberikan kebijakan khusus dengan memproses dokumennya terlebih dahulu dan meminta warga tersebut berjanji mengirimkan kekurangannya via pos.", val: 3}, {text: "Mengarahkan warga tersebut untuk beristirahat di ruang tunggu sembari Anda mencoba berkonsultasi dengan atasan mengenai kemungkinan diskresi.", val: 4}, {text: "Tetap mengikuti prosedur dengan menolak permohonan tersebut demi menjaga keadilan bagi pengantre lain yang sudah melengkapi berkas.", val: 1}] },
{ text: "Sebagai pengelola layanan informasi di sebuah kementerian, Anda mendapati bahwa sebuah isu negatif mengenai keterlambatan penyaluran bantuan sosial sedang menjadi tren di media sosial dan memicu gelombang kritik tajam dari netizen. Berdasarkan pengecekan internal, keterlambatan tersebut disebabkan oleh adanya verifikasi data ganda agar bantuan tepat sasaran, namun masyarakat terlanjur berasumsi bahwa ada unsur kesengajaan atau korupsi di balik keterlambatan tersebut. Dalam posisi sebagai jembatan komunikasi antara instansi dan masyarakat, langkah strategis yang Anda ambil untuk memulihkan kepercayaan publik adalah...", options: [{text: "Segera membuat infografis transparan mengenai alur verifikasi data dan progres penyaluran bantuan sebagai bentuk pertanggungjawaban publik.", val: 5}, {text: "Memberikan klarifikasi singkat melalui kolom komentar di media sosial untuk membantah tuduhan korupsi yang dilayangkan netizen.", val: 2}, {text: "Menghubungi tokoh masyarakat atau pemengaruh (influencer) untuk membantu menjelaskan kondisi sebenarnya agar suasana lebih tenang.", val: 4}, {text: "Menunggu instruksi resmi dari pimpinan kementerian sebelum memberikan tanggapan apapun guna menghindari kesalahan informasi.", val: 1}, {text: "Mengadakan konferensi pers mendadak untuk menjelaskan kendala teknis yang dihadapi tim verifikator di lapangan secara detail.", val: 3}] },
{ text: "Instansi Anda baru saja meresmikan gedung baru dengan fasilitas modern, namun Anda menyadari bahwa akses masuk utama bagi penyandang disabilitas (ramp) terhalang oleh parkir kendaraan operasional pimpinan yang merasa area tersebut paling dekat dengan pintu masuk. Beberapa tamu penyandang disabilitas mulai kesulitan untuk masuk dan harus menempuh jalur memutar yang cukup jauh. Sebagai staf yang bertugas memastikan kenyamanan layanan bagi seluruh lapisan masyarakat, sementara Anda merasa sungkan untuk menegur pimpinan secara langsung, tindakan yang paling tepat Anda lakukan adalah...", options: [{text: "Membantu tamu penyandang disabilitas tersebut melewati jalur memutar agar mereka tetap merasa terlayani dengan baik.", val: 2}, {text: "Memasang tanda dilarang parkir di area akses disabilitas tersebut dan mengarahkan petugas keamanan untuk menertibkan area tanpa terkecuali.", val: 5}, {text: "Melaporkan kondisi tersebut kepada sekretaris pimpinan agar pimpinan diingatkan secara halus untuk memindahkan kendaraannya.", val: 4}, {text: "Memotret kondisi tersebut dan menjadikannya bahan evaluasi dalam rapat staf bulanan agar tidak terulang kembali di masa depan.", val: 3}, {text: "Membiarkan hal tersebut karena merasa itu adalah wewenang bagian keamanan dan bukan merupakan tugas pokok fungsi Anda.", val: 1}] },
{ text: "Anda sedang melayani antrean panjang saat seorang warga menuntut pelayanan instan karena mengaku sebagai kerabat dekat kepala dinas Anda, sementara warga lain yang sudah antre sejak pagi mulai menunjukkan ketidaksenangan. Menghadapi upaya intervensi personal yang berpotensi merusak ketertiban dan keadilan pelayanan ini, sikap profesional yang Anda tunjukkan adalah...", options: [{text: "Meminta izin warga lain untuk mendahulukannya demi menjaga hubungan baik dengan atasan.", val: 1}, {text: "Menjelaskan standar antrean secara sopan dan tetap melayaninya sesuai nomor urutan.", val: 5}, {text: "Mengarahkan warga tersebut untuk menemui kepala dinas secara langsung di ruang kerja.", val: 2}, {text: "Meminta rekan kerja lain untuk melayaninya di loket berbeda agar tidak memicu keributan.", val: 3}, {text: "Melayaninya dengan cepat sambil memberikan edukasi tentang pentingnya budaya antre.", val: 4}] },
{ text: "Unit kerja Anda baru saja meluncurkan layanan berbasis aplikasi, namun Anda melihat banyak warga usia lanjut yang datang ke kantor masih membawa berkas fisik dan tampak bingung dengan prosedur digital yang wajib diterapkan. Sebagai petugas garda terdepan, langkah yang Anda ambil untuk menjembatani kesenjangan digital ini tanpa menghambat arus pelayanan adalah...", options: [{text: "Menyiapkan tablet khusus dan mendampingi warga tersebut melakukan input data secara digital.", val: 5}, {text: "Menyarankan warga tersebut pulang dan meminta bantuan keluarga yang lebih mengerti teknologi.", val: 2}, {text: "Tetap memproses berkas fisik mereka secara manual untuk mempercepat selesainya antrean.", val: 3}, {text: "Memberikan brosur panduan langkah-langkah penggunaan aplikasi agar dipelajari di rumah.", val: 4}, {text: "Mengarahkan mereka untuk menggunakan jasa pengetikan di luar kantor guna mengisi aplikasi.", val: 1}] },
{ text: "Saat jam pelayanan hampir berakhir, terjadi kerusakan pada alat pencetakan dokumen yang menyebabkan satu orang pemohon terakhir tidak bisa menerima hasilnya hari ini, padahal ia sangat membutuhkannya untuk persyaratan pendaftaran sekolah anaknya besok pagi. Mengingat teknisi baru akan datang esok hari, tindakan solutif yang paling mencerminkan dedikasi Anda adalah...", options: [{text: "Memberikan nomor kontak teknisi agar pemohon bisa menanyakan langsung kapan alat selesai diperbaiki.", val: 1}, {text: "Meminta maaf dan menyarankan pemohon untuk datang paling awal saat kantor dibuka esok hari.", val: 3}, {text: "Memberikan salinan digital atau dokumen sementara yang telah disahkan secara legal oleh pimpinan.", val: 5}, {text: "Menyarankan pemohon mencari kantor cabang lain yang alat cetaknya tidak mengalami kerusakan.", val: 2}, {text: "Mengupayakan penggunaan alat cetak di unit kerja lain yang masih berfungsi meski harus lembur.", val: 4}] },
{ text: "Anda sedang melayani antrean yang sangat panjang ketika tiba-tiba seorang warga paruh baya jatuh pingsan di ruang tunggu, sementara rekan-rekan Anda yang lain sedang sibuk melayani pemohon di loket masing-masing dan petugas kesehatan kantor sedang tidak berada di tempat. Di tengah kerumunan yang mulai panik dan antrean yang menuntut untuk tetap dilayani dengan cepat, tindakan yang paling mencerminkan kepedulian dan profesionalisme Anda adalah...", options: [{text: "Meminta bantuan warga lain di antrean untuk membantu mengangkat warga tersebut ke ruang kesehatan.", val: 3}, {text: "Segera keluar loket untuk memberikan pertolongan pertama dan meminta rekan lain mengalihkan antrean Anda sementara.", val: 5}, {text: "Menghubungi petugas keamanan untuk segera menangani warga yang pingsan agar pelayanan loket tetap berjalan.", val: 4}, {text: "Mengumumkan kepada warga untuk tetap tenang dan tetap fokus melayani antrean agar tidak terjadi penumpukan.", val: 2}, {text: "Menutup loket Anda sementara dan mencari kotak pertolongan pertama sembari meminta warga bersabar.", val: 1}] },
{ text: "Instansi Anda menerapkan sistem pendaftaran daring sepenuhnya, namun pagi ini server pusat mengalami gangguan sehingga data pemohon tidak muncul di layar kerja Anda, sementara banyak warga sudah membawa bukti pendaftaran cetak dan menuntut layanan saat itu juga karena sebagian besar adalah pekerja yang hanya memiliki waktu izin singkat. Sebagai garda terdepan, menyikapi kemacetan sistem digital yang menghambat hak akses warga ini, langkah paling tepat yang Anda ambil adalah...", options: [{text: "Memvalidasi bukti pendaftaran cetak warga secara manual dan tetap memberikan layanan secara luring.", val: 5}, {text: "Meminta warga meninggalkan nomor telepon untuk dihubungi kembali setelah sistem kembali normal.", val: 3}, {text: "Memberikan penjelasan mengenai gangguan teknis dan menyarankan warga datang kembali esok hari.", val: 2}, {text: "Meminta warga menunggu di ruang tunggu sampai tim IT berhasil memperbaiki gangguan server tersebut.", val: 1}, {text: "Berkoordinasi dengan atasan untuk memberikan surat keterangan bahwa warga telah datang namun sistem bermasalah.", val: 4}] },
{ text: "Di tengah upaya instansi Anda mencapai target kepuasan masyarakat, Anda melihat seorang rekan kerja seringkali memberikan informasi yang kurang akurat kepada pemohon karena ingin menyelesaikan pelayanan secepat mungkin, sehingga banyak pemohon yang harus kembali lagi karena berkasnya ternyata masih salah. Mengetahui pola kerja rekan yang merugikan masyarakat secara jangka panjang demi mengejar target kecepatan pribadi ini, sikap Anda adalah...", options: [{text: "Melaporkan tindakan rekan tersebut kepada atasan agar diberikan teguran dan pelatihan kembali.", val: 4}, {text: "Menegur rekan tersebut secara langsung dan memintanya untuk lebih teliti demi kepuasan warga.", val: 3}, {text: "Memberikan contoh cara melayani yang benar dengan tetap teliti meskipun antrean sedang padat.", val: 2}, {text: "Mengajak rekan tersebut berdiskusi mengenai dampak buruk informasi yang salah bagi citra instansi.", val: 5}, {text: "Membantu mengoreksi informasi yang diberikan rekan tersebut jika Anda melihat ada kesalahan.", val: 1}] },
{ text: "Anda sedang melayani warga di loket saat seorang ibu hamil tua yang mengantre di barisan belakang tampak lemas dan hampir pingsan karena suhu ruangan yang panas akibat AC mati. Sementara itu, antrean di depan Anda masih tersisa lima orang yang sudah menunggu sangat lama dan mulai sensitif terhadap isu penyerobotan antrean. Menghadapi kondisi darurat di tengah ketegangan antrean ini, tindakan paling tepat Anda adalah...", options: [{text: "Meminta izin warga paling depan untuk mendahulukan ibu tersebut.", val: 4}, {text: "Meminta petugas keamanan membawa ibu tersebut ke ruang medis segera.", val: 3}, {text: "Mengajak ibu tersebut ke kursi prioritas dan tetap melayani sesuai urutan.", val: 2}, {text: "Mengambil inisiatif mengarahkan ibu tersebut ke loket khusus prioritas.", val: 5}, {text: "Memberikan air minum dan memintanya bersabar menunggu giliran.", val: 1}] },
{ text: "Instansi Anda menerapkan sistem perizinan digital sepenuhnya, namun hari ini terjadi gagal sistem (server down) saat banyak pengusaha yang sedang mengejar tenggat waktu investasi datang ke kantor Anda. Rekan kerja Anda menyarankan untuk menolak semua layanan sampai sistem pulih, namun Anda melihat hal ini akan sangat merugikan kredibilitas instansi. Sebagai garda terdepan, menyikapi kemacetan sistem digital ini, langkah yang paling menunjukkan tanggung jawab adalah...", options: [{text: "Menghubungi tim IT pusat agar sistem segera diperbaiki secepat mungkin.", val: 2}, {text: "Meminta nomor kontak semua pengusaha untuk dihubungi saat sistem normal.", val: 3}, {text: "Mengarahkan pengusaha untuk mencoba kembali di kantor wilayah lain.", val: 1}, {text: "Memberikan penjelasan transparan dan janji penyelesaian via email nanti.", val: 4}, {text: "Menerima berkas fisik sementara sebagai bukti pendaftaran agar tidak terlambat.", val: 5}] },
{ text: "Anda mendapati seorang warga sedang marah-marah di ruang tunggu karena merasa dipermainkan oleh informasi yang berbeda-beda dari petugas sebelumnya terkait persyaratan izin usaha, sehingga ia harus bolak-balik membawa dokumen yang salah. Meskipun warga tersebut membentak Anda yang tidak tahu-menahu masalah sebelumnya, sikap profesional yang harus Anda tunjukkan adalah...", options: [{text: "Mendengarkan keluhannya dengan sabar dan segera membantu verifikasi dokumennya.", val: 5}, {text: "Menjelaskan bahwa kesalahan informasi tersebut bukan berasal dari diri Anda.", val: 1}, {text: "Meminta maaf atas kesalahan rekan sebelumnya dan memberikan brosur panduan.", val: 3}, {text: "Meminta warga tersebut tenang dan menunggunya sampai emosinya stabil kembali.", val: 2}, {text: "Mengantarkan warga tersebut langsung ke atasan agar masalahnya segera tuntas.", val: 4}] },
{ text: "Anda sedang melayani antrean di loket yang sangat padat saat seorang warga lanjut usia tampak kebingungan di depan mesin antrean digital karena tidak ada petugas jaga di area tersebut, sementara rekan-rekan Anda sedang fokus pada layanan di meja masing-masing agar target waktu penyelesaian dokumen tercapai. Sebagai ASN yang menjunjung tinggi aksesibilitas layanan bagi semua kalangan, tindakan yang paling tepat Anda lakukan adalah...", options: [{text: "Meminta izin sebentar kepada pemohon di depan Anda untuk membantu warga lansia tersebut.", val: 4}, {text: "Meminta petugas keamanan yang sedang berjaga di pintu masuk untuk membantu warga tersebut.", val: 3}, {text: "Memberi isyarat kepada rekan kerja yang bebannya lebih ringan agar membantu warga tersebut.", val: 2}, {text: "Mengajak warga lansia tersebut ke loket Anda untuk dibantu prosesnya secara langsung.", val: 5}, {text: "Menunggu warga tersebut menghampiri loket Anda sendiri untuk menanyakan prosedur.", val: 1}] },
{ text: "Unit kerja Anda baru saja meluncurkan aplikasi pelayanan baru, namun Anda menyadari bahwa sistem tersebut sering mengalami error saat mengunggah dokumen berukuran besar, sehingga banyak warga mengeluh di media sosial karena gagal mendapatkan nomor antrean daring. Ketika seorang warga datang ke kantor dengan wajah emosional karena telah mencoba mengunggah berkas berkali-kali namun gagal, sementara batas waktu pengajuannya hampir habis, langkah Anda adalah...", options: [{text: "Membantu warga tersebut mengunggah berkas menggunakan jaringan internal kantor.", val: 5}, {text: "Menjelaskan kendala sistem dan meminta warga mencoba lagi saat lalu lintas data sepi.", val: 2}, {text: "Mencatat keluhan warga tersebut untuk dilaporkan kepada tim IT pusat segera.", val: 3}, {text: "Menerima berkas fisik warga secara manual untuk diproses oleh bagian verifikasi.", val: 4}, {text: "Menyarankan warga untuk mengompres ukuran dokumen agar sesuai dengan kapasitas sistem.", val: 1}] },
{ text: "Sore hari saat jam pelayanan akan tutup, seorang warga datang membawa berkas yang tidak lengkap karena salah memahami informasi di situs resmi instansi Anda, sementara ia mengaku sudah meminta izin cuti dari pekerjaannya hanya untuk mengurus hal tersebut hari ini. Di sisi lain, rekan-rekan Anda sudah bersiap untuk pulang karena sistem kantor akan dimatikan secara otomatis sepuluh menit lagi. Menghadapi situasi yang bersumber dari kesalahan informasi instansi ini, sikap Anda adalah...", options: [{text: "Meminta maaf dan meminta warga melengkapi berkas untuk diproses esok pagi.", val: 2}, {text: "Mengarahkan warga melengkapi berkas dan mengirimkannya via jasa kurir besok.", val: 3}, {text: "Tetap melayani pengecekan berkas yang ada agar esok tinggal proses cetak.", val: 4}, {text: "Membantu warga mencetak kekurangan berkas di kantor agar selesai hari ini juga.", val: 5}, {text: "Menyarankan warga menghubungi call center untuk mengadukan kesalahan informasi.", val: 1}] },
{ text: "Anda sedang melayani antrean di loket saat seorang warga datang dengan kondisi marah-marah karena merasa dipersulit oleh prosedur yang dianggapnya berbelit-belit, padahal prosedur tersebut merupakan aturan baru yang bertujuan meningkatkan keamanan data pemohon. Di tengah tatapan warga lain yang merasa terganggu dengan kegaduhan tersebut, tindakan paling tepat yang Anda ambil adalah...", options: [{text: "Meminta petugas keamanan untuk membawa warga tersebut keluar agar tidak mengganggu ketertiban.", val: 1}, {text: "Mendengarkan keluhannya dengan tenang lalu menjelaskan esensi dan manfaat aturan baru tersebut.", val: 5}, {text: "Meminta maaf atas ketidaknyamanan tersebut dan mempercepat proses layanannya agar ia segera pulang.", val: 3}, {text: "Menyarankan warga tersebut untuk mengisi formulir pengaduan jika tidak puas dengan prosedur yang ada.", val: 2}, {text: "Mengajak warga tersebut ke ruangan khusus untuk berdiskusi agar suasana di loket kembali kondusif.", val: 4}] },
{ text: "Instansi Anda mewajibkan pendaftaran daring, namun seorang lansia datang ke kantor karena tidak memiliki ponsel pintar dan tidak mengerti cara mengoperasikan komputer untuk mendaftar, sementara antrean fisik sedang sangat padat. Mengingat target digitalisasi harus tetap tercapai namun kebutuhan warga juga mendesak, sikap Anda adalah...", options: [{text: "Meminta bantuan warga lain di antrean untuk membantu lansia tersebut mendaftar melalui ponsel mereka.", val: 2}, {text: "Menyarankan lansia tersebut pergi ke warnet terdekat agar dibantu oleh petugas di sana.", val: 1}, {text: "Membantu lansia tersebut melakukan pendaftaran melalui komputer helpdesk yang tersedia di kantor.", val: 5}, {text: "Mengambil berkas fisiknya dan menjanjikan akan membantu menginput datanya setelah jam pelayanan tutup.", val: 4}, {text: "Memberikan brosur panduan pendaftaran agar bisa dipelajari oleh anggota keluarganya di rumah.", val: 3}] },
{ text: "Sesaat sebelum jam kerja berakhir, terjadi pemadaman listrik yang menyebabkan seluruh sistem pelayanan di kantor Anda mati total, padahal masih ada satu pemohon yang dokumennya sangat mendesak untuk diselesaikan hari itu juga karena alasan medis. Menghadapi kendala sarana prasarana yang tidak terduga di akhir waktu pelayanan ini, langkah Anda adalah...", options: [{text: "Meminta maaf dan meminta warga tersebut kembali lagi esok pagi saat listrik sudah menyala.", val: 2}, {text: "Mencatat data manual dan menjanjikan pengiriman dokumen melalui kurir segera setelah sistem pulih.", val: 5}, {text: "Memberikan surat keterangan gangguan sistem agar bisa digunakan warga di instansi kesehatan terkait.", val: 4}, {text: "Menghubungi pimpinan untuk meminta izin pulang lebih awal karena pekerjaan tidak bisa dilanjutkan.", val: 1}, {text: "Mencoba menggunakan koneksi seluler pribadi untuk mengakses sistem jika memungkinkan dari perangkat mobile.", val: 3}] },
{ text: "Anda sedang melayani antrean panjang saat seorang warga di barisan depan tiba-tiba kehilangan kesadaran karena ruangan sangat sesak, sementara petugas kesehatan belum tiba di lokasi. Di saat yang sama, warga lain mulai memprotes karena pelayanan terhenti dan mereka sudah menunggu lama. Menghadapi situasi darurat di area pelayanan publik ini, tindakan paling tepat Anda adalah...", options: [{text: "Meminta bantuan warga lain untuk menggotong korban ke ruang medis agar pelayanan tetap berjalan.", val: 3}, {text: "Keluar loket segera untuk memberi pertolongan pertama dan meminta rekan lain memandu antrean.", val: 5}, {text: "Menghubungi atasan agar segera mengirimkan bantuan keamanan untuk menenangkan antrean yang riuh.", val: 2}, {text: "Mengumumkan penghentian layanan sementara sampai tim medis datang demi keamanan bersama.", val: 1}, {text: "Memberikan ruang bagi warga yang pingsan dan meminta warga di antrean tetap tenang menunggu.", val: 4}] },
{ text: "Instansi Anda menerapkan pendaftaran mandiri melalui kios digital, namun Anda mendapati seorang penyandang disabilitas netral kesulitan mengakses layar sentuh karena fitur suara tidak berfungsi, sementara petugas pendamping sedang membantu di unit lain. Mengingat antrean di loket manual sangat penuh dan sistem digital wajib digunakan, langkah yang Anda ambil adalah...", options: [{text: "Menyarankan warga tersebut untuk menunggu sampai petugas pendamping khusus kembali ke posnya.", val: 2}, {text: "Meminta warga lain yang sedang mengantre untuk membantu warga tersebut menginput datanya.", val: 1}, {text: "Mendampingi warga tersebut menggunakan kios digital secara langsung hingga pendaftaran tuntas.", val: 5}, {text: "Meminta warga tersebut masuk ke loket manual Anda agar dapat diproses tanpa antre lama.", val: 4}, {text: "Memberikan panduan manual berupa huruf braille agar warga bisa mencoba mesin itu kembali.", val: 3}] },
{ text: "Sistem perizinan daring mengalami gangguan teknis di akhir jam kerja, padahal seorang pemohon harus menyelesaikan dokumennya hari ini juga karena akan digunakan untuk keperluan mendesak di luar negeri besok pagi. Rekan Anda menyarankan agar pemohon tersebut datang lagi esok hari sesuai prosedur gangguan teknis, namun pemohon terlihat sangat cemas. Respons profesional Anda adalah...", options: [{text: "Meminta maaf dan menyarankan pemohon untuk melaporkan keluhan melalui saluran pengaduan resmi.", val: 2}, {text: "Menghubungi tim IT pusat untuk meminta prioritas perbaikan pada akun milik pemohon tersebut.", val: 3}, {text: "Meminta pemohon untuk mencoba kembali secara mandiri di rumah saat jaringan mungkin sudah stabil.", val: 1}, {text: "Menerima berkas manualnya untuk diverifikasi awal dan menjanjikan input sistem saat pulih.", val: 5}, {text: "Memberikan surat keterangan bahwa sistem sedang terganggu agar bisa digunakan sebagai jaminan.", val: 4}] },
{ text: "Anda sedang melayani antrean padat saat seorang warga datang membawa dokumen yang tidak lengkap karena ia mendapatkan informasi yang keliru dari situs resmi instansi Anda. Warga tersebut tampak sangat kecewa karena telah menempuh perjalanan jauh dan tidak memiliki waktu lagi untuk kembali besok. Menghadapi kesalahan yang bersumber dari internal instansi ini, tindakan paling tepat Anda adalah...", options: [{text: "Meminta maaf atas kesalahan informasi dan meminta warga untuk melengkapinya esok hari.", val: 2}, {text: "Membantu warga mencetak kekurangan dokumen menggunakan fasilitas kantor jika memungkinkan.", val: 5}, {text: "Memberikan kompensasi berupa percepatan proses saat warga tersebut kembali membawa berkas.", val: 4}, {text: "Mengarahkan warga untuk menyampaikan komplain melalui kotak saran agar situs segera diperbaiki.", val: 1}, {text: "Menghubungi atasan untuk meminta kebijakan khusus agar berkas tetap diproses apa adanya.", val: 3}] },
{ text: "Unit kerja Anda baru saja menerapkan sistem pelayanan terpadu satu pintu, namun Anda mendapati koordinasi antar-meja verifikasi masih sangat lambat sehingga pemohon harus menunggu lebih lama dari standar waktu yang dijanjikan. Saat seorang pemohon mulai marah-marah di depan loket karena merasa sistem baru justru lebih birokratis, langkah yang Anda ambil sebagai garda terdepan adalah...", options: [{text: "Meminta warga tersebut untuk tenang dan memaklumi masa transisi sistem yang baru.", val: 2}, {text: "Mencatat identitas pemohon dan segera menelusuri hambatan berkasnya ke meja verifikasi.", val: 5}, {text: "Memberikan penjelasan teknis mengenai kerumitan sistem baru agar warga memahami kendala.", val: 3}, {text: "Menyarankan pemohon untuk meninggalkan berkas dan akan dihubungi jika sudah selesai.", val: 4}, {text: "Mengabaikan amarah warga dan fokus menyelesaikan pekerjaan agar antrean tetap bergerak.", val: 1}] },
{ text: "Instansi Anda meluncurkan aplikasi pelayanan mandiri bagi masyarakat, namun Anda melihat banyak penyandang disabilitas yang tetap datang ke kantor karena aplikasi tersebut belum dilengkapi fitur aksesibilitas yang memadai. Melihat ketimpangan akses teknologi ini di tengah kebijakan digitalisasi yang ketat, sikap profesional Anda adalah...", options: [{text: "Mengarahkan warga tersebut untuk tetap menggunakan layanan manual di loket khusus.", val: 4}, {text: "Mendampingi warga tersebut menggunakan aplikasi sambil mencatat poin kendala aksesnya.", val: 5}, {text: "Menyarankan warga tersebut membawa pendamping dari rumah untuk membantu pengisian.", val: 1}, {text: "Mengusulkan kepada pimpinan untuk memperbaiki fitur aksesibilitas pada aplikasi tersebut.", val: 3}, {text: "Memberikan panduan penggunaan aplikasi dalam bentuk manual agar warga bisa belajar.", val: 2}] },
];

const tkp_Profesionalisme = [
{ text: "Anda adalah seorang kepala unit pelayanan publik yang baru saja meluncurkan sistem pendaftaran mandiri berbasis aplikasi untuk memangkas antrean panjang. Namun, di hari pertama implementasi, seorang warga lanjut usia datang dari luar kota tanpa membawa ponsel pintar dan sangat kesulitan memahami prosedur digital tersebut, sementara staf Anda sedang sangat sibuk mendampingi pengguna lain yang juga mengalami kendala teknis sistem baru. Melihat kondisi pelayanan yang mulai riuh karena adaptasi teknologi ini, tindakan yang paling mencerminkan profesionalisme Anda adalah...", options: [{text: "Meminta staf khusus untuk segera membantu warga tersebut secara manual hingga tuntas.", val: 4}, {text: "Mengambil alih pelayanan warga tersebut secara langsung sambil mengevaluasi hambatan sistem.", val: 5}, {text: "Memberikan penjelasan santun mengenai prosedur baru dan meminta warga tersebut menunggu staf senggang.", val: 2}, {text: "Mengarahkan warga tersebut untuk meminta bantuan kerabat agar bisa menggunakan aplikasi.", val: 1}, {text: "Menugaskan petugas keamanan untuk membantu pengisian data warga agar tidak menghambat arus antrean.", val: 3}] },
{ text: "Instansi Anda sedang dalam proses audit internal untuk mempertahankan predikat opini WTP (Wajar Tanpa Pengecualian). Atasan langsung Anda, yang merupakan mentor yang sangat Anda hormati, meminta Anda untuk sedikit 'merapikan' catatan laporan perjalanan dinas yang kurang lengkap dokumen pendukungnya agar tidak menjadi temuan minor bagi auditor, dengan alasan bahwa secara substansi kegiatan tersebut benar-benar dilaksanakan dan demi nama baik instansi. Dalam situasi yang mempertaruhkan loyalitas personal dan integritas profesional ini, sikap Anda adalah...", options: [{text: "Menyusun laporan apa adanya sesuai dokumen yang tersedia dan siap menjelaskan kendalanya.", val: 5}, {text: "Membantu merapikan laporan tersebut namun tetap memberikan catatan kritis secara internal.", val: 3}, {text: "Mengingatkan atasan dengan sopan bahwa tindakan tersebut berisiko bagi karier beliau di masa depan.", val: 4}, {text: "Menolak permintaan tersebut secara tegas dan melaporkannya kepada bagian pengawasan internal.", val: 2}, {text: "Mengikuti instruksi atasan sebagai bentuk loyalitas dan tanggung jawab terhadap nama baik instansi.", val: 1}] },
{ text: "Unit kerja Anda diberikan target penyelesaian proyek strategis nasional dalam waktu dua minggu, namun secara mendadak dua anggota tim inti Anda harus menjalani isolasi mandiri karena terpapar virus, sehingga beban kerja meningkat dua kali lipat bagi anggota yang tersisa. Sebagai ketua tim, Anda menyadari bahwa mempertahankan metode kerja lama akan membuat proyek ini gagal memenuhi tenggat waktu yang ketat. Strategi profesional yang paling tepat untuk Anda ambil dalam kondisi mendesak ini adalah...", options: [{text: "Mengajukan permohonan perpanjangan waktu kepada pimpinan dengan alasan keadaan kahar.", val: 2}, {text: "Memotivasi anggota tim yang tersisa untuk bekerja lembur setiap hari agar target tercapai.", val: 3}, {text: "Melakukan pemetaan ulang prioritas dan menyederhanakan alur kerja tanpa mengurangi kualitas hasil.", val: 5}, {text: "Meminta bantuan dari unit kerja lain yang memiliki beban kerja lebih ringan untuk membantu tim.", val: 4}, {text: "Mengerjakan sisa tugas anggota tim yang isolasi secara mandiri sebagai bentuk tanggung jawab ketua.", val: 1}] },
{ text: "Instansi Anda baru saja menerapkan sistem antrean digital terintegrasi untuk meningkatkan efisiensi, namun di tengah kepadatan operasional, datang seorang warga dari wilayah pedalaman yang tidak memiliki akses teknologi, tidak memahami prosedur digital, dan telah menempuh perjalanan jauh demi mendapatkan layanan yang bersifat mendesak. Sementara itu, aturan internal mewajibkan semua pengguna layanan mendaftar melalui aplikasi demi transparansi data, dan staf bagian informasi sedang kewalahan menangani antrean reguler yang mulai tidak sabar. Menghadapi situasi yang membenturkan antara kekakuan sistem dan urgensi kemanusiaan ini, tindakan Anda adalah...", options: [{text: "Menemani warga tersebut melakukan pendaftaran manual melalui perangkat kantor.", val: 5}, {text: "Meminta warga tersebut menunggu hingga jam istirahat agar bisa dibantu staf.", val: 2}, {text: "Memberikan penjelasan santun mengenai aturan pendaftaran melalui aplikasi.", val: 1}, {text: "Mengarahkan warga tersebut ke meja pengaduan untuk mendapatkan dispensasi.", val: 3}, {text: "Memprioritaskan layanan warga tersebut setelah membantunya mendaftar secara daring.", val: 4}] },
{ text: "Anda sedang melayani antrean panjang di loket ketika seorang tokoh masyarakat setempat yang berpengaruh datang dan meminta didahulukan dengan alasan ada pertemuan penting, sementara beberapa warga di belakang mulai merekam situasi tersebut dengan ponsel mereka karena merasa adanya potensi perlakuan istimewa. Tokoh tersebut bersikeras bahwa pelayanannya hanya akan memakan waktu lima menit dan tidak akan mengganggu yang lain, namun Anda menyadari bahwa tindakan tersebut dapat memicu kegaduhan di ruang tunggu maupun di media sosial. Strategi komunikasi dan tindakan yang paling tepat untuk menjaga kredibilitas instansi adalah...", options: [{text: "Memohon maaf dan tetap meminta tokoh tersebut mengantre sesuai nomor urut.", val: 5}, {text: "Mempercepat durasi pelayanan pada antrean saat itu agar tokoh tersebut segera terlayani.", val: 2}, {text: "Mengajak tokoh tersebut berdiskusi di ruang tertutup agar tidak memicu kecurigaan warga.", val: 3}, {text: "Menjelaskan secara publik mengenai pentingnya kesetaraan hak dalam akses pelayanan.", val: 4}, {text: "Melayani tokoh tersebut dengan cepat sembari memberikan penjelasan kepada warga lain.", val: 1}] },
{ text: "Layanan pengaduan instansi Anda mendapatkan kritik tajam dari masyarakat karena dianggap lambat dalam merespons keluhan teknis, padahal secara administratif semua laporan telah dicatat sesuai prosedur yang berlaku. Setelah dilakukan evaluasi, ternyata kendala utama terletak pada alur koordinasi antar-bidang yang terlalu birokratis sehingga solusi tidak segera sampai ke tangan masyarakat. Sebagai penanggung jawab unit layanan tersebut, langkah strategis yang harus Anda ambil untuk memperbaiki kualitas pelayanan adalah...", options: [{text: "Menambah jumlah personel di bagian pengaduan agar respons awal lebih cepat.", val: 2}, {text: "Mewajibkan setiap bidang untuk melaporkan progres pengaduan setiap hari.", val: 3}, {text: "Memangkas rantai koordinasi dengan membuat sistem komunikasi lintas bidang.", val: 5}, {text: "Meminta maaf kepada publik melalui media massa atas keterlambatan layanan.", val: 1}, {text: "Mengintegrasikan seluruh database pengaduan agar dapat dipantau langsung oleh pimpinan.", val: 4}] },
{ text: "Instansi Anda baru saja meresmikan sistem layanan mandiri melalui kios digital untuk mempercepat proses administrasi, namun di hari pertama, seorang warga difabel netra datang sendirian tanpa pendamping dan tampak kebingungan di depan mesin tersebut karena fitur bantuan suara belum berfungsi optimal. Di saat yang sama, Anda sedang memimpin pemantauan arus antrean yang mulai padat di area tunggu, dan semua petugas loket sedang sibuk melayani pemohon lain yang juga membutuhkan bantuan teknis. Tindakan Anda yang paling tepat untuk memastikan kualitas pelayanan tetap terjaga adalah...", options: [{text: "Meminta petugas keamanan untuk membantu warga tersebut.", val: 3}, {text: "Mendampingi warga tersebut menyelesaikan prosesnya secara manual.", val: 5}, {text: "Memberikan arahan suara dengan tenang agar warga dapat mencoba lagi.", val: 2}, {text: "Menghubungi teknisi segera untuk memperbaiki fitur bantuan suara.", val: 4}, {text: "Menyarankan warga tersebut membawa pendamping di kunjungan berikutnya.", val: 1}] },
{ text: "Anda sedang melayani seorang warga yang mengeluhkan prosedur legalisasi dokumen yang dianggapnya terlalu berbelit-belit, hingga warga tersebut mulai berteriak dan merekam Anda menggunakan ponselnya sambil mengancam akan memviralkan ketidakpuasannya ke media sosial jika tidak segera diselesaikan saat itu juga. Padahal, keterlambatan terjadi karena sistem pusat sedang dalam pemeliharaan berkala yang berada di luar kendali unit kerja Anda. Dalam menghadapi tekanan publikasi dan emosi warga tersebut, sikap Anda adalah...", options: [{text: "Menjelaskan kendala sistem dengan tenang dan tetap profesional.", val: 5}, {text: "Meminta warga tersebut berhenti merekam demi privasi kantor.", val: 2}, {text: "Memberikan solusi alternatif sementara sesuai batas kewenangan.", val: 4}, {text: "Memanggil atasan untuk meredam kemarahan warga tersebut.", val: 3}, {text: "Membiarkan warga merekam sebagai bentuk transparansi layanan.", val: 1}] },
{ text: "Menjelang jam tutup kantor, seorang pengguna layanan datang dengan terburu-buru meminta pembaruan data yang sangat mendesak untuk syarat operasi medis keluarganya esok pagi, namun setelah diperiksa, terdapat satu dokumen persyaratan asli yang tertinggal dan hanya tersedia dalam bentuk foto di ponselnya. Sesuai prosedur tetap, dokumen asli wajib diverifikasi secara fisik untuk mencegah pemalsuan data, namun situasi warga tersebut benar-benar berada dalam kondisi darurat kemanusiaan. Tindakan yang paling mencerminkan solusi pelayanan publik yang bertanggung jawab adalah...", options: [{text: "Menolak dengan tegas demi mematuhi standar operasional.", val: 2}, {text: "Memberikan pengecualian karena alasan kemanusiaan yang darurat.", val: 1}, {text: "Melakukan verifikasi data melalui sistem daring yang terintegrasi.", val: 5}, {text: "Mengarahkan warga untuk membawa dokumen asli besok pagi-pagi.", val: 3}, {text: "Meminta jaminan surat pernyataan tanggung jawab mutlak dari warga.", val: 4}] },
{ text: "Anda adalah petugas loket di instansi yang mewajibkan seluruh permohonan dilakukan melalui sistem reservasi daring untuk menghindari kerumunan, namun seorang ibu dari daerah terpencil datang secara langsung tanpa mendaftar karena ponselnya rusak dan ia sangat membutuhkan dokumen tersebut untuk pencairan bantuan modal usaha yang akan ditutup sore ini. Di sisi lain, sistem tidak mengizinkan entri data tanpa nomor reservasi, dan antrean warga yang sudah mendaftar mulai memadati ruang tunggu. Menghadapi situasi yang membenturkan ketegasan aturan dan kebutuhan mendesak warga ini, tindakan Anda adalah...", options: [{text: "Membantu ibu tersebut meminjam ponsel rekan untuk mendaftar daring saat itu juga.", val: 3}, {text: "Menggunakan unit komputer layanan mandiri untuk mendaftarkan ibu tersebut ke slot kosong.", val: 5}, {text: "Memberikan penjelasan santun bahwa sistem tidak dapat diproses tanpa nomor reservasi.", val: 1}, {text: "Meminta izin pimpinan untuk memberikan diskresi pelayanan manual khusus bagi ibu tersebut.", val: 4}, {text: "Menyarankan ibu tersebut kembali esok hari setelah memperbaiki ponsel dan mendaftar.", val: 2}] },
{ text: "Unit kerja Anda sedang berupaya keras meraih predikat zona integritas, namun seorang rekan kerja senior yang dikenal memiliki pengaruh luas mendatangi Anda untuk meminta percepatan proses dokumen milik kerabatnya dengan alasan keadaan darurat keluarga, tanpa melalui prosedur verifikasi awal yang biasanya memakan waktu dua hari kerja. Anda menyadari bahwa menolak permintaannya dapat merusak hubungan kerja di kantor, namun mengabulkannya akan mencederai komitmen transparansi yang sedang dibangun instansi. Strategi yang paling tepat untuk menunjukkan profesionalisme pelayanan Anda adalah...", options: [{text: "Menolak permintaan tersebut dan menyarankan kerabat rekan mengikuti alur resmi.", val: 4}, {text: "Mengarahkan rekan tersebut untuk berbicara langsung kepada pimpinan unit pelayanan.", val: 2}, {text: "Membantu melakukan verifikasi saat itu juga secara teliti sesuai urutan permohonan.", val: 5}, {text: "Mengabulkan permintaan tersebut demi menjaga keharmonisan internal sesama rekan kerja.", val: 1}, {text: "Menjelaskan secara pribadi kepada rekan mengenai risiko integritas jika prosedur dilanggar.", val: 3}] },
{ text: "Sebagai koordinator layanan, Anda menerima banyak keluhan dari masyarakat mengenai fitur chatbot instansi yang sering memberikan jawaban tidak relevan sehingga warga merasa tidak terbantu dan tetap harus datang ke kantor, yang mengakibatkan penumpukan antrean fisik. Anda diminta pimpinan untuk segera menurunkan angka kunjungan fisik hingga 40% dalam satu bulan melalui optimalisasi kanal digital. Langkah strategis yang paling tepat untuk menyelesaikan akar permasalahan tersebut adalah...", options: [{text: "Menutup sebagian loket fisik agar masyarakat terpaksa menggunakan layanan daring.", val: 1}, {text: "Menambah operator manusia pada layanan pesan singkat untuk menjawab keluhan warga.", val: 3}, {text: "Mengevaluasi basis data chatbot dan mengintegrasikannya dengan layanan operator live.", val: 5}, {text: "Memberikan sosialisasi intensif melalui media sosial mengenai cara penggunaan chatbot.", val: 2}, {text: "Memperbaiki alur navigasi aplikasi agar lebih mudah dipahami oleh pengguna awam.", val: 4}] },
{ text: "Instansi Anda baru saja menerapkan sistem pendaftaran layanan sepenuhnya melalui aplikasi untuk meminimalisir kerumunan, namun di tengah jam operasional yang padat, seorang warga lanjut usia datang dari luar kota tanpa membawa ponsel pintar dan sangat membutuhkan layanan tersebut karena terkait tenggat waktu administrasi kesehatan. Petugas di lapangan tampak ragu karena sistem tidak dapat memproses data tanpa kode QR dari aplikasi, sementara warga lain mulai memperhatikan situasi tersebut. Sebagai pengawas layanan yang melihat kejadian ini, tindakan Anda adalah...", options: [{text: "Menemani warga tersebut ke komputer layanan mandiri untuk membantu pendaftaran akun.", val: 5}, {text: "Meminta warga tersebut mencari bantuan keluarga agar bisa mendaftar lewat aplikasi.", val: 1}, {text: "Memberikan dispensasi layanan manual khusus karena alasan usia dan kondisi darurat.", val: 3}, {text: "Menugaskan staf khusus untuk meminjamkan perangkat kantor demi proses pendaftaran.", val: 4}, {text: "Menjelaskan secara santun bahwa tanpa aplikasi, layanan tidak dapat diberikan saat ini.", val: 2}] },
{ text: "Anda sedang melayani antrean panjang ketika seorang warga mulai marah-marah dan merekam situasi kantor dengan ponselnya karena merasa proses verifikasinya terlalu lama, padahal keterlambatan disebabkan oleh gangguan server pusat. Warga tersebut mengancam akan mengunggah rekaman tersebut ke media sosial untuk mempermalukan instansi jika ia tidak segera diselesaikan saat itu juga. Melihat potensi krisis komunikasi dan tekanan dari warga tersebut, sikap yang paling tepat adalah...", options: [{text: "Menjelaskan kendala teknis secara tenang dan meminta maaf atas ketidaknyamanan.", val: 5}, {text: "Meminta warga tersebut berhenti merekam karena melanggar privasi area kantor.", val: 2}, {text: "Melaporkan tindakan warga tersebut kepada petugas keamanan untuk ditertibkan.", val: 3}, {text: "Mengajak warga tersebut berbicara di ruang tertutup agar tidak memprovokasi yang lain.", val: 4}, {text: "Mempercepat proses warga tersebut agar ia segera pergi dan berhenti merekam.", val: 1}] },
{ text: "Layanan pengaduan di unit kerja Anda sering mendapat kritik karena respons yang diberikan dianggap hanya berupa jawaban otomatis yang tidak menyelesaikan inti masalah. Hasil evaluasi menunjukkan bahwa koordinasi antara bagian pengaduan dan bagian teknis di lapangan sangat lamban karena prosedur surat-menyurat internal yang panjang. Sebagai penanggung jawab layanan, langkah strategis yang harus Anda ambil untuk meningkatkan kepuasan publik adalah...", options: [{text: "Menambah jumlah personel di bagian pengaduan untuk mempercepat respons pesan.", val: 2}, {text: "Mewajibkan staf pengaduan memberikan jawaban yang lebih ramah dan persuasif.", val: 1}, {text: "Menciptakan sistem koordinasi digital langsung antara admin pengaduan dan tim teknis.", val: 5}, {text: "Mengadakan pertemuan mingguan untuk mengevaluasi keluhan yang belum terselesaikan.", val: 3}, {text: "Memberikan target waktu maksimal penyelesaian keluhan yang ketat pada setiap bidang.", val: 4}] },
{ text: "Seorang tokoh masyarakat yang sangat dihormati di lingkungan kantor Anda datang untuk meminta bantuan percepatan pengurusan izin usaha milik rekannya, sementara antrean saat itu sangat padat dan sistem sedang memproses urutan sesuai nomor kedatangan. Tokoh tersebut menyiratkan bahwa ia telah banyak membantu instansi Anda dalam kegiatan sosial sebelumnya dan berharap ada timbal balik yang setara. Menghadapi situasi konflik kepentingan ini, tindakan Anda adalah...", options: [{text: "Membantu mempercepat prosesnya secara diam-diam agar tidak memicu kecemburuan.", val: 1}, {text: "Menjelaskan secara santun mengenai prosedur antrean yang berlaku bagi semua warga.", val: 5}, {text: "Mengarahkan tokoh tersebut untuk berbicara dengan pimpinan agar diberikan izin khusus.", val: 2}, {text: "Mempercepat proses tokoh tersebut namun dengan tetap memberikan penjelasan pada pengantre.", val: 3}, {text: "Mengapresiasi bantuan beliau selama ini namun tetap memintanya mengikuti alur resmi.", val: 4}] },
{ text: "Instansi Anda baru saja mengganti seluruh sistem loket fisik dengan anjungan layanan mandiri berbasis layar sentuh untuk meningkatkan efisiensi. Namun, Anda mendapati seorang warga penyandang disabilitas fisik yang kesulitan mencapai posisi layar anjungan tersebut, sementara petugas keamanan sedang sibuk mengarahkan arus parkir di luar dan rekan kerja Anda yang lain terpaku pada target penyelesaian input data di ruangan masing-masing. Melihat situasi yang menghambat aksesibilitas layanan ini, tindakan yang paling mencerminkan profesionalisme Anda adalah...", options: [{text: "Menghampiri dan membantu warga tersebut mengoperasikan mesin hingga selesai.", val: 5}, {text: "Meminta petugas keamanan untuk segera masuk dan mendampingi warga tersebut.", val: 3}, {text: "Memberikan instruksi lisan dari meja kerja Anda mengenai cara penggunaan mesin.", val: 1}, {text: "Melaporkan kendala desain anjungan kepada bagian sarana prasarana untuk dievaluasi.", val: 4}, {text: "Menyarankan warga tersebut untuk membawa pendamping pada kunjungan berikutnya.", val: 2}] },
{ text: "Anda sedang menjelaskan prosedur baru yang memerlukan waktu verifikasi lebih lama kepada seorang pengguna layanan, namun ia tidak terima dan mulai membentak Anda sambil melakukan siaran langsung (live streaming) di media sosial, menuduh Anda sengaja mempersulit urusan rakyat. Suasana ruang tunggu mulai tegang karena pengguna lain ikut terprovokasi oleh narasi yang dibangun orang tersebut di depan kamera. Strategi terbaik Anda dalam mengelola krisis pelayanan ini adalah...", options: [{text: "Membiarkan orang tersebut merekam agar publik melihat bahwa Anda tetap bekerja.", val: 2}, {text: "Menghentikan pelayanan sementara dan meminta bantuan atasan untuk menjelaskan.", val: 3}, {text: "Menjelaskan kembali prosedur dengan nada tenang, sopan, dan tetap informatif.", val: 5}, {text: "Mengajak orang tersebut ke ruang mediasi untuk menghindari kegaduhan di ruang tunggu.", val: 4}, {text: "Meminta orang tersebut mematikan kamera demi menjaga privasi petugas dan pengguna lain.", val: 1}] },
{ text: "Menjelang jam operasional berakhir, seorang warga datang dengan kondisi panik meminta dokumen legalisasi untuk keperluan beasiswa luar negeri yang tenggat waktunya malam ini, namun ia lupa membawa dokumen asli sebagai syarat verifikasi dan hanya memiliki salinan digital di ponselnya. Berdasarkan aturan, verifikasi wajib menggunakan dokumen asli untuk mencegah pemalsuan, namun Anda menyadari bahwa penolakan akan membatalkan kesempatan beasiswa warga tersebut. Langkah yang paling bijaksana sebagai pelayan publik adalah...", options: [{text: "Memberikan pengecualian karena situasi darurat dan memprosesnya saat itu juga.", val: 1}, {text: "Membantu memverifikasi keaslian dokumen melalui sistem basis data pusat jika terintegrasi.", val: 5}, {text: "Meminta warga tersebut menulis surat pernyataan tanggung jawab mutlak di atas materai.", val: 4}, {text: "Menyarankan warga untuk kembali besok pagi dengan membawa dokumen yang lengkap.", val: 2}, {text: "Meminta izin pimpinan untuk mendapatkan diskresi khusus bagi kasus warga tersebut.", val: 3}] },
{ text: "Instansi Anda baru saja menerapkan sistem antrean dan pengisian formulir sepenuhnya melalui pemindaian kode QR untuk meningkatkan efisiensi, namun seorang warga lanjut usia yang datang sendirian tampak kebingungan karena ponsel miliknya bukan tipe pintar yang dapat memindai kode tersebut. Sementara itu, antrean di belakangnya mulai tidak sabar dan petugas loket lainnya sedang sangat sibuk melayani pemohon lain sesuai urutan digital. Sebagai petugas yang sedang berjaga di area informasi, tindakan yang paling mencerminkan profesionalisme pelayanan Anda adalah...", options: [{text: "Memberikan petunjuk lisan secara perlahan agar warga tersebut mencoba meminta bantuan pengantre lain.", val: 2}, {text: "Meminta warga tersebut untuk pulang dan kembali lagi dengan membawa pendamping yang mengerti teknologi.", val: 1}, {text: "Mendampingi warga tersebut ke meja khusus untuk membantu pengisian data secara manual melalui perangkat kantor.", val: 5}, {text: "Menyarankan warga tersebut untuk membeli ponsel baru agar di masa depan dapat mengakses layanan dengan mudah.", val: 3}, {text: "Meminta pimpinan untuk memberikan pengecualian sehingga warga tersebut bisa langsung dilayani tanpa sistem.", val: 4}] },
{ text: "Anda sedang memproses berkas perizinan yang cukup rumit ketika seorang teman lama yang kini menjadi pengusaha sukses datang dan meminta agar berkasnya didahulukan karena ia harus segera mengejar penerbangan untuk pertemuan bisnis penting. Ia mengingatkan bahwa keberhasilan bisnisnya nanti juga akan berdampak pada penyerapan tenaga kerja di daerah Anda, dan ia menjanjikan akan memberikan apresiasi khusus atas bantuan Anda. Di saat yang sama, sistem antrean sedang berjalan normal dan transparan. Langkah yang paling tepat untuk Anda ambil adalah...", options: [{text: "Membantu mempercepat prosesnya hanya jika semua dokumennya sudah sangat lengkap dan sempurna.", val: 2}, {text: "Menjelaskan secara personal mengenai komitmen instansi terhadap antrean yang adil dan transparan.", val: 5}, {text: "Mengarahkan teman tersebut untuk menemui atasan Anda agar mendapatkan kebijakan khusus.", val: 3}, {text: "Mempercepat prosesnya sedikit demi kepentingan ekonomi daerah namun tanpa menerima imbalan apa pun.", val: 1}, {text: "Memberikan apresiasi atas niat baiknya namun tetap memintanya mengikuti prosedur antrean yang ada.", val: 4}] },
{ text: "Layanan pengaduan masyarakat di unit Anda sering menerima keluhan mengenai lamanya durasi perbaikan fasilitas publik, yang setelah ditelusuri ternyata disebabkan oleh rumitnya alur verifikasi lapangan yang melibatkan banyak bidang. Sebagai koordinator layanan, Anda dituntut untuk memangkas waktu respons tanpa mengurangi validitas data hasil verifikasi tersebut. Strategi paling inovatif yang dapat Anda terapkan adalah...", options: [{text: "Menambah jumlah petugas verifikasi di lapangan agar laporan yang masuk lebih cepat diperiksa.", val: 3}, {text: "Memperketat target waktu penyelesaian laporan kepada setiap bidang disertai sanksi administratif.", val: 2}, {text: "Meminta masyarakat untuk melampirkan foto dan koordinat lokasi yang akurat saat mengirimkan laporan.", val: 4}, {text: "Mengintegrasikan aplikasi pengaduan dengan sistem pelaporan real-time yang dapat diakses semua bidang.", val: 5}, {text: "Rutin mengadakan rapat koordinasi harian untuk membahas kendala verifikasi yang dihadapi setiap tim.", val: 1}] },
{ text: "Instansi Anda baru saja menerapkan sistem pendaftaran layanan sepenuhnya melalui aplikasi untuk meningkatkan akurasi data, namun di tengah jam operasional yang sangat padat, datang seorang warga lansia dari desa terpencil yang tidak memiliki ponsel pintar dan ingin mengurus dokumen jaminan kesehatan yang sangat mendesak. Sementara itu, sistem di loket secara otomatis menolak input data tanpa kode unik dari aplikasi, dan warga lain di antrean mulai merasa terganggu dengan waktu pelayanan yang tersita. Sebagai petugas layanan, tindakan Anda yang paling mencerminkan prinsip pelayanan publik adalah...", options: [{text: "Menemani warga tersebut ke komputer layanan mandiri untuk membantu pendaftaran akun.", val: 5}, {text: "Meminta warga tersebut mencari bantuan keluarga agar bisa mendaftar lewat aplikasi.", val: 1}, {text: "Memberikan dispensasi layanan manual khusus karena alasan usia dan kondisi darurat.", val: 3}, {text: "Menugaskan staf khusus untuk membantu memproses pendaftaran warga melalui perangkat kantor.", val: 4}, {text: "Menjelaskan secara santun bahwa tanpa kode aplikasi, layanan tidak dapat diproses saat ini.", val: 2}] },
{ text: "Anda sedang melayani warga di loket ketika sistem pusat mengalami gangguan teknis yang menyebabkan proses unggah data melambat secara signifikan, sehingga antrean menjadi sangat panjang dan suasana mulai memanas. Seorang warga yang tidak sabar mulai membentak Anda sambil merekam situasi menggunakan ponselnya dan mengancam akan memviralkan ketidakmampuan instansi Anda dalam melayani masyarakat jika ia tidak segera diselesaikan. Dalam situasi krisis citra dan tekanan emosional ini, sikap Anda adalah...", options: [{text: "Memohon maaf dan tetap memberikan penjelasan mengenai kendala teknis secara tenang.", val: 5}, {text: "Meminta warga tersebut berhenti merekam demi menjaga kenyamanan pengguna layanan lain.", val: 2}, {text: "Melaporkan tindakan warga tersebut kepada petugas keamanan untuk segera ditertibkan.", val: 3}, {text: "Mengajak warga tersebut berbicara di ruang konsultasi untuk meredam kemarahan publik.", val: 4}, {text: "Mempercepat proses warga tersebut secara manual agar ia segera pergi dan berhenti merekam.", val: 1}] },
{ text: "Unit kerja Anda sedang berupaya mempertahankan predikat zona integritas, namun seorang tokoh berpengaruh di wilayah tersebut datang ke ruangan Anda untuk meminta bantuan agar izin usaha kerabatnya diprioritaskan tanpa melalui tahap verifikasi lapangan, dengan alasan tokoh tersebut telah banyak mendukung program sosial instansi Anda selama setahun terakhir. Tokoh tersebut menyiratkan bahwa kelancaran izin ini akan memengaruhi keberlanjutan kerja sama di masa depan. Menghadapi situasi dilematis ini, langkah Anda adalah...", options: [{text: "Menjelaskan secara santun bahwa seluruh izin harus melalui prosedur verifikasi yang sama.", val: 5}, {text: "Membantu mempercepat proses verifikasi lapangan namun tetap dilakukan secara objektif.", val: 3}, {text: "Mengarahkan tokoh tersebut untuk berkoordinasi langsung dengan pimpinan mengenai izin itu.", val: 2}, {text: "Mengapresiasi dukungan beliau dan berjanji akan memantau progres izin tersebut secara rutin.", val: 4}, {text: "Mengabulkan permintaan tersebut sebagai bentuk timbal balik atas bantuan sosial yang diberikan.", val: 1}] },
{ text: "Hasil survei kepuasan masyarakat menunjukkan bahwa unit pelayanan Anda dinilai lamban dalam merespons keluhan teknis yang masuk melalui kanal digital, karena admin pengaduan harus menunggu disposisi manual dari beberapa kepala bidang sebelum bisa memberikan jawaban. Sebagai penanggung jawab unit, Anda diminta untuk memangkas waktu tunggu respons tersebut hingga 50% dalam waktu singkat. Strategi paling efektif yang akan Anda terapkan adalah...", options: [{text: "Menambah jumlah personel admin agar pesan yang masuk dapat segera dibalas satu per satu.", val: 2}, {text: "Membuat standar operasional prosedur baru yang mewajibkan respons maksimal satu jam.", val: 3}, {text: "Mengintegrasikan aplikasi pengaduan dengan dasbor pemantauan real-time untuk setiap bidang.", val: 5}, {text: "Memberikan kewenangan kepada admin untuk langsung menjawab keluhan yang sifatnya umum.", val: 4}, {text: "Rutin mengadakan rapat harian untuk mengevaluasi keluhan yang belum mendapatkan jawaban.", val: 1}] },
{ text: "Instansi Anda baru saja memindahkan seluruh layanan konsultasi ke sistem berbasis kecerdasan buatan (AI Chatbot) untuk mengurangi antrean fisik, namun Anda mendapati seorang warga penyandang disabilitas rungu yang tampak sangat kesulitan memahami instruksi teks yang terlalu teknis pada mesin tersebut, sementara petugas di area informasi sedang sibuk menangani gangguan jaringan sistem pusat. Warga tersebut terlihat mulai frustrasi karena pesan yang ia sampaikan tidak terbantu oleh jawaban otomatis mesin. Tindakan Anda yang paling tepat untuk memastikan kualitas pelayanan tetap terjaga adalah...", options: [{text: "Mendampingi warga tersebut secara langsung dengan berkomunikasi melalui tulisan manual yang jelas.", val: 5}, {text: "Meminta warga tersebut menunggu hingga petugas di area informasi selesai menangani gangguan sistem.", val: 2}, {text: "Memberikan penjelasan santun bahwa sistem sedang dalam masa transisi dan meminta warga bersabar.", val: 1}, {text: "Mengarahkan warga tersebut untuk menggunakan fitur bantuan video call yang tersedia di dalam sistem.", val: 3}, {text: "Menugaskan staf dari unit kerja lain yang sedang tidak melayani untuk membantu warga tersebut.", val: 4}] },
{ text: "Anda sedang melayani warga yang mengeluhkan lamanya proses verifikasi dokumen karena adanya perubahan kebijakan internal yang belum banyak disosialisasikan, hingga warga tersebut mulai merekam Anda dengan ponselnya sambil berteriak menuduh instansi Anda sengaja mempersulit rakyat demi mendapatkan pungutan liar. Suasana mulai riuh karena pengantre lain ikut terprovokasi oleh narasi yang dibangun warga tersebut di depan kamera. Strategi terbaik Anda untuk menjaga marwah instansi dan kredibilitas pelayanan adalah...", options: [{text: "Menjelaskan rincian kebijakan baru tersebut dengan tenang dan tetap bersikap santun.", val: 5}, {text: "Meminta warga tersebut mematikan kamera karena mengganggu privasi petugas dan warga lain.", val: 2}, {text: "Melaporkan tindakan warga tersebut kepada bagian humas agar segera diberikan klarifikasi resmi.", val: 3}, {text: "Mengajak warga tersebut ke ruangan khusus untuk menyelesaikan masalahnya secara tenang.", val: 4}, {text: "Mempercepat proses warga tersebut secara khusus agar ia berhenti merekam dan tidak gaduh.", val: 1}] },
{ text: "Seorang pengguna layanan datang di detik-detik terakhir sebelum jam kantor tutup dengan permohonan yang bersifat sangat darurat untuk keperluan rujukan medis anggota keluarganya, namun ia lupa membawa satu dokumen fisik asli yang wajib diverifikasi secara tatap muka menurut standar operasional prosedur (SOP). Ia menunjukkan foto dokumen asli tersebut di ponselnya dan memohon agar Anda memberikan pengecualian karena nyawa keluarganya menjadi taruhan jika harus menunggu esok hari. Menghadapi situasi yang membenturkan prosedur tetap dan aspek kemanusiaan ini, tindakan Anda adalah...", options: [{text: "Menolak permohonan tersebut secara tegas karena mematuhi SOP adalah integritas utama.", val: 2}, {text: "Memberikan pengecualian langsung karena situasi darurat menyangkut keselamatan nyawa.", val: 1}, {text: "Membantu memverifikasi keaslian dokumen tersebut melalui integrasi basis data sistem internal.", val: 5}, {text: "Meminta jaminan surat pernyataan tanggung jawab mutlak dan memprosesnya sebagai diskresi.", val: 4}, {text: "Meminta izin kepada pimpinan unit untuk mendapatkan arahan terkait kebijakan darurat ini.", val: 3}] },
{ text: "Instansi Anda baru saja memigrasikan seluruh sistem perizinan ke platform digital terintegrasi untuk mempercepat durasi layanan, namun di hari pertama implementasi, seorang warga penyandang disabilitas datang tanpa pendamping dan tampak sangat kesulitan mengoperasikan anjungan mandiri karena antarmuka sistem yang belum sepenuhnya ramah disabilitas. Sementara itu, petugas di area informasi sedang sangat sibuk menangani antrean warga lain yang juga mengalami kendala teknis serupa, dan suasana ruang tunggu mulai tidak kondusif. Sebagai pengawas layanan, tindakan Anda yang paling tepat adalah...", options: [{text: "Menghampiri warga tersebut dan membantu mengoperasikan sistem hingga prosesnya tuntas.", val: 5}, {text: "Meminta petugas keamanan untuk segera mendampingi warga tersebut agar tidak menghambat antrean.", val: 3}, {text: "Mencatat data warga tersebut secara manual untuk diproses oleh staf di dalam ruangan.", val: 4}, {text: "Menyarankan warga tersebut untuk kembali lagi dengan membawa pendamping yang bisa membantu.", val: 1}, {text: "Memberikan instruksi lisan dari jarak jauh mengenai langkah-langkah penggunaan mesin tersebut.", val: 2}] },
{ text: "Anda sedang melayani warga yang mengeluhkan lambatnya proses verifikasi dokumen akibat gangguan jaringan pusat, hingga warga tersebut mulai merekam Anda dengan ponselnya sambil berteriak menuduh instansi Anda sengaja mempersulit rakyat untuk memicu pungutan liar. Rekaman tersebut dilakukan secara siaran langsung (live streaming) dan mulai menarik perhatian pengguna layanan lain di ruang tunggu yang ikut terprovokasi. Strategi terbaik Anda dalam mengelola krisis pelayanan ini adalah...", options: [{text: "Memohon maaf dengan tenang dan tetap menjelaskan kendala teknis yang sedang terjadi.", val: 5}, {text: "Meminta warga tersebut berhenti merekam karena tindakan tersebut melanggar privasi kantor.", val: 2}, {text: "Mengajak warga tersebut ke ruang konsultasi untuk menyelesaikan masalahnya secara tertutup.", val: 4}, {text: "Melaporkan tindakan warga tersebut kepada petugas keamanan agar segera ditertibkan.", val: 3}, {text: "Mempercepat proses verifikasi warga tersebut secara manual agar ia berhenti berteriak.", val: 1}] },
{ text: "Hasil survei kepuasan pelanggan menunjukkan bahwa masyarakat sangat mengeluhkan lamanya durasi pengurusan berkas di unit Anda karena alur koordinasi antar-bidang yang terlalu panjang dan masih bersifat manual. Sebagai pimpinan unit, Anda dituntut untuk meningkatkan kecepatan layanan sebesar 30% dalam waktu satu bulan tanpa ada penambahan anggaran maupun personel. Langkah paling efektif yang akan Anda ambil adalah...", options: [{text: "Menambah jam kerja pegawai setiap harinya agar semua berkas dapat selesai tepat waktu.", val: 2}, {text: "Mengaudit alur kerja saat ini dan memangkas tahapan verifikasi yang bersifat repetitif.", val: 5}, {text: "Memberikan target penyelesaian berkas yang lebih ketat kepada setiap staf pelaksana.", val: 3}, {text: "Memohon kepada pimpinan pusat agar diberikan bantuan perangkat teknologi baru.", val: 1}, {text: "Memfokuskan seluruh personel untuk menyelesaikan berkas yang paling lama tertunda.", val: 4}] },
{ text: "Seorang tokoh masyarakat yang memiliki pengaruh besar di lingkungan Anda datang membawa berkas permohonan yang kurang lengkap, namun ia meminta agar permohonannya tetap diproses hari ini juga karena ia harus segera berangkat ke luar negeri. Tokoh tersebut menyiratkan bahwa kelancaran urusannya akan sangat membantu kerja sama instansi Anda dengan komunitasnya di masa depan. Menghadapi situasi yang membenturkan antara relasi strategis dan standar operasional, sikap Anda adalah...", options: [{text: "Menolak dengan tegas karena setiap warga harus diperlakukan sama sesuai prosedur.", val: 4}, {text: "Memberikan pengecualian khusus namun dengan catatan bahwa hal ini hanya dilakukan sekali.", val: 1}, {text: "Menjelaskan secara santun mengenai kelengkapan dokumen dan membantu memeriksa ulang berkasnya.", val: 5}, {text: "Mengarahkan tokoh tersebut untuk berbicara dengan pimpinan agar mendapatkan diskresi.", val: 2}, {text: "Membantu memproses berkas tersebut namun meminta tokoh itu melengkapinya esok hari.", val: 3}] },
];

const tkp_JejaringKerja = [
{ text: "Anda adalah seorang analis kebijakan yang sedang memimpin proyek kolaborasi lintas instansi untuk integrasi data nasional. Di tengah jalannya proyek, salah satu perwakilan instansi mitra yang memiliki data krusial bersikap tertutup dan enggan membagi akses dengan alasan prosedur internal yang kaku, padahal tenggat waktu integrasi sudah sangat dekat. Dalam situasi yang menghambat sinergi ini, langkah yang paling tepat Anda lakukan untuk memastikan keberlanjutan jejaring kerja adalah...", options: [{text: "Melaporkan kendala tersebut kepada atasan agar dilakukan koordinasi tingkat tinggi antar pimpinan.", val: 3}, {text: "Mempelajari prosedur internal mitra tersebut untuk mencari celah legalitas pertukaran data yang aman.", val: 4}, {text: "Mengadakan pertemuan informal dengan perwakilan mitra untuk membangun kepercayaan dan mencari solusi bersama.", val: 5}, {text: "Mengirimkan surat resmi permohonan percepatan data dengan menekankan urgensi proyek nasional.", val: 2}, {text: "Fokus mengerjakan bagian data dari instansi lain yang kooperatif agar progres tetap terlihat berjalan.", val: 1}] },
{ text: "Sebagai manajer proyek di sebuah perusahaan teknologi, Anda mendapati bahwa tim desain dan tim pengembang sering mengalami miskomunikasi yang mengakibatkan revisi berulang. Saat Anda mengusulkan penggunaan platform manajemen tugas baru untuk mempererat koordinasi, beberapa anggota senior merasa keberatan karena merasa cara manual yang lama sudah cukup baik. Menghadapi resistensi dalam ekosistem kerja ini, tindakan yang mencerminkan profesionalisme dalam memperkuat jejaring adalah...", options: [{text: "Memberikan pelatihan intensif bagi anggota senior agar mahir menggunakan platform tersebut.", val: 4}, {text: "Memberikan kebebasan bagi anggota senior menggunakan cara lama asalkan hasil akhirnya tetap sama.", val: 2}, {text: "Mengajak anggota senior berdiskusi untuk menyelaraskan persepsi manfaat platform bagi efisiensi tim.", val: 5}, {text: "Mewajibkan penggunaan platform tersebut melalui instruksi resmi demi keseragaman sistem kerja.", val: 3}, {text: "Meminta anggota tim yang lebih muda untuk membantu tugas-tugas administratif anggota senior.", val: 1}] },
{ text: "Unit kerja Anda terpilih sebagai percontohan dalam program transformasi digital, namun anggaran pendukung untuk studi banding ke instansi yang lebih maju telah dipangkas. Rekan kerja Anda menyarankan untuk tetap fokus pada tugas internal saja tanpa perlu mencari referensi luar. Namun, Anda menyadari bahwa tanpa masukan dari pihak luar, inovasi unit Anda akan stagnan. Di tengah keterbatasan sumber daya untuk memperluas jejaring, sikap Anda adalah...", options: [{text: "Mengusulkan pemanfaatan forum daring dan webinar gratis untuk tetap terhubung dengan para ahli.", val: 5}, {text: "Menggunakan dana pribadi untuk melakukan kunjungan singkat ke instansi yang dianggap sukses.", val: 2}, {text: "Meminta pimpinan untuk meninjau kembali pemotongan anggaran khusus untuk studi banding.", val: 3}, {text: "Menyusun rencana transformasi berdasarkan literatur dan riset mandiri melalui mesin pencari.", val: 4}, {text: "Menunda rencana transformasi hingga anggaran tersedia kembali di tahun anggaran berikutnya.", val: 1}] },
{ text: "Anda adalah penanggung jawab hubungan masyarakat di sebuah instansi yang sedang menghadapi keluhan massal di media sosial terkait lambatnya proses perizinan digital. Hasil evaluasi menunjukkan bahwa hambatan tersebut bukan pada sistem instansi Anda, melainkan pada ketidaksiapan data dari instansi mitra yang terintegrasi dalam sistem satu pintu tersebut. Menghadapi situasi yang dapat merusak kepercayaan publik ini, langkah strategis yang Anda ambil untuk menjaga hubungan kerja sama sekaligus menyelesaikan masalah adalah...", options: [{text: "Menjelaskan secara transparan kepada publik mengenai posisi data instansi mitra agar beban opini tidak bertumpu pada instansi Anda.", val: 2}, {text: "Meminta pimpinan instansi Anda untuk mengirimkan teguran resmi agar instansi mitra segera memperbaiki kualitas data mereka.", val: 3}, {text: "Mengajak tim teknis dari kedua instansi duduk bersama untuk merumuskan protokol darurat sinkronisasi data sementara.", val: 5}, {text: "Mengalihkan alur perizinan ke sistem manual untuk sementara waktu hingga instansi mitra berhasil menuntaskan kendala datanya.", val: 1}, {text: "Membangun komunikasi persuasif dengan narahubung instansi mitra untuk bersama-sama menyusun pernyataan publik yang selaras.", val: 4}] },
{ text: "Instansi tempat Anda bekerja sedang berupaya menerapkan sistem kerja fleksibel (Remote Working), namun koordinasi antar divisi menjadi sering terhambat karena perbedaan gaya kerja antara pegawai senior yang terbiasa bertatap muka dan pegawai muda yang sangat teknologis. Sebagai koordinator tim yang berada di antara kedua kelompok tersebut, tindakan Anda untuk memastikan ekosistem kerja tetap produktif dan terkoneksi adalah...", options: [{text: "Mewajibkan seluruh pegawai untuk tetap hadir di kantor pada hari-hari tertentu demi menjaga komunikasi fisik.", val: 3}, {text: "Membuat jadwal bimbingan teknis rutin agar pegawai senior dapat mengikuti standar komunikasi digital tim muda.", val: 4}, {text: "Merancang ruang diskusi virtual yang mengakomodasi gaya kerja formal maupun santai guna menyelaraskan frekuensi tim.", val: 5}, {text: "Memisahkan beban kerja berdasarkan karakteristik pegawai agar setiap kelompok dapat bekerja maksimal sesuai kenyamanannya.", val: 1}, {text: "Menyarankan kepada pimpinan untuk memberikan penghargaan bagi mereka yang paling cepat beradaptasi dengan sistem baru.", val: 2}] },
{ text: "Anda sedang memimpin sebuah proyek riset strategis dan menyadari bahwa data yang dikumpulkan oleh rekan kerja senior Anda memiliki kekeliruan metodologis yang cukup fatal jika tetap diteruskan ke tingkat pimpinan. Di sisi lain, rekan tersebut sangat dihormati dan memiliki pengaruh besar dalam jejaring profesional Anda yang dapat membantu karier Anda di masa depan. Menghadapi dilema antara integritas hasil kerja dan pemeliharaan hubungan baik dengan rekan senior tersebut, Anda akan...", options: [{text: "Melaporkan temuan kesalahan tersebut secara tertutup kepada atasan agar integritas proyek tetap terjaga.", val: 3}, {text: "Mendiskusikan temuan tersebut secara personal dengan rekan senior dengan menyertakan solusi perbaikan datanya.", val: 5}, {text: "Memperbaiki data tersebut secara diam-diam tanpa memberitahu rekan senior agar tidak menyinggung perasaannya.", val: 2}, {text: "Meminta pendapat ahli pihak ketiga untuk memvalidasi temuan Anda sebelum membicarakannya dengan rekan senior.", val: 4}, {text: "Tetap menyertakan data tersebut namun memberikan catatan kecil mengenai potensi risiko ketidakakuratannya.", val: 1}] },
{ text: "Unit Anda sedang merancang program pemberdayaan ekonomi masyarakat, namun Anda melihat bahwa partisipasi dari tokoh masyarakat setempat sangat rendah karena mereka merasa program tersebut terlalu 'kaku' dan bersifat top-down. Untuk memperluas jejaring dan memastikan program ini berhasil mendapatkan dukungan lokal yang kuat, strategi yang Anda terapkan adalah...", options: [{text: "Melakukan sosialisasi ulang dengan bahasa yang lebih sederhana agar mudah dipahami masyarakat.", val: 3}, {text: "Melibatkan tokoh masyarakat sejak tahap perencanaan untuk menyerap aspirasi dan kebutuhan lokal.", val: 5}, {text: "Memberikan kompensasi atau insentif bagi tokoh masyarakat yang bersedia memobilisasi warga.", val: 1}, {text: "Bekerja sama dengan LSM lokal yang sudah memiliki kepercayaan di mata masyarakat setempat.", val: 4}, {text: "Meminta pimpinan daerah untuk memberikan instruksi kepada perangkat desa guna menyukseskan acara.", val: 2}] },
{ text: "Anda baru saja dipindahkan ke unit kerja baru yang memiliki budaya kerja sangat tertutup, di mana setiap pegawai cenderung bekerja secara individualis dan jarang berbagi informasi. Mengingat tugas Anda membutuhkan koordinasi lintas fungsi yang intensif, langkah awal yang paling efektif untuk mencairkan suasana dan membangun jejaring kerja internal yang solid adalah...", options: [{text: "Fokus menyelesaikan tugas pribadi dengan sangat baik agar rekan kerja lain mulai menaruh kepercayaan kepada Anda.", val: 3}, {text: "Mengusulkan sesi diskusi ringan saat jam istirahat untuk saling mengenal kompetensi dan peran masing-masing.", val: 5}, {text: "Meminta bantuan atasan untuk mewajibkan rapat koordinasi mingguan agar informasi antar pegawai terbuka.", val: 4}, {text: "Mengamati gaya kerja masing-masing rekan untuk menyesuaikan diri agar tidak menimbulkan konflik.", val: 2}, {text: "Membagikan informasi penting terkait pekerjaan kepada rekan lain tanpa diminta agar mereka melakukan hal serupa.", val: 1}] },
{ text: "Dalam sebuah konsorsium proyek lintas organisasi, Anda ditunjuk sebagai koordinator lapangan. Namun, Anda menyadari bahwa salah satu organisasi mitra sering terlambat mengirimkan laporan perkembangan karena kekurangan staf ahli, yang berpotensi menghambat pencairan termin anggaran proyek secara keseluruhan. Sikap profesional Anda dalam mengelola jejaring kerja ini adalah...", options: [{text: "Menawarkan bantuan teknis dari staf ahli tim Anda untuk membantu percepatan laporan mitra tersebut.", val: 5}, {text: "Melaporkan keterlambatan tersebut dalam rapat besar agar menjadi catatan evaluasi bagi semua mitra.", val: 2}, {text: "Memberikan peringatan kepada mitra agar lebih profesional dalam memenuhi komitmen kesepakatan.", val: 3}, {text: "Mengatur ulang jadwal proyek agar keterlambatan satu mitra tidak mengganggu alur kerja tim lain.", val: 4}, {text: "Meminta pimpinan konsorsium untuk mengganti mitra tersebut dengan organisasi yang lebih kompeten.", val: 1}] },
{ text: "Unit Anda sedang mengembangkan aplikasi layanan masyarakat, namun Anda melihat ada komunitas relawan teknologi yang memiliki inovasi serupa dan lebih relevan dengan kebutuhan lapangan. Meskipun atasan meminta Anda fokus pada pengembangan internal agar hasil kerja terlihat murni milik instansi, Anda merasa kolaborasi dengan komunitas tersebut akan jauh lebih berdampak. Tindakan Anda adalah...", options: [{text: "Mengabaikan inovasi komunitas tersebut demi menjaga orisinalitas dan reputasi internal unit kerja.", val: 1}, {text: "Mengambil ide-ide terbaik dari komunitas tersebut untuk diterapkan dalam aplikasi internal instansi.", val: 2}, {text: "Mengundang komunitas tersebut untuk berdiskusi dan mengusulkan skema kolaborasi kepada atasan.", val: 5}, {text: "Menyarankan kepada komunitas untuk mengajukan proposal resmi agar bisa menjadi vendor instansi.", val: 3}, {text: "Tetap fokus pada aplikasi internal namun tetap menjaga hubungan komunikasi informal dengan komunitas.", val: 4}] },
{ text: "Anda baru saja ditugaskan memimpin tim lintas divisi yang anggotanya belum pernah bekerja sama sebelumnya. Pada pertemuan pertama, suasana terasa kaku dan setiap anggota hanya menunggu instruksi tanpa memberikan masukan. Untuk membangun fondasi jejaring kerja yang kuat di awal proyek, langkah Anda adalah...", options: [{text: "Memberikan pembekalan teknis mengenai target dan rincian tugas yang harus dicapai.", val: 3}, {text: "Meminta setiap anggota mempresentasikan keahlian unik yang bisa dikontribusikan.", val: 5}, {text: "Memberikan motivasi tentang pentingnya kerja sama tim untuk kesuksesan organisasi.", val: 2}, {text: "Menetapkan pembagian tugas secara adil berdasarkan posisi masing-masing di divisi asal.", val: 4}, {text: "Menunjuk anggota yang paling senior untuk membantu Anda menggerakkan tim.", val: 1}] },
{ text: "Instansi Anda sedang berupaya memperluas jangkauan layanan ke daerah terpencil, namun terkendala minimnya jumlah personel lapangan. Di saat yang sama, terdapat organisasi lokal yang memiliki visi serupa namun belum memiliki legalitas yang kuat. Tindakan Anda dalam mengelola potensi jejaring kerja ini adalah...", options: [{text: "Melaporkan keberadaan organisasi tersebut kepada pihak berwenang agar segera dilegalkan.", val: 2}, {text: "Mengabaikan organisasi tersebut karena risiko perbedaan standar operasional prosedur.", val: 1}, {text: "Menjadikan organisasi tersebut sebagai mitra informal untuk membantu distribusi layanan.", val: 4}, {text: "Menginisiasi forum dialog untuk menyinergikan peran dalam peningkatan layanan publik.", val: 5}, {text: "Menyarankan personel Anda untuk memantau cara kerja organisasi tersebut sebagai referensi.", val: 3}] },
{ text: "Seorang rekan kerja dari instansi lain yang merupakan mitra strategis unit Anda melakukan kesalahan administrasi kecil yang berdampak pada keterlambatan laporan tahunan Anda. Rekan tersebut memohon agar Anda tidak melaporkan hal tersebut secara resmi karena khawatir akan penilaian kinerjanya. Sikap Anda adalah...", options: [{text: "Melaporkan kejadian tersebut secara resmi demi menjaga integritas data unit Anda.", val: 3}, {text: "Membantu rekan tersebut memperbaiki laporannya secara cepat agar tetap sesuai jadwal.", val: 5}, {text: "Mengabaikan permintaannya karena profesionalisme kerja harus diutamakan di atas teman.", val: 1}, {text: "Memberikan teguran keras secara pribadi agar rekan tersebut tidak mengulanginya lagi.", val: 2}, {text: "Menyampaikan kendala tersebut secara lisan kepada atasan tanpa menyebut nama rekan.", val: 4}] },
{ text: "Saat sedang memimpin rapat koordinasi lintas sektoral, terjadi perdebatan sengit antara dua pimpinan unit yang memiliki kepentingan berbeda terkait alokasi sumber daya. Perdebatan ini mulai menghambat pengambilan keputusan proyek. Sebagai fasilitator, tindakan yang Anda ambil adalah...", options: [{text: "Mengambil alih keputusan secara sepihak agar rapat dapat segera diselesaikan.", val: 1}, {text: "Meminta kedua pihak untuk menunda perdebatan dan fokus pada agenda rapat lainnya.", val: 3}, {text: "Mencari titik temu kepentingan kedua pihak yang mendukung pencapaian tujuan utama.", val: 5}, {text: "Mengikuti pendapat pihak yang memiliki posisi atau jabatan lebih tinggi di organisasi.", val: 2}, {text: "Memberikan waktu istirahat agar kedua pihak dapat mendinginkan suasana secara mandiri.", val: 4}] },
{ text: "Anda adalah anggota tim pengembangan yang menyadari bahwa salah satu rekan dari divisi lain sering melewatkan rapat koordinasi mingguan karena beban kerja di divisinya sangat tinggi. Mengingat kehadiran semua divisi sangat penting untuk integrasi sistem, langkah Anda untuk menjaga efektivitas jejaring kerja ini adalah...", options: [{text: "Menyarankan kepada pimpinan untuk memberikan teguran agar rekan tersebut disiplin hadir.", val: 2}, {text: "Mengirimkan ringkasan hasil rapat secara rutin kepada rekan tersebut agar tetap terinformasi.", val: 4}, {text: "Mengajak rekan tersebut berdiskusi untuk mencari waktu rapat yang tidak bentrok dengan jadwalnya.", val: 5}, {text: "Mengambil alih bagian pekerjaan rekan tersebut sementara waktu agar proyek tidak terhambat.", val: 1}, {text: "Melaporkan masalah beban kerja tersebut kepada atasan divisi rekan Anda agar dicarikan solusi.", val: 3}] },
{ text: "Instansi Anda akan meluncurkan layanan baru, namun Anda merasa metode sosialisasi yang direncanakan terlalu tradisional. Anda mengetahui ada komunitas pemuda lokal yang sangat aktif di media sosial dan bisa membantu memperluas jangkauan informasi. Sikap Anda untuk memperkuat jejaring eksternal instansi adalah...", options: [{text: "Mempelajari konten komunitas tersebut untuk ditiru oleh tim media sosial instansi Anda.", val: 2}, {text: "Meminta izin pimpinan untuk bekerja sama dengan komunitas tersebut dalam menyebarkan informasi.", val: 5}, {text: "Memberikan apresiasi berupa bingkisan kepada komunitas tersebut agar mereka mau membantu.", val: 1}, {text: "Menyarankan komunitas tersebut untuk membuat konten positif tentang instansi tanpa ikatan resmi.", val: 3}, {text: "Mengajak komunitas tersebut berdiskusi informal mengenai tren informasi di masyarakat saat ini.", val: 4}] },
{ text: "Unit kerja Anda baru saja menjalin kemitraan dengan perusahaan rintisan (startup) untuk digitalisasi arsip. Namun, beberapa rekan kerja Anda merasa skeptis dan menganggap cara kerja startup yang cepat terlalu berisiko bagi keamanan data. Tindakan Anda untuk menjembatani perbedaan budaya kerja dalam jejaring ini adalah...", options: [{text: "Meminta pihak startup untuk memperlambat tempo kerja mereka agar sesuai dengan budaya instansi.", val: 1}, {text: "Mengusulkan pertemuan bersama untuk membedah protokol keamanan guna membangun rasa percaya tim.", val: 5}, {text: "Fokus pada tugas teknis Anda sendiri tanpa mencampuri perdebatan mengenai keamanan data tersebut.", val: 2}, {text: "Meminta pimpinan untuk meninjau kembali kontrak kerja sama jika kekhawatiran rekan terbukti.", val: 3}, {text: "Memberikan penjelasan mandiri kepada rekan-rekan mengenai keunggulan teknologi startup tersebut.", val: 4}] },
{ text: "Saat Anda sedang mengerjakan proyek kolaborasi antar instansi, terjadi pergantian kepemimpinan di instansi mitra yang mengakibatkan kebijakan mereka berubah dan tidak lagi sejalan dengan rencana awal proyek. Sebagai penanggung jawab teknis, tindakan Anda adalah...", options: [{text: "Menunda proyek sementara hingga pimpinan baru di instansi mitra memahami urgensi rencana awal.", val: 3}, {text: "Melanjutkan proyek sesuai rencana semula sambil berharap instansi mitra akan menyesuaikan diri.", val: 1}, {text: "Mengajak narahubung teknis instansi mitra untuk merumuskan ulang poin kerja sama yang baru.", val: 5}, {text: "Melaporkan kepada atasan Anda bahwa kerja sama harus diputus karena ketidaksesuaian visi.", val: 2}, {text: "Mencari instansi mitra lain yang memiliki visi lebih sejalan untuk menggantikan mitra lama.", val: 4}] },
{ text: "Anda baru saja ditunjuk menjadi ketua tim lintas unit, namun salah satu anggota tim yang jauh lebih senior secara terbuka meragukan arahan Anda dalam rapat. Untuk menjaga integritas tim dan efektivitas jejaring kerja, tindakan Anda adalah...", options: [{text: "Memberikan teguran tegas di depan forum agar wibawa pemimpin tetap terjaga.", val: 1}, {text: "Mengabaikan komentar tersebut dan fokus pada agenda rapat yang sedang berjalan.", val: 3}, {text: "Mendatangi rekan senior tersebut secara personal untuk meminta masukan dan dukungannya.", val: 5}, {text: "Meminta pimpinan unit untuk menjelaskan kembali wewenang Anda kepada tim.", val: 2}, {text: "Menyerahkan sebagian tanggung jawab pengambilan keputusan kepada rekan senior tersebut.", val: 4}] },
{ text: "Unit kerja Anda kekurangan anggaran untuk mengadakan sosialisasi program baru kepada masyarakat, sementara target partisipasi sangat tinggi. Anda mengetahui ada tokoh pemuda yang memiliki pengikut besar di media sosial. Sikap Anda untuk mengoptimalkan jejaring adalah...", options: [{text: "Meminta bantuan tokoh pemuda tersebut untuk mempromosikan program secara sukarela.", val: 4}, {text: "Mengajak tokoh pemuda tersebut berkolaborasi merancang konten sosialisasi yang menarik.", val: 5}, {text: "Memberikan kompensasi finansial agar tokoh tersebut bersedia mengunggah info program.", val: 1}, {text: "Melakukan sosialisasi mandiri melalui media sosial instansi meskipun pengikutnya sedikit.", val: 3}, {text: "Melaporkan keterbatasan anggaran kepada pimpinan agar target partisipasi diturunkan.", val: 2}] },
{ text: "Seorang mitra dari instansi lain sering mengirimkan data yang tidak akurat sehingga menghambat pekerjaan Anda. Namun, mitra tersebut adalah sahabat baik atasan Anda. Dalam mengelola jejaring kerja yang profesional, Anda akan...", options: [{text: "Memberitahukan atasan mengenai ketidakakuratan data tersebut agar ditegur secara halus.", val: 3}, {text: "Memperbaiki sendiri data yang salah tanpa perlu membicarakannya dengan mitra tersebut.", val: 2}, {text: "Mengajak mitra berdiskusi teknis untuk menyamakan standar validasi data yang dibutuhkan.", val: 5}, {text: "Mengurangi frekuensi kerja sama dengan mitra tersebut guna menghindari kesalahan data.", val: 1}, {text: "Mengirimkan catatan revisi resmi setiap kali ditemukan kesalahan data agar ada bukti otentik.", val: 4}] },
{ text: "Instansi Anda sedang menjalankan proyek yang melibatkan banyak pihak, namun setiap pihak hanya fokus pada tugas masing-masing sehingga sinkronisasi antarbagian menjadi sangat buruk. Sebagai salah satu anggota tim, tindakan Anda adalah...", options: [{text: "Fokus menyelesaikan bagian Anda tepat waktu agar tidak menjadi penyebab keterlambatan.", val: 3}, {text: "Menunggu arahan ketua proyek untuk melakukan sinkronisasi dengan bagian lainnya.", val: 2}, {text: "Menginisiasi pembuatan dokumen kontrol bersama yang bisa diakses oleh semua pihak.", val: 5}, {text: "Menyarankan kepada pimpinan untuk memberikan sanksi bagi pihak yang tidak kooperatif.", val: 1}, {text: "Sering mengadakan pertemuan informal dengan anggota dari bagian lain untuk bertukar info.", val: 4}] },
{ text: "Anda baru saja ditugaskan ke sebuah unit yang anggotanya memiliki latar belakang suku dan budaya yang sangat berbeda dari Anda. Rekan-rekan tersebut sering menggunakan bahasa daerah saat berdiskusi santai, sehingga Anda merasa dikucilkan dalam pergaulan kantor. Sikap Anda untuk membangun jejaring kerja yang inklusif adalah...", options: [{text: "Meminta rekan-rekan untuk selalu menggunakan bahasa Indonesia agar Anda bisa ikut mengobrol.", val: 3}, {text: "Fokus bekerja dengan giat agar rekan-rekan tersebut menghargai profesionalisme Anda.", val: 2}, {text: "Mencoba mempelajari kata-kata sederhana bahasa mereka untuk membuka percakapan.", val: 5}, {text: "Mengajak mereka berdiskusi mengenai pekerjaan agar komunikasi tetap terjalin profesional.", val: 4}, {text: "Mencari rekan kerja dari unit lain yang memiliki latar belakang suku yang sama dengan Anda.", val: 1}] },
{ text: "Instansi Anda bekerja sama dengan pihak swasta untuk pengadaan sistem keamanan data, namun dalam pelaksanaannya pihak swasta tersebut sering meminta data internal yang bersifat rahasia di luar kesepakatan kontrak. Sebagai narahubung, tindakan Anda untuk menjaga integritas jejaring kerja adalah...", options: [{text: "Menolak memberikan data tersebut dan menghentikan kerja sama karena sudah melanggar etika.", val: 2}, {text: "Memberikan data yang diminta sebagian saja demi menjaga kelancaran hubungan kerja sama.", val: 1}, {text: "Mengajak pihak swasta meninjau kembali batasan data yang telah disepakati dalam kontrak.", val: 5}, {text: "Melaporkan tindakan pihak swasta tersebut kepada atasan untuk mendapatkan arahan resmi.", val: 4}, {text: "Meminta pihak swasta memberikan alasan tertulis mengapa mereka membutuhkan data tambahan tersebut.", val: 3}] },
{ text: "Anda memimpin sebuah proyek yang sedang mengalami kebuntuan teknis. Anda mengetahui ada seorang mantan pegawai di instansi tersebut yang sudah pensiun namun memiliki keahlian spesifik yang dibutuhkan untuk menyelesaikan masalah tersebut. Sikap Anda adalah...", options: [{text: "Menghubungi mantan pegawai tersebut secara pribadi untuk meminta saran atau konsultasi singkat.", val: 5}, {text: "Meminta tim internal untuk melakukan riset lebih dalam tanpa perlu melibatkan pihak luar.", val: 3}, {text: "Mengusulkan kepada pimpinan agar mengontrak kembali mantan pegawai tersebut sebagai konsultan.", val: 4}, {text: "Mencari referensi di internet mengenai solusi teknis yang pernah diterapkan di instansi lain.", val: 2}, {text: "Menyerahkan masalah tersebut kepada divisi teknologi informasi untuk segera diselesaikan.", val: 1}] },
{ text: "Anda adalah perwakilan instansi dalam tim koordinasi penanganan bencana daerah yang melibatkan unsur pemerintah, TNI/Polri, dan relawan sipil. Di lapangan, terjadi tumpang tindih pembagian logistik karena setiap kelompok cenderung bekerja berdasarkan instruksi internal masing-masing tanpa koordinasi terpadu. Menghadapi potensi kekacauan distribusi ini, tindakan Anda untuk menguatkan jejaring kerja adalah...", options: [{text: "Fokus memastikan distribusi logistik dari instansi Anda tersalurkan dengan aman dan tepat sasaran.", val: 2}, {text: "Melaporkan ketidakteraturan tersebut kepada koordinator pusat agar segera diambil tindakan tegas.", val: 3}, {text: "Menginisiasi pembentukan grup komunikasi instan untuk pemutaran data penerima manfaat secara real-time.", val: 5}, {text: "Mengimbau seluruh pihak untuk menahan diri dan mengikuti satu komando utama dari pemerintah.", val: 4}, {text: "Meminta relawan sipil untuk membantu pencatatan administratif agar data lebih terorganisir.", val: 1}] },
{ text: "Unit kerja Anda sedang menghadapi audit internal, namun salah satu rekan kerja yang memegang dokumen kunci mendadak harus cuti panjang karena alasan keluarga yang mendesak. Rekan tersebut sulit dihubungi, sementara auditor membutuhkan dokumen tersebut segera. Langkah Anda dalam menjaga kelancaran operasional dan hubungan profesional adalah...", options: [{text: "Menghubungi pihak keluarga rekan tersebut untuk menanyakan keberadaan dokumen kunci yang dibutuhkan.", val: 4}, {text: "Mencari dokumen tersebut di ruang kerja rekan Anda dengan mengajak saksi agar tidak timbul fitnah.", val: 5}, {text: "Menjelaskan kendala tersebut kepada auditor dan meminta kelonggaran waktu hingga rekan Anda kembali.", val: 3}, {text: "Meminta pimpinan untuk membatalkan cuti rekan tersebut demi kepentingan audit organisasi.", val: 1}, {text: "Mencoba menyusun kembali dokumen tersebut berdasarkan data sisa yang ada di sistem komputer.", val: 2}] },
{ text: "Instansi Anda berencana melakukan digitalisasi layanan secara besar-besaran, namun Anda melihat banyak pegawai senior di unit lain yang merasa terancam posisinya karena kurangnya literasi digital. Hal ini memicu suasana kerja yang tidak kondusif dan munculnya faksi-faksi antar pegawai. Tindakan Anda sebagai bagian dari tim transformasi adalah...", options: [{text: "Menyarankan skema pensiun dini bagi pegawai yang tidak mampu mengikuti perkembangan teknologi.", val: 1}, {text: "Membuat kampanye internal mengenai manfaat teknologi untuk mempermudah pekerjaan sehari-hari.", val: 4}, {text: "Mengusulkan program 'Mentor Sebaya' di mana pegawai muda mendampingi pegawai senior secara personal.", val: 5}, {text: "Mewajibkan pelatihan teknologi bagi seluruh pegawai dengan sanksi bagi yang tidak lulus kualifikasi.", val: 2}, {text: "Meminta pimpinan untuk menempatkan pegawai senior pada posisi yang tidak bersentuhan dengan teknologi.", val: 3}] },
{ text: "Anda ditugaskan dalam proyek riset lintas daerah, namun Anda mendapati bahwa salah satu perwakilan daerah memberikan data yang tampak tidak konsisten. Di sisi lain, perwakilan tersebut merupakan tokoh yang sangat disegani di wilayahnya dan memiliki pengaruh besar terhadap akses informasi tim Anda di masa depan. Tindakan yang paling tepat untuk menjaga kualitas data sekaligus kelancaran jejaring kerja adalah...", options: [{text: "Mengoreksi data tersebut secara mandiri berdasarkan literatur resmi tanpa memberitahu perwakilan tersebut.", val: 2}, {text: "Meminta klarifikasi secara santun melalui diskusi teknis khusus untuk memahami konteks pengambilan data di lapangan.", val: 5}, {text: "Melaporkan ketidakkonsistenan data tersebut kepada ketua proyek untuk ditindaklanjuti secara resmi.", val: 3}, {text: "Mengabaikan ketidakkonsistenan tersebut demi menjaga hubungan baik dengan tokoh yang berpengaruh.", val: 1}, {text: "Menyarankan adanya pengecekan ulang data oleh pihak ketiga yang netral untuk menjaga objektivitas.", val: 4}] },
{ text: "Instansi Anda akan menyelenggarakan kegiatan nasional yang membutuhkan dukungan logistik cepat dari pihak swasta. Namun, proses pengadaan barang seringkali terhambat oleh birokrasi internal yang lambat, sementara mitra swasta menuntut kepastian pembayaran tepat waktu. Sebagai penanggung jawab kemitraan, langkah Anda adalah...", options: [{text: "Meminta pihak swasta untuk tetap mengirimkan logistik terlebih dahulu dengan jaminan nama baik instansi.", val: 2}, {text: "Mendiskusikan kendala birokrasi dengan bagian keuangan untuk mencari jalur percepatan administrasi yang legal.", val: 5}, {text: "Menghubungi pimpinan perusahaan swasta tersebut untuk memohon pengertian atas keterlambatan prosedur.", val: 3}, {text: "Mencari mitra swasta lain yang lebih memahami dan terbiasa dengan prosedur birokrasi pemerintahan.", val: 4}, {text: "Menyarankan kepada pimpinan untuk menunda kegiatan hingga seluruh administrasi keuangan tuntas.", val: 1}] },
{ text: "Anda memimpin sebuah gugus tugas yang anggotanya terdiri dari berbagai latar belakang profesi (dokter, insinyur, dan ekonom). Saat merumuskan solusi sebuah kebijakan, terjadi perdebatan hebat karena masing-masing pihak merasa sudut pandang profesinya adalah yang paling mendesak untuk diakomodasi. Sikap Anda untuk menyatukan jejaring profesional ini adalah...", options: [{text: "Mengambil keputusan berdasarkan sudut pandang profesi yang memiliki urgensi paling tinggi saat ini.", val: 3}, {text: "Mengadakan sesi curah pendapat untuk memetakan bagaimana setiap keahlian dapat saling melengkapi solusi.", val: 5}, {text: "Menugaskan setiap pihak untuk bekerja secara terpisah dan kemudian Anda gabungkan laporannya.", val: 2}, {text: "Menetapkan keputusan secara mandiri sebagai pemimpin tim untuk menghindari perdebatan yang berlarut.", val: 1}, {text: "Meminta pendapat ahli independen untuk memutuskan sudut pandang mana yang terbaik bagi kebijakan.", val: 4}] },
{ text: "Anda adalah perwakilan instansi yang sedang bernegosiasi dengan sebuah vendor teknologi untuk pemeliharaan sistem. Di tengah pertemuan, pihak vendor menawarkan fasilitas liburan gratis kepada Anda agar proses penandatanganan kontrak dipercepat tanpa melalui pemeriksaan teknis ulang. Untuk menjaga integritas dan profesionalisme dalam jejaring kerja, tindakan Anda adalah...", options: [{text: "Menolak tawaran tersebut secara tegas dan menghentikan proses kerja sama dengan vendor.", val: 2}, {text: "Menghargai tawaran tersebut namun tetap bersikeras melakukan pemeriksaan teknis sesuai prosedur.", val: 5}, {text: "Melaporkan upaya gratifikasi tersebut kepada atasan untuk mendapatkan arahan lebih lanjut.", val: 4}, {text: "Mengalihkan pembicaraan pada poin-poin kontrak agar hubungan kerja tetap berjalan formal.", val: 3}, {text: "Menerima tawaran tersebut asalkan pemeriksaan teknis tetap dilakukan oleh anggota tim lain.", val: 1}] },
{ text: "Unit kerja Anda baru saja menerima pegawai mutasi dari daerah yang memiliki cara komunikasi sangat lugas dan cenderung keras, sehingga sering dianggap tidak sopan oleh rekan-rekan lain di kantor pusat. Suasana tim menjadi kurang harmonis karena banyak yang mulai menjaga jarak. Tindakan Anda sebagai rekan kerja untuk memperbaiki jejaring internal adalah...", options: [{text: "Memberitahu pegawai tersebut secara langsung agar mengubah cara bicaranya sesuai budaya kantor pusat.", val: 3}, {text: "Mengajak rekan-rekan lain untuk lebih memaklumi perbedaan latar belakang budaya pegawai tersebut.", val: 4}, {text: "Menginisiasi kegiatan makan siang bersama untuk mempererat kedekatan personal lintas latar belakang.", val: 5}, {text: "Fokus pada koordinasi pekerjaan saja dan menghindari interaksi personal yang tidak perlu.", val: 2}, {text: "Melaporkan ketidaknyamanan tim kepada atasan agar dilakukan pembinaan perilaku bagi pegawai baru.", val: 1}] },
{ text: "Anda sedang memimpin proyek yang membutuhkan dukungan data sensitif dari divisi lain. Namun, kepala divisi tersebut dikenal sangat protektif dan sulit memberikan data karena pengalaman buruk di masa lalu di mana data divisinya disalahgunakan. Untuk mendapatkan akses data demi kelancaran proyek, langkah Anda adalah...", options: [{text: "Meminta pimpinan tertinggi untuk mengeluarkan instruksi resmi agar data tersebut segera diberikan.", val: 3}, {text: "Menjelaskan secara rinci protokol keamanan data yang Anda terapkan dan memberikan jaminan tertulis.", val: 5}, {text: "Menugaskan anggota tim Anda yang memiliki hubungan dekat dengan kepala divisi tersebut untuk melobi.", val: 4}, {text: "Mencari sumber data alternatif dari luar instansi meskipun akurasinya tidak setinggi data internal.", val: 2}, {text: "Menunggu hingga kepala divisi tersebut luluh dan bersedia memberikan data secara sukarela.", val: 1}] },
{ text: "Anda adalah anggota sebuah forum diskusi antarkantor yang baru saja dibentuk untuk membahas isu digitalisasi. Anda menyadari bahwa forum tersebut mulai sepi karena beberapa anggota merasa topik yang dibahas tidak relevan dengan kebutuhan unit mereka masing-masing. Untuk menghidupkan kembali jejaring kerja ini, tindakan Anda adalah...", options: [{text: "Mengusulkan survei kebutuhan topik kepada seluruh anggota agar pembahasan lebih aplikatif.", val: 5}, {text: "Meminta ketua forum untuk memberikan sanksi bagi anggota yang tidak aktif berkontribusi.", val: 1}, {text: "Rutin membagikan artikel menarik terkait teknologi agar forum tetap terlihat beraktivitas.", val: 3}, {text: "Mengajak beberapa rekan terdekat untuk lebih aktif memicu perdebatan di dalam forum.", val: 2}, {text: "Menyarankan pengadaan pertemuan tatap muka agar hubungan antaranggota lebih akrab.", val: 4}] },
{ text: "Instansi Anda sedang berkolaborasi dengan sebuah organisasi non-pemerintah (LSM) untuk program lingkungan, namun di tengah jalan LSM tersebut menggunakan logo instansi Anda untuk kegiatan politik mereka tanpa izin. Menghadapi situasi yang dapat merusak citra instansi dalam jejaring ini, Anda akan...", options: [{text: "Memutuskan hubungan kerja sama saat itu juga untuk menghindari spekulasi negatif publik.", val: 2}, {text: "Menghubungi pimpinan LSM tersebut untuk meminta klarifikasi dan penghapusan logo segera.", val: 5}, {text: "Membuat pernyataan resmi di media massa bahwa instansi Anda tidak terlibat politik praktis.", val: 4}, {text: "Menegur staf LSM yang bersangkutan secara keras melalui media sosial pribadi Anda.", val: 1}, {text: "Melaporkan tindakan tersebut kepada pihak kepolisian sebagai bentuk pencemaran nama baik.", val: 3}] },
{ text: "Unit Anda sering mengalami keterlambatan dalam penyelesaian tugas karena harus menunggu persetujuan dari unit lain yang prosesnya sangat birokratis. Anda secara pribadi mengenal salah satu staf di unit tersebut yang bisa membantu mempercepat prosesnya secara 'jalur belakang'. Sikap Anda dalam mengelola jejaring ini adalah...", options: [{text: "Memanfaatkan pertemanan tersebut agar tugas unit Anda selalu menjadi prioritas utama.", val: 1}, {text: "Mengajak staf tersebut berdiskusi untuk memahami hambatan birokrasi di unitnya dan mencari solusi legal.", val: 5}, {text: "Tetap mengikuti jalur birokrasi yang ada meskipun lambat demi menjaga integritas sistem.", val: 3}, {text: "Meminta bantuan staf tersebut hanya dalam keadaan yang sangat mendesak atau darurat saja.", val: 2}, {text: "Menyarankan pimpinan kedua unit untuk duduk bersama menyederhanakan prosedur administrasi.", val: 4}] },
{ text: "Anda ditugaskan dalam proyek lintas kementerian yang melibatkan berbagai pakar dengan ego sektoral yang tinggi, sehingga sering terjadi perdebatan mengenai siapa yang paling berwenang menentukan arah kebijakan. Sebagai sekretaris tim, tindakan Anda untuk merekatkan jejaring kerja ini adalah...", options: [{text: "Menyusun draf pembagian tugas yang sangat mendetail sesuai dengan kompetensi masing-masing pakar.", val: 4}, {text: "Mengadakan sesi diskusi terfokus untuk merumuskan tujuan bersama yang melampaui kepentingan masing-masing instansi.", val: 5}, {text: "Meminta pimpinan tim untuk memberikan teguran keras bagi anggota yang terlalu mendominasi perdebatan.", val: 1}, {text: "Mengikuti saja alur perdebatan hingga salah satu pihak mengalah demi efisiensi waktu rapat.", val: 2}, {text: "Mencatat semua masukan dan memberikan ruang bicara yang sama rata bagi setiap pakar tanpa kecuali.", val: 3}] },
{ text: "Instansi Anda sedang berkolaborasi dengan sebuah komunitas difabel untuk memperbaiki aksesibilitas layanan digital. Namun, beberapa rekan kerja Anda merasa masukan dari komunitas tersebut terlalu rumit untuk diimplementasikan dan membuang-buang waktu. Sikap Anda untuk menjaga kualitas jejaring ini adalah...", options: [{text: "Meminta komunitas difabel untuk memberikan saran yang lebih sederhana agar mudah dikerjakan tim.", val: 2}, {text: "Menjelaskan kepada rekan kerja bahwa masukan tersebut adalah kunci inklusivitas layanan yang berkelanjutan.", val: 5}, {text: "Mengambil alih pekerjaan rekan yang mengeluh agar hubungan dengan komunitas tetap terjaga dengan baik.", val: 1}, {text: "Mengajak rekan kerja untuk bertemu langsung dengan pengguna layanan dari komunitas tersebut.", val: 4}, {text: "Menyarankan agar masukan komunitas tersebut diimplementasikan secara bertahap pada tahun berikutnya.", val: 3}] },
{ text: "Anda sedang memimpin riset pasar dan membutuhkan bantuan dari rekan di unit lain yang terkenal sangat sibuk dan jarang merespons permintaan bantuan. Di sisi lain, atasan Anda menuntut laporan riset tersebut selesai dalam dua hari. Langkah paling tepat untuk mengelola jejaring kerja ini adalah...", options: [{text: "Melaporkan kesulitan Anda kepada atasan agar beliau yang meminta bantuan langsung ke unit tersebut.", val: 3}, {text: "Mendatangi meja rekan tersebut secara langsung untuk menjelaskan urgensi tugas dan meminta bantuannya secara personal.", val: 5}, {text: "Mengirimkan email resmi yang ditembuskan ke banyak pimpinan agar rekan tersebut merasa tertekan untuk membantu.", val: 2}, {text: "Mengerjakan tugas tersebut sendiri semaksimal mungkin meskipun hasilnya tidak sesempurna jika dibantu rekan.", val: 1}, {text: "Menghubungi rekan tersebut melalui pesan singkat untuk menanyakan kapan ia memiliki waktu luang untuk berdiskusi.", val: 4}] },
];

const tkp_Antiradikalisme = [
{ text: "Anda adalah seorang ASN senior yang cukup disegani di unit kerja. Suatu hari, Anda mendapati seorang rekan kerja yang juga merupakan teman akrab Anda, sering membagikan konten di grup WhatsApp internal kantor yang berisi narasi kebencian terhadap pemerintah serta ajakan untuk menolak kebijakan negara yang dianggap bertentangan dengan paham keagamaan tertentu. Hal ini mulai memengaruhi opini beberapa pegawai muda di kantor. Sikap Anda adalah...", options: [{text: "Menegur teman tersebut secara pribadi dan mengingatkannya agar tidak membawa isu politik atau agama yang provokatif ke dalam lingkungan kantor demi menjaga netralitas ASN.", val: 4}, {text: "Melaporkan tindakan teman tersebut kepada atasan atau unit kerja terkait yang menangani pelanggaran disiplin dan kode etik agar segera ditindaklanjuti secara resmi.", val: 5}, {text: "Mencoba mengimbangi konten tersebut dengan membagikan nilai-nilai nasionalisme dan moderasi beragama di grup WhatsApp agar pegawai muda tidak terpengaruh.", val: 3}, {text: "Mengajak teman tersebut berdiskusi secara santai di luar jam kantor untuk memahami jalan pikirannya sambil perlahan meluruskan pemahamannya yang keliru.", val: 2}, {text: "Menahan diri untuk tidak berkomentar di grup agar tidak terjadi konflik internal, namun tetap memantau sejauh mana pengaruh narasi tersebut berkembang.", val: 1}] },
{ text: "Di lingkungan tempat tinggal Anda, terdapat seorang tokoh masyarakat baru yang mulai mengadakan pengajian tertutup dan eksklusif. Dalam beberapa kesempatan, Anda mendengar tokoh tersebut menghimbau warga untuk tidak perlu menghormati bendera merah putih dan melarang bergaul dengan tetangga yang berbeda keyakinan karena dianggap tidak sejalan. Warga lain tampak segan (ewuh pakewuh) untuk menegur karena status sosial tokoh tersebut. Tindakan Anda sebagai warga negara yang baik adalah...", options: [{text: "Berkoordinasi dengan Ketua RT dan tokoh agama setempat yang moderat untuk melakukan pendekatan serta memberikan edukasi kepada warga tentang pentingnya toleransi.", val: 4}, {text: "Mengikuti pengajian tersebut sesekali untuk mengumpulkan bukti yang kuat sebelum melaporkannya kepada pihak berwenang atau kepolisian.", val: 2}, {text: "Melaporkan indikasi penyebaran paham intoleran tersebut kepada Babinsa/Bhabinkamtibmas atau pihak kepolisian agar segera dilakukan penyelidikan dan pencegahan.", val: 5}, {text: "Memilih untuk tetap bersosialisasi dengan semua warga tanpa membeda-bedakan untuk menunjukkan secara langsung bahwa nilai keberagaman itu indah.", val: 3}, {text: "Bersikap waspada dan membatasi interaksi keluarga Anda dengan kelompok tersebut agar tidak terpapar paham yang serupa sambil tetap menjaga kerukunan.", val: 1}] },
{ text: "Anda adalah seorang kepala bagian yang baru saja dilantik. Anda menemukan bahwa salah satu bawahan Anda sering menggunakan fasilitas komputer dan jaringan internet kantor di luar jam kerja untuk mengelola situs web dan media sosial milik organisasi yang telah dilarang pemerintah karena terindikasi menyebarkan paham radikal. Bawahan tersebut dikenal sangat rajin dan memiliki kinerja yang sangat baik dalam tugas kantornya. Tindakan Anda...", options: [{text: "Memanggil yang bersangkutan untuk memberikan peringatan keras dan memintanya menghentikan aktivitas tersebut karena menggunakan fasilitas negara untuk hal ilegal.", val: 4}, {text: "Melaporkan temuan tersebut kepada pihak berwajib dan atasan yang lebih tinggi sebagai bentuk pelanggaran berat terhadap sumpah jabatan dan integritas ASN.", val: 5}, {text: "Memberikan tugas tambahan yang lebih banyak agar dia tidak memiliki waktu luang untuk mengurusi situs web tersebut selama berada di kantor.", val: 2}, {text: "Meminta unit TI kantor untuk memblokir akses ke situs-situs tersebut agar fasilitas kantor tidak bisa disalahgunakan lagi oleh siapapun.", val: 3}, {text: "Berdiskusi secara mendalam untuk memahami alasannya bergabung dengan organisasi tersebut dan mencoba meyakinkannya agar kembali ke jalan yang moderat.", val: 1}] },
{ text: "Anda adalah seorang CPNS yang sedang dibimbing oleh seorang mentor senior yang sangat berjasa dalam karier Anda. Suatu hari, mentor tersebut mengajak Anda bergabung dalam sebuah komunitas kajian tertutup yang ia pimpin. Di sana, ia mulai mengajarkan bahwa sistem demokrasi di Indonesia adalah sistem yang sesat dan harus diganti dengan sistem khilafah melalui jalur revolusi. Beliau meminta Anda untuk setia menjaga rahasia komunitas ini sebagai bentuk balas budi. Sikap Anda adalah...", options: [{text: "Menolak ajakan tersebut secara halus agar tidak menyinggung perasaan mentor, namun tetap menjalin hubungan profesional yang baik dengannya.", val: 2}, {text: "Mengingatkan mentor tersebut bahwa sebagai ASN kita telah disumpah untuk setia pada Pancasila dan memohon agar beliau menghentikan kajian tersebut.", val: 4}, {text: "Melaporkan aktivitas mentor tersebut kepada Unit Kerja Kepatuhan Internal atau Badan Intelijen Negara (BIN) melalui kanal pengaduan resmi secara anonim demi keamanan.", val: 5}, {text: "Tetap mengikuti kajian tersebut hanya untuk menjaga hubungan baik, namun tidak menerapkan ajarannya dalam kehidupan sehari-hari.", val: 1}, {text: "Berdiskusi dengan rekan kerja lain yang juga dibimbing oleh beliau untuk menanyakan pendapat mereka sebelum mengambil langkah lebih lanjut.", val: 3}] },
{ text: "Anak Anda menunjukkan sebuah video dari grup belajar sekolahnya yang berisi konten provokatif. Video tersebut mengedit pidato pejabat negara sehingga terkesan menghina agama tertentu, disertai ajakan untuk melakukan aksi protes anarkis di depan kantor pemerintahan. Setelah ditelusuri, ternyata penyebar video tersebut adalah salah satu guru di sekolah tersebut. Sebagai orang tua sekaligus ASN, Anda akan...", options: [{text: "Meminta anak Anda untuk keluar dari grup tersebut dan menghapus videonya agar tidak terpengaruh oleh konten negatif.", val: 2}, {text: "Menghubungi guru tersebut secara pribadi untuk mengklarifikasi niatnya membagikan video tersebut dan mengingatkannya akan dampak hukum UU ITE.", val: 3}, {text: "Mengajak orang tua murid lain untuk memprotes guru tersebut secara langsung di sekolah agar guru tersebut segera diberhentikan.", val: 1}, {text: "Melaporkan temuan tersebut kepada Kepala Sekolah dan Dinas Pendidikan setempat agar guru tersebut diperiksa sesuai dengan kode etik pendidik dan peraturan anti-radikalisme.", val: 5}, {text: "Memberikan penjelasan kepada anak tentang cara menyaring informasi (literasi digital) dan menunjukkan fakta asli dari pidato pejabat tersebut agar anak tidak salah paham.", val: 4}] },
{ text: "Anda terpilih menjadi admin media sosial resmi instansi tempat Anda bekerja. Di kolom komentar salah satu postingan, terjadi perdebatan panas yang mengarah pada sentimen SARA (Suku, Agama, Ras, dan Antargolongan). Beberapa akun bahkan mulai menyebarkan link petisi untuk memisahkan diri dari NKRI karena merasa pemerintah tidak adil terhadap kelompok mereka. Langkah yang Anda ambil adalah...", options: [{text: "Menghapus komentar-komentar yang mengandung SARA dan memblokir akun-akun yang menyebarkan link petisi pemisahan diri tersebut secara tegas.", val: 4}, {text: "Segera mendokumentasikan (screenshot) bukti-bukti komentar tersebut dan melaporkannya ke tim siber Kepolisian serta Kementerian Kominfo untuk ditindaklanjuti.", val: 5}, {text: "Menuliskan komentar balasan yang berisi ajakan untuk menjaga persatuan dan kesatuan bangsa tanpa menghapus komentar negatif tersebut sebagai bentuk kebebasan berpendapat.", val: 2}, {text: "Melaporkan situasi tersebut kepada atasan untuk meminta petunjuk mengenai SOP penanganan komentar negatif yang mengandung unsur radikalisme.", val: 3}, {text: "Mematikan fitur komentar pada postingan tersebut untuk sementara waktu agar perdebatan tidak semakin meluas dan merusak citra instansi.", val: 1}] },
{ text: "Anda adalah anggota tim seleksi untuk pengisian jabatan strategis di instansi Anda. Salah satu kandidat terkuat memiliki kompetensi teknis yang luar biasa dan didukung penuh oleh pimpinan Anda. Namun, Anda menemukan bukti digital bahwa kandidat tersebut aktif dalam organisasi yang visi-misinya ingin mengganti dasar negara Pancasila secara inkonstitusional. Pimpinan Anda meminta Anda untuk 'menutup mata' karena instansi sangat membutuhkan keahlian teknis orang tersebut. Sikap Anda adalah...", options: [{text: "Tetap meloloskan kandidat tersebut namun memberikan catatan khusus agar kinerjanya dipantau ketat oleh unit intelijen internal setelah menjabat.", val: 2}, {text: "Mengikuti arahan pimpinan untuk meloloskan kandidat tersebut demi kepentingan operasional instansi yang lebih besar.", val: 1}, {text: "Menyampaikan keberatan secara tertulis dan formal kepada pimpinan dengan melampirkan bukti-bukti keterlibatan kandidat dalam organisasi radikal sebagai dasar pembatalan.", val: 5}, {text: "Mengajak kandidat tersebut berdiskusi secara pribadi untuk memastikan apakah dia masih memegang teguh paham radikal tersebut sebelum mengambil keputusan.", val: 3}, {text: "Meminta pendapat dari ahli hukum atau pihak berwenang mengenai keabsahan bukti tersebut agar keputusan Anda memiliki dasar hukum yang kuat.", val: 4}] },
{ text: "Di grup media sosial lingkungan perumahan, seorang tetangga yang dikenal sangat dermawan mengajak warga untuk menyumbang pada sebuah yayasan kemanusiaan internasional. Anda secara tidak sengaja membaca rilis resmi dari pemerintah bahwa yayasan tersebut terindikasi kuat menyalurkan dana untuk pendanaan logistik kelompok teroris di Timur Tengah. Beberapa warga sudah mulai mentransfer uang karena rasa percaya pada tetangga tersebut. Tindakan Anda adalah...", options: [{text: "Menghubungi tetangga tersebut secara pribadi dan memberikan informasi rilis pemerintah agar dia berhenti mengajak warga menyumbang ke yayasan tersebut.", val: 4}, {text: "Membagikan rilis resmi pemerintah tersebut ke grup media sosial warga disertai imbauan agar berhati-hati dalam menyalurkan donasi tanpa menyudutkan pihak manapun.", val: 5}, {text: "Menegur tetangga tersebut di grup warga agar semua orang tahu bahwa dia sedang menggalang dana untuk kelompok berbahaya.", val: 2}, {text: "Melaporkan tetangga tersebut ke pihak berwajib secara diam-diam tanpa melakukan tindakan apapun di lingkungan warga agar tidak terjadi keributan.", val: 3}, {text: "Memilih untuk diam dan tidak ikut menyumbang, serta beranggapan bahwa niat warga lain tetap baik untuk kemanusiaan meskipun salah sasaran.", val: 1}] },
{ text: "Seorang rekan kerja di kantor Anda menunjukkan perubahan perilaku yang drastis. Ia mulai menarik diri dari pergaulan, menolak mengikuti upacara bendera dengan berbagai alasan, dan sering tertangkap basah sedang membaca literatur yang menghasut untuk membenci kelompok agama lain di ruang istirahat. Ia adalah rekan setim yang selama ini sangat membantu pekerjaan Anda. Sikap Anda adalah...", options: [{text: "Melaporkan perubahan perilaku dan aktivitas rekan tersebut secara detail kepada atasan atau bagian kepegawaian agar dilakukan pembinaan ideologi.", val: 5}, {text: "Mencoba mengajak rekan tersebut mengobrol dan mengingatkannya bahwa sikapnya dapat membahayakan kariernya sebagai ASN jika diketahui pimpinan.", val: 3}, {text: "Menjauhinya secara perlahan agar Anda tidak dianggap memiliki pemikiran yang sama dengan rekan tersebut oleh rekan kerja yang lain.", val: 2}, {text: "Melakukan diskusi moderasi beragama secara santai dengannya untuk mencoba menariknya kembali ke pemahaman yang inklusif dan toleran.", val: 4}, {text: "Tetap bekerja sama secara profesional dalam urusan kantor dan menganggap perilaku pribadinya adalah hak asasi yang harus dihormati selama tidak mengganggu kerja.", val: 1}] },
{ text: "Anda mendapati adik kandung Anda, yang baru saja lulus kuliah dan sedang mencari kerja, mulai sering mengunggah pernyataan di media sosial yang menghujat ideologi Pancasila dan memuji tindakan kekerasan yang dilakukan oleh kelompok separatis di luar negeri sebagai bentuk perjuangan yang suci. Sebagai seorang ASN dan kakak, sikap Anda adalah...", options: [{text: "Menghapus unggahan adik Anda secara diam-diam melalui ponselnya dan menasihatinya agar tidak melakukan hal tersebut demi keselamatannya sendiri.", val: 2}, {text: "Mengajak adik Anda berdiskusi secara mendalam dari hati ke hati, memberikan pemahaman tentang sejarah bangsa, serta menegaskan konsekuensi hukum jika ia terus menyebarkan paham tersebut.", val: 4}, {text: "Mengajak tokoh agama atau guru yang ia hormati untuk membantu memberikan pencerahan dan membimbingnya kembali ke pemahaman yang moderat dan toleran.", val: 3}, {text: "Mengambil tindakan tegas dengan memberikan peringatan keras, jika tidak diindahkan, Anda akan berkonsultasi dengan pihak berwenang/ahli deradikalisasi untuk langkah mitigasi profesional.", val: 5}, {text: "Berhenti mengikuti akun media sosial adik Anda agar Anda tidak merasa terbebani secara moral dan profesional sebagai seorang ASN.", val: 1}] },
{ text: "Anda baru saja pindah ke unit kerja baru. Dalam rapat internal perdana, atasan langsung Anda secara terang-terangan menyatakan bahwa aturan organisasi harus didasarkan pada hukum agama tertentu dan menyebutkan bahwa pegawai yang tidak sejalan dengan pemahamannya akan sulit mendapatkan promosi. Banyak rekan kerja Anda hanya diam karena takut pada posisi atasan tersebut. Sikap Anda...", options: [{text: "Tetap bekerja dengan profesional sesuai tupoksi dan menghindari pembicaraan mengenai agama atau ideologi dengan atasan tersebut agar karier tetap aman.", val: 2}, {text: "Menggalang dukungan dari rekan kerja lain untuk secara kolektif menyampaikan keberatan kepada atasan tersebut dalam rapat berikutnya.", val: 3}, {text: "Melaporkan indikasi penyalahgunaan wewenang dan penyebaran paham eksklusivisme tersebut kepada Inspektorat atau Komisi Aparatur Sipil Negara (KASN).", val: 5}, {text: "Mencoba mendekati atasan secara pribadi untuk mengingatkan bahwa visi instansi adalah pelayanan publik yang netral dan inklusif bagi seluruh warga negara.", val: 4}, {text: "Mengajukan permohonan mutasi ke unit kerja lain karena merasa lingkungan kerja tersebut sudah tidak sehat dan bertentangan dengan prinsip ASN.", val: 1}] },
{ text: "Di grup WhatsApp 'Alumni Kampus' yang anggotanya berasal dari berbagai latar belakang, salah seorang teman lama Anda membagikan sebuah infografis yang berisi tutorial membuat bahan peledak sederhana dengan narasi 'untuk persiapan melawan ketidakadilan rezim'. Anggota grup lain banyak yang menanggapinya dengan candaan, namun Anda merasa ini adalah hal yang sangat serius. Tindakan Anda...", options: [{text: "Segera keluar dari grup tersebut agar nama Anda tidak terseret jika suatu saat grup tersebut dipantau oleh aparat keamanan.", val: 1}, {text: "Mengingatkan di grup bahwa konten tersebut sangat berbahaya dan melanggar hukum, serta meminta admin grup untuk segera menghapus kiriman tersebut.", val: 4}, {text: "Mendokumentasikan kiriman tersebut dan melaporkannya kepada pihak kepolisian/siber agar segera dilakukan pemantauan terhadap pengirim konten tersebut.", val: 5}, {text: "Menghubungi teman tersebut secara pribadi (japri) untuk menanyakan apakah akunnya sedang dibajak oleh orang lain karena merasa tidak percaya ia mengirim hal seperti itu.", val: 2}, {text: "Memberikan penjelasan mengenai bahaya terorisme dan dampak hukum bagi penyebar konten radikal di dalam grup tersebut agar teman-teman yang lain tidak ikut bercanda.", val: 3}] },
{ text: "Anda adalah seorang Kepala Bagian Kepegawaian. Anda menerima laporan bahwa seorang Kepala Subbagian di bawah Anda secara sistematis hanya memberikan tugas-tugas strategis dan kesempatan pelatihan luar negeri kepada bawahan yang mengikuti kelompok pengajian yang sama dengannya. Sementara itu, pegawai lain yang berbeda keyakinan atau berbeda pemahaman diberikan beban kerja administratif yang tidak relevan dengan pengembangan karier. Tindakan Anda adalah...", options: [{text: "Melakukan rotasi besar-besaran di unit tersebut agar terjadi pembauran antar pegawai tanpa harus menyinggung isu sensitif secara langsung.", val: 2}, {text: "Memanggil Kepala Subbagian tersebut untuk dimintai klarifikasi dan memberikan peringatan lisan agar bertindak adil kepada semua bawahan.", val: 3}, {text: "Mengadakan pertemuan dengan seluruh staf untuk menegaskan kembali nilai-nilai moderasi beragama dan inklusivitas dalam lingkungan kerja ASN.", val: 4}, {text: "Membentuk tim pemeriksa internal untuk menyelidiki dugaan diskriminasi dan memberikan sanksi disiplin berat karena penyalahgunaan wewenang berbasis paham eksklusivisme.", val: 5}, {text: "Menyarankan kepada pegawai yang merasa dirugikan untuk melaporkan hal tersebut secara resmi ke Komisi Aparatur Sipil Negara (KASN) agar objektif.", val: 1}] },
{ text: "Sebagai pengurus di tempat ibadah lingkungan kantor (Masjid/Gereja/Pura kantor), Anda mendapati seorang penceramah tamu yang diundang oleh rekan Anda mulai menyisipkan pesan-pesan yang mendelegitimasi kedaulatan negara dan menyebut bahwa konstitusi saat ini adalah produk 'thogut' atau sesat yang harus diperangi. Banyak jemaah yang tampak terpengaruh oleh retorika tersebut. Sikap Anda adalah...", options: [{text: "Segera menginterupsi ceramah tersebut dengan cara yang sopan dan meluruskan pernyataan penceramah agar tidak terjadi penyesatan informasi di tempat.", val: 4}, {text: "Mendokumentasikan isi ceramah tersebut dan melaporkan penceramah serta rekan yang mengundangnya ke bagian keamanan dan pimpinan instansi.", val: 5}, {text: "Tidak lagi mengizinkan penceramah tersebut untuk mengisi kegiatan di lingkungan kantor di masa mendatang tanpa memberikan penjelasan apapun.", val: 2}, {text: "Memberikan kesempatan bagi penceramah lain yang moderat pada sesi berikutnya untuk menetralisir paham radikal yang telah disampaikan.", val: 3}, {text: "Menahan diri agar tidak terjadi keributan di tempat ibadah, namun segera meninggalkan lokasi sebagai bentuk protes pribadi.", val: 1}] },
{ text: "Di lingkungan tempat tinggal Anda, sekelompok orang baru saja memasang spanduk besar yang mengharamkan warga untuk mengikuti kegiatan sedekah bumi atau festival budaya lokal karena dianggap syirik dan mengancam akidah. Hal ini memicu ketegangan dengan warga asli yang sudah menjalankan tradisi tersebut secara turun-temurun. Sebagai ASN yang tinggal di sana, Anda akan...", options: [{text: "Memilih untuk tidak ikut campur dalam urusan tersebut karena merupakan sensitivitas agama dan Anda ingin menjaga netralitas sebagai ASN.", val: 1}, {text: "Mengusulkan kepada Ketua RT untuk memindahkan lokasi festival budaya agar tidak berdekatan dengan kelompok yang kontra guna menghindari bentrokan.", val: 2}, {text: "Melakukan pendekatan personal kepada pimpinan kelompok tersebut untuk menjelaskan bahwa budaya dan agama bisa berjalan beriringan di Indonesia.", val: 3}, {text: "Berkoordinasi dengan FKUB (Forum Kerukunan Umat Beragama) dan aparat setempat untuk memberikan sosialisasi mengenai moderasi beragama dan pentingnya merawat kearifan lokal.", val: 5}, {text: "Meminta pihak berwenang untuk mencopot spanduk tersebut secara paksa karena dianggap mengganggu ketertiban umum dan memicu disintegrasi warga.", val: 4}] },
{ text: "Anda adalah seorang pejabat pembuat komitmen (PPK) di sebuah instansi pemerintah. Dalam sebuah proyek pengadaan sistem keamanan siber, salah satu perusahaan vendor yang mengajukan penawaran memiliki reputasi teknis yang sangat baik. Namun, berdasarkan laporan intelijen internal, diketahui bahwa direktur utama vendor tersebut merupakan penyokong dana utama bagi organisasi yang memperjuangkan penggantian dasar negara melalui jalur kekerasan. Vendor ini menawarkan harga paling kompetitif dan fitur terbaik. Sikap Anda adalah...", options: [{text: "Membatalkan keikutsertaan vendor tersebut dalam proses tender karena risiko ideologi dapat mengancam keamanan data negara di masa depan.", val: 5}, {text: "Tetap memproses vendor tersebut selama syarat administratif dan teknis terpenuhi untuk menghindari tuntutan hukum atas diskriminasi vendor.", val: 1}, {text: "Melaporkan temuan tersebut kepada atasan dan pihak kepolisian siber untuk meminta arahan legal sebelum mengambil keputusan akhir.", val: 4}, {text: "Meminta vendor tersebut membuat pernyataan tertulis di atas materai bahwa mereka setia pada NKRI dan tidak terlibat organisasi radikal.", val: 2}, {text: "Mengarahkan tim seleksi untuk mencari celah administratif lain guna menggugurkan vendor tersebut secara halus tanpa memicu kegaduhan.", val: 3}] },
{ text: "Di komplek perumahan Anda, seorang warga baru yang vokal mulai mengajak warga lainnya untuk tidak memasang bendera merah putih saat peringatan Hari Kemerdekaan dengan alasan hal tersebut adalah tindakan pemujaan terhadap benda mati yang dilarang agama. Beberapa warga mulai ragu dan mengikuti ajakan tersebut karena segan dengan argumen keagamaan yang dibawakan. Sebagai ASN yang tinggal di sana, tindakan Anda adalah...", options: [{text: "Melaporkan warga tersebut kepada pengurus RT dan aparat wilayah (Babinsa) agar segera diambil tindakan terhadap provokasi anti-simbol negara.", val: 5}, {text: "Tetap memasang bendera di rumah Anda sendiri setinggi mungkin sebagai bentuk protes diam-diam dan contoh bagi warga lainnya.", val: 2}, {text: "Menginisiasi dialog warga dengan menghadirkan tokoh agama yang moderat untuk menjelaskan posisi nasionalisme dan simbol negara dalam perspektif agama yang benar.", val: 4}, {text: "Mendatangi warga tersebut secara pribadi dan memintanya untuk tidak menyebarkan paham yang memicu perpecahan di lingkungan perumahan.", val: 3}, {text: "Memilih untuk tidak ikut campur agar hubungan bertetangga tetap harmonis dan tidak memicu perdebatan agama yang berkepanjangan.", val: 1}] },
{ text: "Anda mengelola akun media sosial resmi instansi. Anda mendapati seorang ASN di instansi yang sama (namun berbeda divisi) sering meninggalkan komentar di postingan kantor yang isinya memicu sentimen kebencian terhadap kelompok minoritas dan memuji-muji aksi terorisme di luar negeri sebagai 'perjuangan yang heroik'. Setelah Anda cek, profil akun tersebut dengan jelas mencantumkan bahwa ia bekerja di instansi Anda. Sikap Anda adalah...", options: [{text: "Menghapus komentar tersebut dan memblokir akun rekan kerja tersebut agar tidak merusak citra digital instansi pemerintah.", val: 3}, {text: "Mendokumentasikan seluruh komentar tersebut dan melaporkannya kepada unit kerja yang menangani disiplin pegawai serta atasan yang bersangkutan.", val: 5}, {text: "Menghubungi rekan kerja tersebut melalui pesan pribadi (DM) dan mengingatkannya bahwa tindakannya melanggar kode etik digital ASN.", val: 2}, {text: "Melaporkan akun tersebut kepada platform media sosial (report spam/hate speech) agar akun tersebut segera ditutup secara otomatis oleh sistem.", val: 4}, {text: "Mengabaikan hal tersebut karena menganggap itu adalah akun pribadi yang bersangkutan dan merupakan hak kebebasan berpendapat di ruang publik.", val: 1}] },
{ text: "Anda melihat seorang teman dekat Anda, yang merupakan influencer muda, sedang dirundung secara masif (di-cancel) di media sosial karena salah satu opininya dianggap kurang religius oleh kelompok tertentu. Tak lama kemudian, muncul sebuah kelompok 'pembela' yang mengajak teman Anda bergabung. Kelompok ini menawarkan perlindungan, namun dengan syarat teman Anda harus mulai membuat konten yang menyerang balik kelompok lain dengan narasi kebencian dan ekstremisme. Teman Anda merasa bimbang dan meminta saran Anda. Sikap Anda adalah...", options: [{text: "Menyarankan teman Anda untuk tidak bergabung dengan kelompok tersebut dan melaporkan akun-akun yang memprovokasi kebencian tersebut kepada pihak berwajib atau platform terkait.", val: 5}, {text: "Mengajak teman Anda untuk beristirahat sejenak dari media sosial (digital detox) agar ia tidak mengambil keputusan gegabah di bawah tekanan publik.", val: 4}, {text: "Menasihati teman Anda agar tetap netral dan tidak membalas rundungan tersebut dengan kebencian, demi menjaga reputasi jangka panjangnya.", val: 3}, {text: "Membantu teman Anda memberikan klarifikasi yang tenang dan moderat di media sosial untuk meredam kemarahan publik tanpa harus bersekutu dengan kelompok ekstrem.", val: 2}, {text: "Memberitahu teman Anda bahwa ia bebas memilih kelompok manapun yang bisa memberikan rasa aman, asalkan ia tetap berhati-hati dalam berucap.", val: 1}] },
{ text: "Sebagai ASN muda, Anda aktif dalam komunitas e-sports di kantor yang anggotanya lintas divisi. Anda mendapati bahwa ketua komunitas tersebut sering menyisipkan pesan di grup Discord komunitas yang menyatakan bahwa loyalitas kepada negara adalah hal yang sia-sia dan mengklaim bahwa sistem pemerintahan saat ini adalah penghambat kemajuan pemuda. Ia mengajak anggota komunitas untuk mulai membangun 'tatanan baru' yang eksklusif. Sikap Anda sebagai anggota adalah...", options: [{text: "Memilih untuk keluar dari komunitas tersebut secara diam-diam agar Anda tidak dikaitkan dengan narasi yang dibangun oleh ketua tersebut.", val: 2}, {text: "Menegur ketua komunitas di dalam grup agar ia berhenti menyebarkan paham politik yang tidak relevan dengan tujuan komunitas hobi.", val: 3}, {text: "Melaporkan indikasi penyebaran paham anti-negara di dalam komunitas tersebut kepada pimpinan instansi atau unit yang menangani kode etik ASN.", val: 5}, {text: "Berdiskusi dengan anggota komunitas lainnya yang sepaham dengan Anda untuk bersama-sama mengganti ketua komunitas tersebut dengan orang yang lebih moderat.", val: 4}, {text: "Mengabaikan pesan-pesan tersebut karena menganggap itu hanyalah ekspresi kekecewaan anak muda yang biasa dan tidak akan berdampak besar.", val: 1}] },
{ text: "Seorang rekan sesama ASN muda mengajak Anda untuk menonton sebuah pameran seni independen. Di pameran tersebut, terdapat sebuah karya instalasi yang secara eksplisit memprovokasi audiens untuk merusak simbol-simbol negara dan memuji gerakan ekstremis luar negeri sebagai contoh kebebasan yang hakiki. Rekan Anda tampak kagum dan menganggap itu adalah puncak dari kebebasan berekspresi pemuda. Tanggapan Anda adalah...", options: [{text: "Mengingatkan rekan Anda bahwa kebebasan berekspresi tetap memiliki batasan hukum, terutama jika sudah mengarah pada penghinaan simbol negara dan radikalisme.", val: 4}, {text: "Segera meninggalkan tempat pameran dan melaporkan penyelenggara pameran kepada pihak berwenang karena memfasilitasi penyebaran konten radikal.", val: 5}, {text: "Mencoba memahami makna karya tersebut dari sudut pandang seni terlebih dahulu sebelum memberikan penilaian benar atau salah.", val: 2}, {text: "Berdebat dengan rekan Anda mengenai definisi radikalisme dan nasionalisme agar ia tidak terbawa arus pemikiran seni yang ekstrem.", val: 3}, {text: "Menikmati pameran tersebut sebagai hiburan belaka tanpa perlu mengaitkannya dengan ideologi atau kewajiban Anda sebagai ASN.", val: 1}] },
{ text: "Sahabat karib Anda sejak SMA, yang kini aktif sebagai content creator muda, mulai sering mengunggah narasi yang mengagungkan tokoh radikal luar negeri sebagai simbol 'perlawanan terhadap ketidakadilan dunia'. Anda sudah mencoba mengingatkannya, namun ia berdalih itu hanya tren estetika perlawanan anak muda. Anda khawatir ia akan segera berurusan dengan hukum jika terus berlanjut. Sikap Anda adalah...", options: [{text: "Melaporkan akun sahabat Anda ke pihak kepolisian agar ia segera mendapatkan pembinaan sebelum pemikirannya menjadi lebih ekstrem.", val: 4}, {text: "Mengajak sahabat Anda bertemu secara personal dan melibatkan mentor atau tokoh yang sangat ia segani untuk memberikan sudut pandang moderat secara mendalam.", val: 5}, {text: "Menghapus kontak dan memutus hubungan pertemanan dengannya agar karier Anda sebagai ASN tidak terancam oleh afiliasi dengannya.", val: 1}, {text: "Menuliskan komentar edukatif di setiap unggahannya agar pengikutnya tidak ikut terpapar paham yang ia bagikan.", val: 2}, {text: "Berdiskusi dengannya dan menyarankan agar ia mengubah kemasan kontennya agar tetap kritis namun tidak melanggar undang-undang anti-radikalisme.", val: 3}] },
{ text: "Anda bergabung dalam sebuah grup diskusi daring (Discord) khusus ASN milenial se-Indonesia. Salah satu anggota grup yang cukup vokal mulai membagikan dokumen internal instansinya dan memprovokasi anggota lain untuk melakukan sabotase terhadap sistem data nasional karena ia menganggap pemerintah saat ini tidak berhak atas data rakyat. Anggota lain mulai terprovokasi. Sikap Anda...", options: [{text: "Mendokumentasikan (screenshot) bukti percakapan dan profil anggota tersebut, lalu melaporkannya secara resmi melalui kanal pengaduan siber Polri atau BSSN.", val: 5}, {text: "Menegur anggota tersebut di dalam grup dan mengingatkannya bahwa tindakannya adalah pelanggaran berat terhadap sumpah jabatan ASN.", val: 3}, {text: "Melaporkan keberadaan grup tersebut kepada atasan Anda untuk meminta petunjuk apakah Anda harus keluar atau tetap memantau.", val: 4}, {text: "Mengabaikan diskusi tersebut dan memilih untuk tidak berkomentar agar tidak dianggap sebagai bagian dari kelompok provokator.", val: 1}, {text: "Mencoba mendebat argumen anggota tersebut dengan data dan fakta yang benar untuk menyeimbangkan opini di dalam grup.", val: 2}] },
{ text: "Anda adalah pengurus sebuah komunitas film pendek anak muda. Anda menemukan bahwa dana operasional komunitas selama setahun terakhir diam-diam didukung oleh donatur yang memiliki afiliasi dengan organisasi terlarang. Donatur ini tidak pernah meminta imbalan apa pun, kecuali meminta agar komunitas sesekali memutar film pendek yang bertema 'ketidakadilan hukum di Indonesia'. Sikap Anda sebagai pengurus adalah...", options: [{text: "Meminta pengurus lain untuk segera memutus hubungan dengan donatur tersebut dan mengembalikan sisa dana yang ada meskipun komunitas terancam bubar.", val: 5}, {text: "Tetap menggunakan dana tersebut namun menolak untuk memutar film yang mereka minta agar komunitas tetap bisa berjalan.", val: 3}, {text: "Melaporkan donatur tersebut kepada pihak kepolisian atas dugaan pendanaan organisasi terlarang dan mencari sumber dana baru yang legal.", val: 4}, {text: "Mengajak pengurus komunitas untuk berdiskusi guna mencari celah bagaimana tetap mendapatkan dana tanpa harus menyebarkan paham donatur tersebut.", val: 2}, {text: "Berhenti dari kepengurusan komunitas secara baik-baik tanpa memberitahu alasan sebenarnya agar tidak terjadi kegaduhan di internal.", val: 1}] },
{ text: "Anda menyadari bahwa algoritma media sosial seorang adik tingkat Anda terus-menerus menampilkan konten video pendek yang memuliakan kekerasan atas nama ideologi tertentu. Adik tingkat Anda mulai menganggap konten tersebut sebagai kebenaran mutlak karena 'semua orang di internet membicarakannya'. Sikap Anda...", options: [{text: "Membiarkannya karena setiap orang memiliki kebebasan dalam mengonsumsi konten digital.", val: 1}, {text: "Melaporkan akun-akun penyebar konten tersebut secara massal melalui fitur report platform.", val: 4}, {text: "Mengajaknya berdiskusi kritis dan membantunya menyeimbangkan algoritma dengan konten moderat.", val: 5}, {text: "Menyarankannya untuk menghapus aplikasi media sosial tersebut agar tidak terpengaruh lebih jauh.", val: 2}, {text: "Memberikan daftar akun media sosial resmi pemerintah yang berisi konten nasionalisme kepadanya.", val: 3}] },
{ text: "Dalam sebuah komunitas game online yang populer di kalangan pemuda kantor, muncul sebuah kelompok yang menggunakan simbol-simbol organisasi terlarang sebagai identitas tim (avatar dan nama grup). Mereka dikenal sangat jago sehingga banyak pemain muda ingin bergabung tanpa peduli makna di balik simbol tersebut. Sikap Anda...", options: [{text: "Memperingatkan anggota muda tentang makna berbahaya di balik simbol tersebut dan risiko hukumnya.", val: 5}, {text: "Melaporkan grup tersebut kepada admin pengembang game agar akun mereka diblokir permanen.", val: 4}, {text: "Ikut bergabung ke dalam tim tersebut untuk memantau aktivitas mereka dari dalam secara diam-diam.", val: 2}, {text: "Mengimbau rekan-rekan untuk membuat tim tandingan yang menggunakan identitas nasionalisme.", val: 3}, {text: "Tidak mempedulikannya selama mereka tidak membawa obrolan radikal ke dalam urusan pekerjaan.", val: 1}] },
{ text: "Anda menemukan seorang rekan kerja milenial sering aktif di forum anonim yang dikenal sebagai sarang penyebaran teori konspirasi anti-Pancasila dan ujaran kebencian. Di forum itu, ia sering bertanya tentang cara memanipulasi data kantor untuk menghambat layanan publik tertentu sebagai bentuk 'protes'. Sikap Anda...", options: [{text: "Mengajak rekan tersebut berdiskusi tentang etika kerja dan dampak buruk sabotase bagi masyarakat.", val: 2}, {text: "Melaporkan aktivitas dan identitas akun rekan tersebut kepada unit siber Polri dan atasan.", val: 5}, {text: "Menegurnya secara pribadi dan memintanya segera menghapus akun di forum anonim tersebut.", val: 3}, {text: "Melaporkan forum anonim tersebut kepada Kementerian Kominfo agar segera diblokir aksesnya.", val: 4}, {text: "Menjaga jarak secara profesional agar tidak ikut terseret jika rekan tersebut tertangkap nantinya.", val: 1}] },
{ text: "Anda menemukan sebuah video deepfake (rekayasa AI) yang sangat halus di grup koordinasi kantor. Video tersebut memperlihatkan pimpinan lembaga Anda seolah-olah sedang memberikan instruksi rahasia untuk mendukung salah satu organisasi radikal yang dilarang negara. Beberapa rekan kerja muda mulai percaya karena kualitas video yang tampak asli. Sikap Anda...", options: [{text: "Menghubungi pimpinan secara langsung untuk mengklarifikasi apakah video tersebut asli atau rekayasa.", val: 3}, {text: "Melaporkan video tersebut kepada tim keamanan siber instansi untuk segera dilakukan takedown dan investigasi.", val: 5}, {text: "Membagikan artikel tentang cara membedakan video deepfake kepada rekan kerja di grup tersebut.", val: 4}, {text: "Menghapus video tersebut dari ponsel Anda dan mengabaikannya agar tidak terjebak dalam hoaks.", val: 1}, {text: "Menunggu pernyataan resmi dari humas lembaga sebelum memberikan komentar apa pun di grup.", val: 2}] },
{ text: "Seorang teman akrab Anda terus-menerus mengunggah narasi di media sosial yang menyudutkan kelompok minoritas dengan menggunakan data statistik yang dimanipulasi. Anda melihat dia terjebak dalam komunitas daring yang sangat tertutup (echo chamber) yang hanya membenarkan pandangannya yang makin ekstrem. Sikap Anda...", options: [{text: "Memblokir akun teman tersebut agar kesehatan mental Anda tetap terjaga dari konten kebencian.", val: 1}, {text: "Melaporkan setiap unggahannya kepada platform media sosial sebagai bentuk ujaran kebencian.", val: 4}, {text: "Mengajaknya bertemu langsung untuk berdiskusi santai sambil menunjukkan data pembanding yang valid.", val: 5}, {text: "Menyarankannya untuk mengikuti akun-akun tokoh nasionalis agar pandangannya lebih berimbang.", val: 3}, {text: "Mendiamkannya karena Anda beranggapan bahwa setiap orang berhak atas opininya masing-masing.", val: 2}] },
{ text: "Instansi Anda menerapkan kebijakan kerja dari rumah (Work From Home). Anda mendapati seorang bawahan Anda sering menggunakan waktu kerja untuk menjadi moderator di forum diskusi daring yang aktif menyebarkan paham anti-Pancasila dan mendiskreditkan simbol negara. Kinerjanya secara teknis tetap baik, namun aktivitas digitalnya sangat radikal. Sikap Anda...", options: [{text: "Memanggilnya untuk memberikan teguran keras terkait penggunaan jam kerja untuk aktivitas non-kantor.", val: 3}, {text: "Mengabaikannya selama tugas-tugas kantor yang diberikan tetap selesai tepat waktu dan berkualitas.", val: 1}, {text: "Mendokumentasikan aktivitas digitalnya dan melaporkannya kepada bagian disiplin pegawai dan atasan.", val: 5}, {text: "Mengajaknya berdiskusi mengenai pentingnya netralitas dan loyalitas ASN terhadap ideologi negara.", val: 4}, {text: "Mengusulkan agar kebijakan Work From Home bagi yang bersangkutan dicabut agar lebih mudah diawasi.", val: 2}] },
{ text: "Di masjid lingkungan rumah Anda, pengurus yang baru mulai melarang warga yang berbeda pandangan politik untuk beribadah di sana. Ia juga sering memberikan ceramah yang mengafirkan kelompok lain yang tidak sejalan. Hal ini mulai menciptakan suasana tidak harmonis di antara warga yang sebelumnya rukun. Sikap Anda...", options: [{text: "Memilih beribadah di tempat lain yang lebih tenang untuk menghindari konflik.", val: 1}, {text: "Menggalang tanda tangan warga untuk mengganti pengurus masjid tersebut secara paksa.", val: 2}, {text: "Melaporkan indikasi paham radikal dan eksklusivitas tersebut kepada KUA atau Kemenag setempat.", val: 5}, {text: "Mengajak pengurus tersebut berdiskusi tentang konsep moderasi beragama dalam Islam.", val: 4}, {text: "Mengimbau warga agar tidak terpengaruh dan tetap menjaga silaturahmi antar tetangga.", val: 3}] },
{ text: "Seorang bawahan Anda mulai menolak mengerjakan tugas dari atasan wanita karena ia meyakini paham bahwa wanita tidak boleh memimpin pria. Ia sering menyebarkan literatur di grup kantor yang menyatakan bahwa menaati aturan negara yang dibuat manusia adalah perbuatan dosa jika tidak sesuai dengan tafsir kelompoknya. Sikap Anda sebagai pimpinan...", options: [{text: "Menghargai keyakinannya sebagai bagian dari hak asasi manusia dan kebebasan beragama.", val: 1}, {text: "Memberikan pembinaan dan peringatan bahwa ASN wajib patuh pada konstitusi dan hierarki jabatan.", val: 5}, {text: "Melaporkannya langsung ke pihak kepolisian agar segera diperiksa terkait paham radikalnya.", val: 3}, {text: "Memindahkan bawahan tersebut ke unit kerja yang dipimpin oleh pria agar kinerjanya membaik.", val: 2}, {text: "Mengajaknya berdialog secara teologis untuk meluruskan pemahamannya tentang kepemimpinan.", val: 4}] },
{ text: "Anda mendapati sebuah yayasan keagamaan di media sosial sedang menggalang dana besar-besaran untuk membantu 'korban perang' di negara konflik. Namun, Anda menemukan informasi valid bahwa dana tersebut digunakan untuk membiayai keberangkatan relawan bersenjata guna bergabung dengan kelompok teroris internasional. Banyak teman Anda yang sudah ikut menyumbang. Sikap Anda...", options: [{text: "Menasihati teman-teman secara pribadi agar lebih berhati-hati dalam memilih lembaga donasi.", val: 3}, {text: "Berhenti menyumbang dan keluar dari grup yang membahas tentang yayasan tersebut.", val: 1}, {text: "Memberikan penjelasan di media sosial tentang modus pendanaan terorisme berkedok kemanusiaan.", val: 4}, {text: "Melaporkan yayasan tersebut ke BNPT atau pihak Kepolisian melalui kanal pengaduan resmi.", val: 5}, {text: "Mempertanyakan transparansi laporan keuangan yayasan tersebut di kolom komentar media sosial mereka.", val: 2}] },
];

const tkp_SosialBudaya = [
{ text: "Anda baru saja ditunjuk sebagai ketua tim proyek digital yang anggotanya berasal dari berbagai latar belakang suku dan zona waktu yang berbeda. Dalam diskusi grup daring, terjadi ketegangan karena salah satu anggota senior dari daerah tertentu sering menggunakan gaya bahasa yang dianggap terlalu lugas dan keras oleh anggota lain yang memiliki budaya tutur kata lebih halus, sehingga suasana kerja menjadi kaku dan produktivitas menurun. Sebagai ketua tim, tindakan Anda adalah...", options: [{text: "Mengingatkan seluruh anggota tim untuk tetap profesional dan fokus pada target proyek tanpa terlalu membawa perasaan ke dalam urusan komunikasi di grup kerja.", val: 3}, {text: "Mengadakan sesi pertemuan virtual santai di luar jam kerja untuk saling mengenal budaya masing-masing agar timbul rasa saling memahami secara personal.", val: 4}, {text: "Melakukan pendekatan personal kepada anggota senior tersebut untuk menjelaskan dinamika komunikasi tim dan bersama-sama merumuskan kesepakatan etiket komunikasi yang inklusif bagi semua.", val: 5}, {text: "Meminta anggota yang merasa tersinggung untuk lebih terbuka dan memaklumi perbedaan karakter rekan kerja demi kelancaran pencapaian target tim.", val: 2}, {text: "Menyusun panduan baku komunikasi tertulis di grup kerja yang wajib dipatuhi oleh seluruh anggota untuk meminimalisir penggunaan kata-kata yang bersifat ambigu.", val: 1}] },
{ text: "Anda tinggal di lingkungan perumahan yang baru saja kedatangan sekelompok pekerja migran dari latar belakang sosial-ekonomi yang berbeda dengan mayoritas warga sekitar. Muncul keresahan di antara warga lama mengenai perubahan suasana lingkungan, dan dalam rapat warga, beberapa orang mengusulkan untuk membatasi akses fasilitas umum bagi para pekerja tersebut guna menjaga kenyamanan. Menghadapi situasi ini, sikap Anda adalah...", options: [{text: "Menyetujui usulan warga untuk menjaga ketertiban lingkungan asalkan dilakukan dengan cara yang sopan dan tidak menyinggung perasaan para pekerja tersebut.", val: 1}, {text: "Mengusulkan program kerja bakti atau kegiatan sosial bersama antara warga lama dan para pekerja tersebut untuk membangun interaksi dan memecah prasangka yang ada.", val: 5}, {text: "Mengingatkan warga bahwa semua orang memiliki hak yang sama, namun menyarankan para pekerja untuk lebih menyesuaikan diri dengan norma yang berlaku di perumahan.", val: 3}, {text: "Memilih untuk diam dan netral agar tidak terjadi konflik dengan tetangga lama, sambil tetap bersikap ramah jika kebetulan berpapasan dengan para pekerja migran.", val: 2}, {text: "Mengajak pengurus RT untuk menyosialisasikan aturan tata tertib lingkungan secara tegas kepada para pekerja agar mereka memahami standar perilaku di lingkungan tersebut.", val: 4}] },
{ text: "Anda ditugaskan ke sebuah daerah terpencil untuk memimpin unit layanan publik. Di sana, terdapat praktik adat tertentu yang sudah turun-temurun dilakukan oleh warga setempat, namun menurut analisis Anda, praktik tersebut sedikit menghambat efisiensi prosedur birokrasi yang baru Anda bawa dari pusat. Di sisi lain, warga sangat menjunjung tinggi adat tersebut. Tindakan Anda adalah...", options: [{text: "Tetap menjalankan prosedur birokrasi dari pusat secara konsisten karena merupakan standar operasional yang berlaku secara nasional di seluruh wilayah.", val: 1}, {text: "Melakukan penyesuaian prosedur layanan dengan menyisipkan unsur nilai lokal ke dalam sistem tanpa mengurangi substansi dan keamanan administrasi birokrasi.", val: 5}, {text: "Melakukan sosialisasi intensif tentang pentingnya modernisasi birokrasi agar warga secara perlahan bersedia meninggalkan praktik adat yang kurang efisien tersebut.", val: 2}, {text: "Mengikuti seluruh keinginan masyarakat dalam menjalankan prosedur adat agar Anda diterima dengan baik oleh warga, meskipun efisiensi kerja menjadi berkurang.", val: 3}, {text: "Berkoordinasi dengan tokoh adat untuk mencari kesepakatan mengenai batas-batas mana yang boleh menggunakan adat dan mana yang harus sesuai aturan negara.", val: 4}] },
{ text: "Anda memimpin unit pelayanan publik di daerah yang memegang teguh tradisi 'sowan' (bertamu secara personal) kepada pejabat sebelum mengurus administrasi resmi. Hal ini menyebabkan antrean digital yang Anda bangun menjadi tidak efektif karena warga lebih memilih jalur belakang melalui pertemuan personal. Sikap Anda adalah...", options: [{text: "Menutup akses pertemuan personal agar warga terbiasa menggunakan sistem digital yang transparan.", val: 2}, {text: "Menugaskan staf khusus untuk menerima 'sowan' warga secara formal sambil memandu mereka input data ke sistem.", val: 4}, {text: "Mengintegrasikan unsur ramah tamah budaya lokal ke dalam alur sistem digital tanpa menghilangkan prosedur resmi.", val: 5}, {text: "Memberikan sosialisasi tegas bahwa aturan negara harus didahulukan daripada tradisi lokal dalam hal birokrasi.", val: 1}, {text: "Meminta tokoh adat setempat untuk mengimbau warga agar beralih sepenuhnya ke layanan digital yang lebih cepat.", val: 3}] },
{ text: "Perusahaan tempat Anda bekerja merekrut beberapa penyandang disabilitas dan rekan dari latar belakang etnis minoritas. Beberapa rekan kerja lama sering melontarkan candaan stereotip yang dianggap akrab bagi mereka, namun terlihat membuat rekan baru merasa tidak nyaman dan terkucilkan dari pergaulan kantor. Tindakan Anda...", options: [{text: "Menegur rekan yang bercanda dan meminta mereka meminta maaf secara terbuka saat rapat divisi.", val: 3}, {text: "Menyarankan rekan baru untuk lebih santai dan menganggap candaan tersebut sebagai bentuk keakraban kantor.", val: 1}, {text: "Menginisiasi dialog kelompok tentang etika kerja inklusif untuk menyepakati batasan profesional yang menghargai perbedaan.", val: 5}, {text: "Melaporkan kejadian tersebut kepada bagian SDM agar dilakukan tindakan disipliner sesuai aturan perusahaan.", val: 2}, {text: "Menjadi teladan dengan selalu berkomunikasi secara inklusif dan merangkul rekan baru dalam setiap aktivitas.", val: 4}] },
{ text: "Anda ditugaskan di wilayah yang baru saja pulih dari konflik antar-kelompok sosial. Saat ingin mengadakan kegiatan peresmian program baru, Anda menyadari bahwa lokasi kegiatan berada di wilayah salah satu kelompok, yang membuat kelompok lain enggan hadir karena merasa tidak terwakili. Menanggapi hal ini, Anda akan...", options: [{text: "Memindahkan lokasi kegiatan ke tempat netral yang dapat diakses dan diterima oleh kedua belah pihak.", val: 5}, {text: "Tetap melaksanakan di lokasi awal namun memberikan porsi peran yang lebih besar bagi kelompok yang keberatan.", val: 3}, {text: "Mengadakan dua kegiatan terpisah di masing-masing wilayah agar kedua kelompok merasa diperlakukan adil.", val: 2}, {text: "Melakukan pendekatan kepada kedua pemimpin kelompok untuk menjamin keamanan dan netralitas kegiatan tersebut.", val: 4}, {text: "Melaksanakan kegiatan sesuai rencana awal karena fokus utama adalah keberhasilan program, bukan masalah lokasi.", val: 1}] },
{ text: "Anda ditugaskan memvalidasi data bantuan sosial di sebuah desa terpencil yang masyarakatnya sangat tertutup dan memiliki trauma masa lalu terhadap pendataan orang asing. Saat Anda datang dengan perangkat digital, warga menolak memberikan informasi karena mencurigai data mereka akan disalahgunakan untuk kepentingan politik tertentu. Sikap Anda...", options: [{text: "Memberikan jaminan tertulis bahwa data aman dan tetap melakukan pendataan sesuai prosedur.", val: 3}, {text: "Meminta bantuan aparat keamanan untuk mendampingi agar proses pendataan berjalan lancar.", val: 1}, {text: "Melakukan pendekatan melalui tokoh adat setempat untuk menjelaskan manfaat bantuan bagi warga.", val: 4}, {text: "Mengadakan pertemuan terbuka untuk mendengarkan kekhawatiran warga dan menyepakati cara pendataan.", val: 5}, {text: "Melaporkan kendala kepada pusat dan menyarankan penundaan hingga situasi lebih kondusif.", val: 2}] },
{ text: "Anda adalah seorang guru di sekolah yang siswanya sangat beragam secara keyakinan. Saat momen perayaan hari besar salah satu agama, muncul perdebatan di antara orang tua murid mengenai keterlibatan siswa dari agama lain dalam kepanitiaan acara tersebut. Beberapa orang tua merasa hal itu melanggar prinsip keyakinan mereka. Tindakan Anda...", options: [{text: "Membatasi kepanitiaan hanya bagi siswa yang merayakan agar tidak menimbulkan konflik lebih luas.", val: 2}, {text: "Menghapuskan semua perayaan keagamaan di sekolah agar tercipta kesetaraan bagi seluruh siswa.", val: 1}, {text: "Mengalihkan fokus kegiatan pada aspek sosial-kemanusiaan yang bisa diikuti semua siswa tanpa batasan ritual.", val: 5}, {text: "Memberikan penjelasan bahwa kegiatan sekolah bersifat opsional bagi yang bersedia berpartisipasi saja.", val: 3}, {text: "Mengundang perwakilan tokoh agama untuk memberikan pemahaman tentang toleransi di lingkungan sekolah.", val: 4}] },
{ text: "Anda bekerja di instansi pemerintah yang sedang menjalin kerja sama dengan konsultan asing dari negara yang sangat disiplin terhadap waktu dan bersifat to-the-point. Rekan-rekan kerja Anda di kantor masih terbiasa dengan budaya kerja yang santai dan sering menyisipkan obrolan personal saat rapat, yang membuat konsultan asing tersebut merasa tidak dihargai. Sikap Anda...", options: [{text: "Meminta maaf kepada konsultan asing dan memintanya memaklumi budaya ramah tamah di Indonesia.", val: 2}, {text: "Menegur rekan kerja secara langsung saat rapat agar lebih menghormati waktu tamu asing tersebut.", val: 3}, {text: "Menjadi moderator rapat yang memastikan agenda tetap pada jalur teknis namun tetap dalam suasana hangat.", val: 5}, {text: "Menyusun jadwal rapat yang sangat ketat dan melarang adanya obrolan di luar urusan pekerjaan.", val: 1}, {text: "Berdiskusi dengan rekan kerja sebelum rapat dimulai untuk menyepakati profesionalitas saat bekerja dengan pihak asing.", val: 4}] },
{ text: "Anda ditugaskan memvalidasi data bantuan sosial di sebuah desa terpencil yang masyarakatnya sangat tertutup dan memiliki trauma masa lalu terhadap pendataan asing. Saat Anda datang dengan perangkat digital, warga menolak memberikan informasi karena mencurigai data mereka akan disalahgunakan untuk kepentingan politik tertentu. Sikap Anda...", options: [{text: "Memberikan jaminan tertulis bahwa data aman dan tetap mendata sesuai prosedur.", val: 3}, {text: "Meminta bantuan aparat keamanan untuk mendampingi agar proses berjalan lancar.", val: 1}, {text: "Melakukan pendekatan melalui tokoh adat untuk menjelaskan manfaat bantuan bagi warga.", val: 4}, {text: "Mengadakan pertemuan terbuka untuk mendengar kekhawatiran warga dan menyepakati cara kerja.", val: 5}, {text: "Melaporkan kendala kepada pusat dan menyarankan penundaan hingga situasi kondusif.", val: 2}] },
{ text: "Anda adalah seorang guru di sekolah dengan siswa yang sangat beragam. Saat momen perayaan hari besar salah satu agama, muncul perdebatan di antara orang tua murid mengenai keterlibatan siswa dari agama lain dalam kepanitiaan acara. Beberapa orang tua merasa hal itu melanggar prinsip keyakinan mereka. Tindakan Anda...", options: [{text: "Membatasi kepanitiaan hanya bagi siswa yang merayakan agar tidak terjadi konflik.", val: 2}, {text: "Menghapuskan semua perayaan keagamaan di sekolah agar tercipta kesetaraan mutlak.", val: 1}, {text: "Mengalihkan fokus kegiatan pada aspek sosial-kemanusiaan yang bisa diikuti semua siswa.", val: 5}, {text: "Memberikan penjelasan bahwa kegiatan bersifat opsional bagi yang bersedia saja.", val: 3}, {text: "Mengundang perwakilan tokoh agama untuk memberikan pemahaman tentang toleransi.", val: 4}] },
{ text: "Anda bekerja di instansi pemerintah yang sedang menjalin kerja sama dengan mitra asing dari negara yang sangat disiplin waktu dan to-the-point. Rekan kerja Anda masih terbiasa dengan budaya santai dan sering menyisipkan obrolan personal saat rapat, yang membuat mitra asing tersebut terlihat kurang nyaman. Sikap Anda...", options: [{text: "Meminta maaf kepada mitra asing dan memintanya memaklumi budaya ramah tamah lokal.", val: 2}, {text: "Menegur rekan kerja secara langsung saat rapat agar lebih menghormati tamu tersebut.", val: 3}, {text: "Menjadi moderator rapat yang memastikan agenda teknis tetap fokus namun suasana hangat.", val: 5}, {text: "Menyusun jadwal rapat yang sangat ketat dan melarang adanya obrolan di luar pekerjaan.", val: 1}, {text: "Berdiskusi dengan rekan sebelum rapat dimulai untuk menyepakati profesionalitas kerja.", val: 4}] },
{ text: "Instansi Anda sedang menerapkan kebijakan baru yang memicu pro-kontra hebat di media sosial. Di grup internal kantor, terjadi perdebatan panas antar pegawai yang mulai menjurus pada sentimen identitas dan pengelompokan kubu, sehingga suasana kerja menjadi tidak kondusif. Sebagai bagian dari tim kerja tersebut, Anda akan...", options: [{text: "Meminta admin grup untuk menutup kolom komentar agar perdebatan tidak meluas.", val: 1}, {text: "Mengajak rekan yang bertikai untuk berdiskusi santai di luar jam kerja guna mendinginkan suasana.", val: 4}, {text: "Menginisiasi forum dialog resmi untuk menyalurkan aspirasi secara profesional dan berbasis data.", val: 5}, {text: "Memilih netral dan fokus pada penyelesaian tugas individu agar tidak terjebak dalam konflik.", val: 2}, {text: "Mengingatkan rekan kerja tentang kode etik pegawai dalam berkomunikasi di ruang digital.", val: 3}] },
{ text: "Anda ditugaskan mengimplementasikan program kesehatan reproduksi di wilayah yang memiliki nilai adat sangat konservatif. Tokoh masyarakat setempat menganggap program Anda bertentangan dengan tabu budaya mereka, sehingga warga menolak kedatangan tim lapangan Anda. Langkah yang Anda ambil adalah...", options: [{text: "Mengganti istilah dan pendekatan program agar lebih selaras dengan bahasa budaya lokal.", val: 5}, {text: "Tetap menjalankan program dengan pengawalan ketat dari pihak berwenang setempat.", val: 1}, {text: "Memberikan edukasi medis secara masif untuk membuktikan bahwa adat tersebut keliru.", val: 2}, {text: "Meminta bantuan tokoh pemuda yang lebih modern untuk meyakinkan orang tua mereka.", val: 4}, {text: "Menunda program sementara waktu sambil menunggu kesiapan mental masyarakat desa.", val: 3}] },
{ text: "Anda baru saja pindah ke lingkungan perumahan yang memiliki jadwal ibadah dan kegiatan keagamaan yang sangat padat dari berbagai keyakinan. Beberapa warga merasa terganggu dengan volume suara dan keramaian yang ditimbulkan, sehingga muncul gesekan kecil antar tetangga. Sebagai warga baru, sikap Anda...", options: [{text: "Mengusulkan pertemuan warga untuk menyepakati batasan volume dan waktu kegiatan bersama.", val: 5}, {text: "Memilih untuk tidak ikut campur dan menyesuaikan diri dengan situasi yang sudah ada.", val: 2}, {text: "Mendatangi tetangga yang paling merasa terganggu untuk memberikan dukungan moral.", val: 3}, {text: "Mengingatkan pengurus RT agar lebih tegas mengatur ketertiban lingkungan sesuai aturan.", val: 4}, {text: "Menutup pintu dan jendela rapat-rapat agar tidak terganggu oleh aktivitas di luar rumah.", val: 1}] },
{ text: "Anda memimpin sebuah program bantuan modal usaha bagi UMKM. Salah satu syarat administratif adalah kepemilikan rekening bank, namun mayoritas pelaku usaha di wilayah penempatan Anda adalah kelompok lansia dari suku tertentu yang secara budaya menghindari institusi perbankan dan lebih mempercayai sistem simpan-pinjam adat. Hal ini menyebabkan penyerapan bantuan sangat rendah. Tindakan Anda adalah...", options: [{text: "Melakukan edukasi perbankan secara intensif agar warga mau membuka rekening sesuai aturan.", val: 2}, {text: "Meminta pusat memberikan pengecualian syarat rekening khusus untuk wilayah tersebut.", val: 3}, {text: "Berkolaborasi dengan lembaga keuangan lokal untuk menyediakan layanan perbankan jemput bola yang didampingi tokoh adat.", val: 5}, {text: "Memberikan kelonggaran bagi warga untuk menggunakan rekening kerabat atau tokoh masyarakat yang dipercaya.", val: 1}, {text: "Menyusun modul pelatihan keuangan yang menggabungkan prinsip perbankan dengan nilai-nilai lokal mereka.", val: 4}] },
{ text: "Anda adalah seorang aparatur desa di wilayah urban yang padat. Terdapat sebuah lapangan serbaguna yang secara rutin digunakan oleh pemuda untuk berolahraga, namun kelompok warga lansia ingin menggunakan lahan tersebut untuk membangun sanggar seni tradisional guna melestarikan budaya lokal. Kedua kelompok saling mengklaim hak penggunaan lahan hingga menimbulkan ketegangan. Sikap Anda...", options: [{text: "Memberikan izin kepada kelompok lansia karena pelestarian budaya memiliki nilai yang lebih luhur.", val: 2}, {text: "Membagi jadwal penggunaan lapangan secara adil agar kedua kelompok tetap bisa beraktivitas.", val: 4}, {text: "Mengusulkan konsep pembangunan ruang multifungsi yang dapat mengakomodasi olahraga dan kegiatan seni secara terintegrasi.", val: 5}, {text: "Meminta kedua pihak untuk bermusyawarah mandiri dan melaporkan hasilnya kepada pihak desa.", val: 3}, {text: "Menutup sementara lapangan tersebut hingga tercapai kesepakatan tertulis agar tidak terjadi keributan.", val: 1}] },
{ text: "Anda baru saja dipindahkan ke unit kerja di daerah yang memiliki budaya komunikasi sangat tidak langsung (high context). Setiap kali Anda memberikan instruksi kerja yang lugas dan to-the-point sebagaimana kebiasaan Anda sebelumnya, rekan kerja merasa tersinggung dan menganggap Anda arogan, sehingga koordinasi pekerjaan menjadi terhambat. Respon Anda adalah...", options: [{text: "Tetap konsisten dengan gaya bicara lugas agar rekan kerja terbiasa dengan profesionalisme kerja modern.", val: 1}, {text: "Mengubah total gaya komunikasi Anda menjadi sangat halus dan mengikuti kebiasaan mereka sepenuhnya.", val: 3}, {text: "Mempelajari pola komunikasi lokal dan menyisipkan basa-basi budaya sebelum menyampaikan poin pekerjaan utama.", val: 5}, {text: "Meminta maaf kepada rekan kerja dan menjelaskan bahwa gaya bicara Anda adalah bawaan daerah asal.", val: 2}, {text: "Mengajak rekan kerja berdiskusi tentang pentingnya komunikasi yang efektif dan cepat dalam dunia kerja.", val: 4}] },
{ text: "Anda baru saja dipromosikan menjadi kepala kantor di wilayah yang kental dengan budaya senioritas. Staf senior di sana sering kali mengabaikan prosedur operasional standar (SOP) baru yang Anda bawa karena merasa pengalaman puluhan tahun mereka lebih valid daripada sistem digital. Hal ini mulai diikuti oleh staf muda dan mengancam kohesi serta performa tim. Tindakan Anda...", options: [{text: "Memberikan sanksi disiplin kepada staf senior agar menjadi pelajaran bagi staf muda lainnya.", val: 1}, {text: "Memberikan apresiasi atas pengalaman staf senior sambil melibatkan mereka sebagai mentor dalam transisi sistem baru.", val: 5}, {text: "Mengadakan rapat evaluasi berkala untuk membuktikan secara data bahwa sistem lama tidak lagi efektif.", val: 3}, {text: "Melakukan pendekatan personal kepada staf muda agar tetap patuh pada aturan meskipun senior mereka melanggar.", val: 2}, {text: "Menyesuaikan kembali SOP agar tetap mengakomodasi beberapa kebiasaan lama staf senior demi menjaga harmoni.", val: 4}] },
{ text: "Anda ditugaskan memimpin sebuah proyek pembangunan fasilitas umum di daerah yang sedang mengalami ketegangan akibat perbedaan pandangan keagamaan. Kelompok mayoritas menuntut agar arsitektur fasilitas tersebut menonjolkan simbol identitas mereka, sementara kelompok minoritas merasa terintimidasi dan menolak rencana tersebut. Sikap Anda sebagai ASN adalah...", options: [{text: "Menunda pembangunan hingga situasi politik dan agama di daerah tersebut benar-benar stabil.", val: 2}, {text: "Mengikuti kemauan mayoritas demi menjamin keamanan dan kelancaran proses pembangunan fisik.", val: 1}, {text: "Mengusulkan desain arsitektur yang netral dan universal namun tetap merepresentasikan kearifan lokal daerah tersebut.", val: 5}, {text: "Mengadakan audiensi terpisah dengan masing-masing kelompok untuk mencari jalan tengah yang paling adil.", val: 4}, {text: "Menyerahkan keputusan desain sepenuhnya kepada pemerintah daerah pusat agar Anda tetap berada di posisi netral.", val: 3}] },
{ text: "Dalam sebuah grup koordinasi resmi instansi yang bersifat lintas daerah, seorang rekan kerja mengunggah konten yang mengandung prasangka SARA terhadap suatu etnis tertentu dengan dalih candaan. Meskipun banyak yang diam, Anda menyadari hal ini mulai menciptakan jarak komunikasi antar anggota grup yang berasal dari etnis tersebut. Respon Anda...", options: [{text: "Melaporkan rekan tersebut secara diam-diam kepada atasan agar ditindak sesuai kode etik.", val: 3}, {text: "Menegur rekan tersebut secara langsung di dalam grup agar semua orang tahu bahwa hal itu tidak benar.", val: 2}, {text: "Menghubungi rekan tersebut secara personal untuk menjelaskan dampak unggahannya dan memintanya mengklarifikasi.", val: 5}, {text: "Mengunggah konten tandingan yang bersifat edukasi tentang keberagaman untuk menetralkan suasana.", val: 4}, {text: "Membiarkan saja selama tidak ada yang merasa keberatan secara terbuka demi menjaga suasana grup.", val: 1}] },
{ text: "Anda adalah pejabat pengadaan yang sedang ditugaskan di sebuah daerah yang memiliki tradisi kuat memberikan 'buah tangan' sebagai bentuk rasa syukur dan penghormatan setelah sebuah urusan selesai. Setelah Anda berhasil menyelesaikan proyek jembatan desa, tokoh masyarakat setempat memberikan hasil bumi yang melimpah ke rumah Anda sebagai tanda terima kasih warga. Sikap Anda adalah...", options: [{text: "Menolak dengan tegas karena pemberian tersebut dapat dikategorikan sebagai gratifikasi.", val: 2}, {text: "Menerima pemberian tersebut agar tidak melukai perasaan warga, lalu membagikannya kembali ke panti asuhan.", val: 5}, {text: "Menerima sebagian kecil saja sebagai bentuk formalitas penghargaan terhadap budaya mereka.", val: 3}, {text: "Menjelaskan aturan hukum mengenai gratifikasi secara mendetail agar warga tidak mengulanginya.", val: 1}, {text: "Melaporkan pemberian tersebut kepada unit pengendalian gratifikasi dan menunggu instruksi lanjut.", val: 4}] },
{ text: "Instansi Anda memiliki anggaran terbatas untuk perbaikan fasilitas ibadah tahun ini. Terdapat dua proposal yang masuk: satu dari kelompok mayoritas yang ingin memperluas bangunan, dan satu dari kelompok minoritas yang ingin memperbaiki atap yang bocor. Kedua kelompok sama-sama merasa paling berhak mendapatkan bantuan. Tindakan Anda adalah...", options: [{text: "Memberikan bantuan kepada kelompok mayoritas demi menjaga stabilitas keamanan wilayah.", val: 1}, {text: "Membagi anggaran secara rata kepada kedua kelompok meskipun hasilnya tidak maksimal bagi keduanya.", val: 3}, {text: "Mengalokasikan bantuan untuk perbaikan kerusakan fisik yang mendesak bagi kelompok minoritas terlebih dahulu.", val: 5}, {text: "Mengadakan musyawarah bersama kedua kelompok untuk menyepakati skala prioritas berdasarkan tingkat kerusakan.", val: 4}, {text: "Menyarankan kedua kelompok untuk mencari dana swadaya agar anggaran negara bisa dialihkan ke sektor lain.", val: 2}] },
{ text: "Unit kerja Anda baru saja kedatangan staf baru dari latar belakang etnis yang secara stereotip dianggap memiliki sifat malas dan kurang disiplin. Beberapa rekan kerja mulai membatasi interaksi dan enggan memberikan tugas penting kepada staf baru tersebut karena terpengaruh stigma tersebut. Sebagai rekan kerja yang lebih senior, Anda akan...", options: [{text: "Mengamati kinerja staf baru tersebut secara objektif sebelum memutuskan untuk berteman dengannya.", val: 2}, {text: "Menegur rekan kerja yang menyebarkan stereotip tersebut agar mereka bersikap lebih profesional.", val: 3}, {text: "Melibatkan staf baru tersebut dalam proyek tim Anda dan memberikan bimbingan untuk membuktikan kemampuannya.", val: 5}, {text: "Menyarankan staf baru tersebut untuk bekerja lebih keras agar bisa mematahkan stigma yang ada.", val: 4}, {text: "Bersikap netral dan tidak ikut campur dalam urusan persepsi rekan kerja terhadap staf baru.", val: 1}] },
{ text: "Anda adalah seorang ASN yang bertugas di bagian Hubungan Masyarakat. Di wilayah tugas Anda, beredar hoaks yang memicu sentimen negatif terhadap kelompok etnis tertentu terkait isu kesehatan nasional. Ketegangan mulai terasa di pasar-pasar tradisional dan ruang publik lainnya. Tindakan paling tepat yang Anda lakukan adalah...", options: [{text: "Melaporkan akun penyebar hoaks kepada pihak kepolisian agar segera ditindak tegas.", val: 2}, {text: "Membuat konten tandingan berupa fakta medis yang valid untuk disebarkan di media sosial.", val: 3}, {text: "Menggandeng tokoh agama dan tokoh masyarakat setempat untuk memberikan klarifikasi secara langsung kepada warga.", val: 5}, {text: "Mengadakan konferensi pers resmi untuk membantah hoaks tersebut agar kepercayaan publik kembali.", val: 4}, {text: "Meminta warga untuk tidak mudah percaya pada informasi yang belum jelas sumber dan kebenarannya.", val: 1}] },
{ text: "Instansi Anda memperkenalkan aplikasi pendaftaran layanan mandiri untuk mengurangi kerumunan. Namun, di daerah penempatan Anda, masyarakat sangat menjunjung tinggi nilai 'guyub' dan merasa pelayanan kurang memuaskan jika tidak berinteraksi langsung dengan petugas. Akibatnya, aplikasi tersebut sepi peminat dan warga tetap berkerumun di kantor. Sikap Anda...", options: [{text: "Menutup loket manual secara permanen agar warga terpaksa beralih menggunakan aplikasi digital.", val: 1}, {text: "Menempatkan petugas pendamping di area ruang tunggu untuk membantu warga menggunakan aplikasi sambil tetap berinteraksi ramah.", val: 5}, {text: "Memberikan insentif berupa antrean prioritas bagi warga yang bersedia menggunakan aplikasi pendaftaran.", val: 4}, {text: "Menambah jumlah kursi dan fasilitas di ruang tunggu agar warga tetap nyaman meskipun harus mengantre lama.", val: 2}, {text: "Melakukan sosialisasi berkala tentang keunggulan teknologi digital dalam mempercepat proses birokrasi.", val: 3}] },
{ text: "Anda ditugaskan dalam proyek pembangunan jalan tol yang harus melewati lahan yang dianggap keramat oleh suku asli setempat. Masyarakat menolak keras pembangunan tersebut meskipun pemerintah telah menyiapkan ganti rugi yang sangat besar, karena lahan tersebut berkaitan dengan identitas leluhur mereka. Sebagai perwakilan pemerintah, Anda akan...", options: [{text: "Melakukan negosiasi ulang dengan menaikkan nilai ganti rugi agar masyarakat mau melepaskan lahan tersebut.", val: 2}, {text: "Meminta bantuan aparat untuk melakukan pengosongan lahan demi kepentingan pembangunan nasional yang lebih luas.", val: 1}, {text: "Mengusulkan rekayasa jalur (rerouting) untuk menghindari area keramat tersebut meskipun memerlukan biaya tambahan.", val: 5}, {text: "Memberikan edukasi bahwa pembangunan jalan tol akan meningkatkan kesejahteraan ekonomi suku tersebut secara jangka panjang.", val: 3}, {text: "Mengajak para ahli antropologi untuk berdiskusi dengan warga guna mencari kesepakatan ritual tertentu sebelum pembangunan dimulai.", val: 4}] },
{ text: "Anda adalah seorang kepala wilayah yang tengah menghadapi situasi di mana salah satu tokoh adat yang sangat dihormati meninggal dunia. Warga bersikeras ingin mengadakan prosesi pemakaman adat yang melibatkan kerumunan besar, padahal saat itu sedang berlaku pembatasan sosial ketat karena wabah. Ketegangan mulai muncul antara petugas keamanan dan warga. Tindakan Anda adalah...", options: [{text: "Memberikan izin khusus hanya untuk prosesi ini demi menjaga stabilitas dan kehormatan tokoh tersebut.", val: 1}, {text: "Meminta petugas keamanan untuk bertindak tegas membubarkan kerumunan demi keselamatan publik.", val: 2}, {text: "Memfasilitasi prosesi adat secara terbatas dengan protokol ketat yang disiarkan daring untuk warga lainnya.", val: 5}, {text: "Melakukan pendekatan personal kepada keluarga inti agar bersedia menunda prosesi adat hingga situasi aman.", val: 4}, {text: "Menjelaskan secara formal melalui pengeras suara tentang sanksi hukum jika warga tetap melanggar aturan.", val: 3}] },
{ text: "Unit kerja Anda meluncurkan program pelatihan ekonomi digital untuk masyarakat luas. Namun, Anda menyadari bahwa kelompok perempuan di sebuah desa tertentu enggan mendaftar karena adanya stigma lokal bahwa teknologi adalah ranah laki-laki, serta keterbatasan waktu karena beban domestik yang tinggi. Langkah yang Anda ambil adalah...", options: [{text: "Mengubah jadwal dan lokasi pelatihan menjadi lebih fleksibel serta berbasis komunitas perempuan setempat.", val: 5}, {text: "Memberikan kuota khusus bagi perempuan agar mereka terdorong untuk mencoba meskipun ada stigma.", val: 3}, {text: "Melakukan sosialisasi masif tentang pentingnya kesetaraan gender dalam dunia kerja digital saat ini.", val: 4}, {text: "Meminta bantuan tokoh agama untuk memberikan ceramah bahwa perempuan boleh belajar teknologi.", val: 2}, {text: "Tetap menjalankan program sesuai rencana awal karena fokus utama adalah profesionalisme peserta.", val: 1}] },
{ text: "Anda ditugaskan di sebuah wilayah di mana terdapat norma sosial yang mengharuskan pendatang untuk memberikan kontribusi berupa hewan ternak untuk upacara desa tertentu. Sebagai ASN, Anda tahu bahwa memberikan sumbangan pribadi dalam jumlah besar bisa membebani keuangan Anda, namun menolak akan membuat Anda dikucilkan oleh masyarakat setempat. Sikap Anda...", options: [{text: "Menolak secara halus dengan alasan bahwa aturan kantor melarang keterlibatan dalam acara adat.", val: 1}, {text: "Menginisiasi sumbangan kolektif bersama rekan kerja lain untuk diberikan atas nama instansi.", val: 5}, {text: "Mencari pinjaman uang agar tetap bisa menyumbang hewan ternak demi nama baik dan kelancaran tugas.", val: 2}, {text: "Menjelaskan kondisi keuangan Anda secara jujur kepada tokoh adat agar diberikan keringanan.", val: 3}, {text: "Mengusulkan kontribusi dalam bentuk lain, seperti bantuan tenaga atau keahlian yang bermanfaat bagi desa.", val: 4}] },
{ text: "Anda adalah seorang kepala wilayah yang tengah menghadapi situasi di mana salah satu tokoh adat yang sangat dihormati meninggal dunia. Warga bersikeras ingin mengadakan prosesi pemakaman adat yang melibatkan kerumunan besar, padahal saat itu sedang berlaku pembatasan sosial ketat karena wabah. Ketegangan mulai muncul antara petugas keamanan dan warga. Tindakan Anda adalah...", options: [{text: "Memberikan izin khusus hanya untuk prosesi ini demi menjaga stabilitas dan kehormatan tokoh tersebut.", val: 1}, {text: "Meminta petugas keamanan untuk bertindak tegas membubarkan kerumunan demi keselamatan publik.", val: 2}, {text: "Memfasilitasi prosesi adat secara terbatas dengan protokol ketat yang disiarkan daring untuk warga lainnya.", val: 5}, {text: "Melakukan pendekatan personal kepada keluarga inti agar bersedia menunda prosesi adat hingga situasi aman.", val: 4}, {text: "Menjelaskan secara formal melalui pengeras suara tentang sanksi hukum jika warga tetap melanggar aturan.", val: 3}] },
{ text: "Unit kerja Anda meluncurkan program pelatihan ekonomi digital untuk masyarakat luas. Namun, Anda menyadari bahwa kelompok perempuan di sebuah desa tertentu enggan mendaftar karena adanya stigma lokal bahwa teknologi adalah ranah laki-laki, serta keterbatasan waktu karena beban domestik yang tinggi. Langkah yang Anda ambil adalah...", options: [{text: "Mengubah jadwal dan lokasi pelatihan menjadi lebih fleksibel serta berbasis komunitas perempuan setempat.", val: 5}, {text: "Memberikan kuota khusus bagi perempuan agar mereka terdorong untuk mencoba meskipun ada stigma.", val: 3}, {text: "Melakukan sosialisasi masif tentang pentingnya kesetaraan gender dalam dunia kerja digital saat ini.", val: 4}, {text: "Meminta bantuan tokoh agama untuk memberikan ceramah bahwa perempuan boleh belajar teknologi.", val: 2}, {text: "Tetap menjalankan program sesuai rencana awal karena fokus utama adalah profesionalisme peserta.", val: 1}] },
{ text: "Anda ditugaskan di sebuah wilayah di mana terdapat norma sosial yang mengharuskan pendatang untuk memberikan kontribusi berupa hewan ternak untuk upacara desa tertentu. Sebagai ASN, Anda tahu bahwa memberikan sumbangan pribadi dalam jumlah besar bisa membebani keuangan Anda secara signifikan, namun menolak akan membuat Anda dikucilkan oleh masyarakat setempat. Sikap Anda...", options: [{text: "Menolak secara halus dengan alasan bahwa aturan kantor melarang keterlibatan dalam acara adat.", val: 1}, {text: "Menginisiasi sumbangan kolektif bersama rekan kerja lain untuk diberikan atas nama instansi.", val: 5}, {text: "Mencari pinjaman uang agar tetap bisa menyumbang hewan ternak demi nama baik dan kelancaran tugas.", val: 2}, {text: "Menjelaskan kondisi keuangan Anda secara jujur kepada tokoh adat agar diberikan keringanan.", val: 3}, {text: "Mengusulkan kontribusi dalam bentuk lain, seperti bantuan tenaga atau keahlian yang bermanfaat bagi desa.", val: 4}] },
{ text: "Anda adalah kepala puskesmas di daerah yang memiliki kepercayaan kuat pada pengobatan tradisional dari seorang tokoh adat. Saat terjadi wabah menular, warga lebih memilih mendatangi tokoh tersebut daripada ke puskesmas, sehingga angka penularan meningkat tajam. Tokoh adat tersebut sebenarnya terbuka, namun merasa ilmunya direndahkan oleh tenaga medis Anda. Tindakan Anda adalah...", options: [{text: "Melakukan sidak bersama aparat keamanan untuk menutup praktik pengobatan tradisional demi keselamatan publik.", val: 1}, {text: "Memberikan edukasi medis secara masif kepada warga bahwa pengobatan tradisional tidak efektif untuk wabah.", val: 2}, {text: "Mengajak tokoh adat bekerja sama dalam proses skrining kesehatan dan memberikan ruang baginya untuk terlibat.", val: 5}, {text: "Meminta bantuan tokoh agama untuk memberikan pemahaman bahwa kesehatan adalah kewajiban agama.", val: 4}, {text: "Melaporkan situasi tersebut kepada dinas kesehatan pusat dan menunggu instruksi penanganan lebih lanjut.", val: 3}] },
{ text: "Anda bekerja di dinas pariwisata daerah yang sedang dikembangkan menjadi destinasi digital nomad. Muncul ketegangan antara wisatawan mancanegara yang bekerja di area terbuka dengan pakaian santai, dan warga lokal yang merasa perilaku tersebut tidak sopan serta melanggar norma kesantunan setempat. Sebagai mediator, Anda akan...", options: [{text: "Menegur wisatawan agar menyesuaikan cara berpakaian mereka dengan aturan budaya lokal secara ketat.", val: 2}, {text: "Meminta warga untuk lebih terbuka dan memaklumi perbedaan budaya demi kemajuan ekonomi daerah.", val: 1}, {text: "Membuat panduan etika bersama yang disosialisasikan kepada wisatawan dan menciptakan ruang kerja khusus.", val: 5}, {text: "Mengadakan forum dialog antara perwakilan wisatawan dan tokoh masyarakat untuk saling mengenal.", val: 4}, {text: "Memasang papan imbauan di area publik tentang cara berpakaian yang pantas di wilayah tersebut.", val: 3}] },
{ text: "Anda dipindahkan untuk memimpin unit kerja yang memiliki reputasi sebagai 'daerah sulit' karena karakteristik masyarakatnya yang dianggap keras dan sulit diatur secara administratif. Staf Anda terlihat mulai kehilangan motivasi dan cenderung bersikap apatis karena merasa usaha mereka akan selalu gagal. Langkah awal Anda adalah...", options: [{text: "Memberikan instruksi tegas dan disiplin tinggi agar staf tidak ikut terpengaruh oleh karakter masyarakat.", val: 1}, {text: "Melakukan studi literatur tentang sejarah dan budaya daerah tersebut untuk mencari pola komunikasi yang tepat.", val: 4}, {text: "Turun langsung ke lapangan bersama staf untuk berinteraksi dengan warga dan mencari keberhasilan kecil sebagai bukti.", val: 5}, {text: "Meminta mutasi kembali ke pusat karena merasa latar belakang budaya Anda tidak cocok dengan daerah tersebut.", val: 1}, {text: "Mengadakan rapat internal untuk mendengarkan keluh kesah staf dan memberikan motivasi spiritual.", val: 3}] },
];

const tkp_TIK = [
{ text: "Instansi tempat Anda bekerja baru saja melakukan migrasi besar-besaran seluruh basis data dan alur kerja ke sistem Cloud Computing untuk mendukung kebijakan work from anywhere. Namun, banyak rekan senior di tim Anda yang merasa kesulitan dan mengeluh karena terbiasa dengan metode penyimpanan manual di perangkat keras masing-masing, sehingga koordinasi pekerjaan menjadi terhambat saat tenggat waktu proyek besar semakin dekat. Sebagai staf yang lebih memahami teknologi, sikap Anda dalam menghadapi situasi ini adalah...", options: [{text: "Fokus menyelesaikan bagian pekerjaan Anda sendiri menggunakan sistem baru agar menjadi contoh nyata bahwa sistem ini lebih efisien dan cepat bagi organisasi.", val: 3}, {text: "Mengusulkan kepada atasan agar memberikan pelatihan khusus bagi pegawai senior dan tetap menggunakan metode manual untuk sementara agar target proyek tidak terganggu.", val: 2}, {text: "Membantu rekan senior dengan cara mengunggah dokumen mereka ke sistem cloud secara rutin agar progres tim tetap terlihat berjalan di dasbor pemantauan.", val: 1}, {text: "Membuat panduan ringkas (infografis) dan secara proaktif membimbing rekan satu tim dalam menggunakan fitur kolaborasi digital agar target proyek dapat diselesaikan bersama secara real-time.", val: 5}, {text: "Menyarankan rekan-rekan untuk mencoba mengeksplorasi fitur sistem baru tersebut secara perlahan dan tetap bersabar menghadapi kendala teknis yang muncul selama masa transisi.", val: 4}] },
{ text: "Anda sedang mengejar tenggat waktu laporan akhir tahun yang sangat padat ketika menerima sebuah email yang tampak sangat resmi dari 'Sistem Kepegawaian Pusat'. Email tersebut menyatakan ada data pribadi Anda yang tidak valid dan Anda diminta segera mengeklik tautan yang terlampir serta melakukan update data dengan memasukkan kredensial akun kantor agar gaji bulan depan tidak tertunda. Di sisi lain, Anda baru saja mendengar kabar burung bahwa sedang marak terjadi serangan siber di instansi pemerintah, maka tindakan yang Anda ambil adalah...", options: [{text: "Mengabaikan email tersebut dan melanjutkan pekerjaan laporan agar selesai tepat waktu, karena merasa tidak pernah ada masalah dengan data kepegawaian sebelumnya.", val: 3}, {text: "Segera mengeklik tautan tersebut dan memperbarui data secepat mungkin agar masalah administrasi selesai dan Anda bisa kembali fokus pada laporan akhir tahun.", val: 1}, {text: "Melaporkan adanya email mencurigakan tersebut kepada unit kerja pengelola TIK atau keamanan siber instansi untuk diverifikasi keasliannya sebelum mengambil tindakan lebih lanjut.", val: 5}, {text: "Menanyakan kepada rekan kerja sejawat apakah mereka menerima email yang sama, lalu memutuskan tindakan berdasarkan apa yang dilakukan oleh mayoritas rekan Anda.", val: 2}, {text: "Mencoba masuk ke portal resmi kepegawaian melalui browser secara terpisah (bukan dari tautan email) untuk mengecek status data, lalu menghapus email tersebut jika data ternyata aman.", val: 4}] },
{ text: "Pimpinan unit kerja Anda menginstruksikan penggunaan alat berbasis Artificial Intelligence (AI) untuk membantu penyusunan draf naskah dinas dan analisis data guna mempercepat pelayanan publik. Namun, terdapat kekhawatiran di kalangan pegawai bahwa penggunaan AI dapat mengurangi akurasi data atau bahkan menggantikan peran manusia. Menghadapi kebijakan penggunaan teknologi baru ini, posisi Anda adalah...", options: [{text: "Menerima instruksi tersebut dan menggunakannya untuk tugas-tugas yang bersifat administratif saja agar risiko kesalahan data akibat AI tetap terkendali.", val: 3}, {text: "Mengintegrasikan alat AI dalam alur kerja Anda, namun tetap melakukan verifikasi ketat secara manual terhadap setiap hasil yang diberikan AI untuk memastikan kualitas dan akurasi tetap terjaga.", val: 5}, {text: "Mempelajari cara kerja alat AI tersebut di waktu luang agar tidak ketinggalan zaman, namun tetap menggunakan metode analisis konvensional untuk pekerjaan resmi demi keamanan.", val: 2}, {text: "Mengikuti arahan pimpinan dengan menggunakan AI sepenuhnya untuk memproses data agar pelayanan publik menjadi jauh lebih cepat dibandingkan metode sebelumnya.", val: 4}, {text: "Menunggu hasil evaluasi penggunaan AI dari rekan kerja yang lain terlebih dahulu, jika terbukti efektif dan aman baru Anda akan mulai menggunakannya.", val: 1}] },
{ text: "Anda sedang memimpin proyek tim menggunakan aplikasi manajemen tugas daring. Salah satu anggota tim yang sangat kompeten bersikeras tetap mengirimkan laporan melalui pesan instan pribadi dengan alasan aplikasi tersebut terlalu rumit, sehingga data tim menjadi terfragmentasi. Sikap Anda...", options: [{text: "Membiarkannya tetap menggunakan pesan instan selama laporannya selesai tepat waktu demi menjaga produktivitasnya.", val: 1}, {text: "Meminta anggota tim lain untuk memindahkan data dari pesan instan ke aplikasi agar riwayat pekerjaan tetap rapi.", val: 2}, {text: "Menegur anggota tersebut secara tegas di depan tim agar mematuhi prosedur digital yang telah disepakati bersama.", val: 3}, {text: "Mengadakan sesi tutorial singkat khusus untuknya dan menekankan pentingnya sentralisasi data bagi transparansi tim.", val: 5}, {text: "Menyarankan dia untuk mencoba aplikasi tersebut perlahan-lahan dan memberikan toleransi keterlambatan input data.", val: 4}] },
{ text: "Saat sedang bekerja di area publik menggunakan jaringan Wi-Fi terbuka untuk mengejar tenggat laporan yang bersifat rahasia, muncul peringatan keamanan pada perangkat Anda bahwa koneksi tersebut tidak terenkripsi. Tindakan yang paling tepat adalah...", options: [{text: "Segera memutuskan koneksi Wi-Fi dan menggunakan tethering pribadi yang lebih aman meskipun kuota terbatas.", val: 5}, {text: "Tetap melanjutkan pekerjaan dengan cepat agar segera selesai sebelum ada potensi peretasan data terjadi.", val: 1}, {text: "Mengaktifkan fitur mode samaran (incognito) pada peramban agar aktivitas pencarian tidak terlacak oleh pihak luar.", val: 2}, {text: "Mencari lokasi lain yang menyediakan Wi-Fi publik dengan sinyal lebih kuat dan stabil untuk melanjutkan laporan.", val: 3}, {text: "Memasang aplikasi antivirus tambahan saat itu juga untuk memitigasi risiko serangan siber selama terhubung Wi-Fi.", val: 4}] },
{ text: "Instansi Anda baru saja memperbarui sistem layanan mandiri untuk masyarakat, namun sistem tersebut masih sering mengalami perlambatan (lag) saat jam sibuk, sehingga antrean fisik tetap terjadi. Sebagai petugas layanan, respon Anda adalah...", options: [{text: "Meminta masyarakat untuk maklum dan menyarankan mereka kembali lagi saat sistem sudah tidak sibuk.", val: 2}, {text: "Tetap melayani secara manual sepenuhnya tanpa menggunakan sistem agar antrean fisik segera terurai.", val: 3}, {text: "Mencari tahu fitur sistem yang menyebabkan lag dan mengusulkan perbaikan teknis spesifik kepada tim IT.", val: 5}, {text: "Mengarahkan masyarakat untuk menggunakan layanan daring dari rumah masing-masing agar tidak menumpuk di kantor.", val: 4}, {text: "Menjalankan sistem apa adanya sambil sesekali meminta maaf kepada masyarakat atas kendala yang terjadi.", val: 1}] },
{ text: "Anda ditugaskan menyusun draf kebijakan strategis yang harus selesai dalam waktu singkat. Anda memutuskan menggunakan bantuan Generative AI untuk mempercepat pengerjaan. Namun, hasil analisis AI tersebut mencantumkan beberapa data statistik yang tampak meyakinkan tetapi Anda ragu akan keabsahannya. Sikap Anda adalah...", options: [{text: "Langsung menggunakan hasil analisis AI tersebut agar draf kebijakan selesai tepat waktu dan segera diserahkan kepada pimpinan.", val: 1}, {text: "Menghapus bagian data yang diragukan dan hanya menggunakan narasi umum dari AI untuk melengkapi draf kebijakan tersebut.", val: 3}, {text: "Mencantumkan keterangan bahwa draf tersebut disusun dengan bantuan AI sebagai bentuk transparansi penggunaan teknologi.", val: 2}, {text: "Menggunakan AI sebagai kerangka berpikir saja, lalu melakukan verifikasi ulang setiap data menggunakan sumber data primer resmi instansi.", val: 5}, {text: "Meminta rekan kerja yang lebih ahli di bidang statistik untuk memvalidasi hasil dari AI tersebut sebelum dimasukkan ke draf.", val: 4}] },
{ text: "Instansi Anda sedang mengalami gangguan sistem akibat serangan siber yang mengunci akses data penting. Di saat bersamaan, Anda menemukan sebuah flashdisk di meja kerja yang Anda duga berisi cadangan data laporan minggu lalu, namun Anda tidak ingat siapa yang meletakkannya di sana. Tindakan Anda adalah...", options: [{text: "Segera memasukkan flashdisk tersebut ke komputer untuk mengecek isinya dan memulihkan data yang terkunci.", val: 1}, {text: "Menyerahkan flashdisk tersebut kepada bagian TIK untuk dipindai dan dipastikan keamanannya sebelum digunakan.", val: 5}, {text: "Bertanya kepada seluruh rekan di ruangan tentang kepemilikan flashdisk tersebut sebelum memutuskan untuk membukanya.", val: 3}, {text: "Menyimpan flashdisk tersebut dan menunggu instruksi resmi dari pimpinan terkait prosedur pemulihan data.", val: 2}, {text: "Menggunakan komputer pribadi yang tidak terhubung jaringan kantor untuk mengecek isi flashdisk tersebut demi keamanan.", val: 4}] },
{ text: "Anda diminta mengintegrasikan data dari berbagai bidang di unit kerja Anda ke dalam satu dasbor digital baru (Satu Data). Namun, setiap bidang memiliki format data yang berbeda dan beberapa rekan enggan mengubah format mereka karena merasa cara lama lebih nyaman. Respon Anda terhadap hambatan ini adalah...", options: [{text: "Melaporkan kepada pimpinan bahwa integrasi data sulit dilakukan karena adanya ego sektoral dan perbedaan format di tiap bidang.", val: 2}, {text: "Mengonversi semua data secara manual ke format baru tanpa melibatkan rekan lain agar dasbor digital segera berfungsi.", val: 3}, {text: "Mengusulkan standardisasi format data digital yang disepakati bersama dan menjelaskan manfaat efisiensi jangka panjang bagi semua pihak.", val: 5}, {text: "Memberikan kelonggaran bagi setiap bidang untuk tetap menggunakan format lama asalkan data tetap masuk ke dasbor meskipun tidak rapi.", val: 1}, {text: "Mengembangkan sistem konverter otomatis yang bisa membaca semua jenis format data agar rekan kerja tidak perlu mengubah cara kerja mereka.", val: 4}] },
{ text: "Dalam upaya mempercepat penyelesaian tugas yang menumpuk, rekan setim Anda menggunakan aplikasi pihak ketiga yang tidak resmi dari instansi untuk mengolah data laporan karena fitur-fiturnya jauh lebih canggih daripada aplikasi resmi. Ia menyarankan Anda melakukan hal yang sama agar target tercapai. Sikap Anda adalah...", options: [{text: "Mengikuti saran tersebut demi efisiensi kerja dan mencapai target waktu yang ditetapkan oleh pimpinan.", val: 1}, {text: "Menggunakan aplikasi tersebut hanya untuk data yang tidak bersifat rahasia, sementara data sensitif tetap di aplikasi resmi.", val: 3}, {text: "Menolak menggunakannya dan menyarankan rekan tersebut untuk berdiskusi dengan unit TIK mengenai kebutuhan fitur tambahan pada aplikasi resmi.", val: 5}, {text: "Mengapresiasi kreativitas rekan tersebut namun memilih tetap menggunakan sistem resmi meskipun lebih lambat demi keamanan.", val: 4}, {text: "Melaporkan tindakan rekan tersebut kepada atasan karena telah melanggar prosedur penggunaan perangkat lunak di kantor.", val: 2}] },
{ text: "Anda adalah pengelola media sosial instansi. Saat mendokumentasikan kegiatan pelayanan publik untuk konten promosi, terdapat foto yang menunjukkan wajah warga beserta data identitas pada dokumen yang sedang mereka pegang secara jelas. Respon Anda dalam mengunggah konten tersebut adalah...", options: [{text: "Tetap mengunggahnya karena foto tersebut menunjukkan bukti nyata transparansi dan kinerja pelayanan instansi kepada publik.", val: 1}, {text: "Mengunggah foto tersebut namun memberikan keterangan di kolom komentar bahwa data tersebut hanya digunakan untuk keperluan konten.", val: 2}, {text: "Mengunggah foto setelah melakukan penyuntingan dengan menyamarkan (sensor) wajah warga dan data pribadi yang terlihat pada dokumen.", val: 4}, {text: "Memilih foto lain yang tidak menampilkan data sensitif atau meminta izin tertulis dari warga tersebut sebelum melakukan publikasi.", val: 5}, {text: "Hanya menyamarkan bagian data identitas saja karena wajah warga diperlukan untuk membangun kedekatan emosional dalam konten.", val: 3}] },
{ text: "Instansi Anda menerapkan sistem pelaporan baru yang terintegrasi antar departemen. Namun, saat Anda harus memasukkan data krusial, sistem tersebut terus mengalami kegagalan sinkronisasi (error) karena perbedaan format dari departemen pengirim. Padahal, data tersebut harus segera dipaparkan sore ini. Tindakan Anda adalah...", options: [{text: "Menghubungi departemen pengirim untuk meminta data ulang dalam format yang sesuai dengan spesifikasi sistem baru.", val: 4}, {text: "Melakukan perbaikan format secara manual pada data yang bermasalah agar sistem dapat membacanya dan laporan selesai tepat waktu.", val: 5}, {text: "Menggunakan data lama yang sudah ada di sistem sebelumnya untuk sementara waktu agar paparan tidak tertunda.", val: 2}, {text: "Melaporkan kendala teknis tersebut kepada pimpinan dan meminta izin untuk menyampaikan paparan secara manual tanpa sistem.", val: 3}, {text: "Menunggu tim IT memperbaiki sistem sinkronisasi karena itu merupakan tanggung jawab teknis mereka, bukan bagian tugas Anda.", val: 1}] },
{ text: "Anda baru saja dipindahkan ke unit kerja yang masih menggunakan sistem pengarsipan fisik untuk surat menyurat, yang seringkali menyebabkan keterlambatan pencarian data saat pimpinan membutuhkannya segera. Anda tahu bahwa instansi menyediakan lisensi aplikasi manajemen dokumen digital namun belum dimanfaatkan di unit tersebut. Sikap Anda adalah...", options: [{text: "Menyarankan kepada rekan sejawat untuk mulai memindai dokumen penting ke dalam format digital agar lebih mudah ditemukan jika sewaktu-waktu dibutuhkan pimpinan.", val: 4}, {text: "Fokus mengikuti prosedur pengarsipan fisik yang sudah ada di unit tersebut agar tidak menimbulkan konflik dengan rekan kerja yang sudah nyaman dengan cara lama.", val: 2}, {text: "Mempelajari aplikasi manajemen dokumen tersebut secara mandiri, lalu mengajukan usul beserta simulasi alur kerja digital yang lebih cepat kepada kepala unit.", val: 5}, {text: "Memindahkan tugas pengarsipan kepada staf administrasi yang lebih muda karena mereka biasanya lebih cepat dalam mengadopsi penggunaan aplikasi digital.", val: 1}, {text: "Membantu mencari dokumen secara manual dengan lebih giat setiap kali pimpinan membutuhkan agar keterlambatan dapat diminimalisir.", val: 3}] },
{ text: "Sebagai warga negara, Anda sering menggunakan aplikasi layanan publik pemerintah untuk mengurus administrasi kependudukan. Suatu hari, Anda menyadari bahwa aplikasi tersebut meminta akses ke daftar kontak dan lokasi Anda secara terus-menerus, padahal fitur tersebut tidak relevan dengan layanan kependudukan yang Anda akses. Tindakan Anda adalah...", options: [{text: "Tetap memberikan semua izin akses yang diminta agar proses administrasi kependudukan Anda tidak terhambat atau ditolak oleh sistem.", val: 1}, {text: "Menghapus aplikasi tersebut dan memilih mengurus administrasi secara luring (datang ke kantor) demi menjamin keamanan data pribadi secara total.", val: 2}, {text: "Memberikan izin akses hanya saat aplikasi digunakan, kemudian segera mematikan kembali izin tersebut melalui pengaturan perangkat setelah selesai.", val: 3}, {text: "Mengatur izin aplikasi secara selektif dan memberikan masukan melalui fitur 'Ulasan' atau saluran pengaduan resmi mengenai urgensi privasi data pengguna.", val: 5}, {text: "Mengabaikan permintaan akses tersebut dan mencoba mencari aplikasi serupa di toko aplikasi yang tidak meminta izin akses terlalu banyak.", val: 4}] },
{ text: "Di grup pesan instan kantor yang berisi seluruh pegawai, seorang rekan senior membagikan sebuah tautan berita dengan judul bombastis mengenai kebijakan tunjangan pegawai yang berubah drastis. Setelah Anda cek di situs resmi kementerian terkait, informasi tersebut ternyata tidak benar (hoaks). Menghadapi situasi ini, Anda akan...", options: [{text: "Menghubungi rekan senior tersebut secara pribadi untuk memberikan tautan dari situs resmi sebagai pembanding agar ia tidak merasa dipermalukan di grup.", val: 5}, {text: "Segera membantah informasi tersebut di grup besar dengan melampirkan bukti dari situs resmi agar pegawai lain tidak terlanjur percaya.", val: 4}, {text: "Membiarkan saja pesan tersebut karena merasa bukan tugas Anda untuk mengoreksi atasan atau rekan senior guna menjaga keharmonisan kantor.", val: 1}, {text: "Menunggu pimpinan atau admin grup yang memberikan klarifikasi resmi agar tidak terjadi perdebatan antar pegawai di grup pesan instan.", val: 2}, {text: "Menanyakan kebenaran berita tersebut kepada rekan kerja yang lain melalui jalur pribadi sebelum memutuskan untuk mengambil tindakan.", val: 3}] },
{ text: "Anda ditugaskan mengunggah laporan capaian kinerja unit ke sistem pusat. Namun, sistem tersebut terus menolak dokumen Anda karena perbedaan format angka dan struktur tabel dari aplikasi pengolah data yang Anda gunakan. Rekan Anda menyarankan untuk mengunggah seadanya yang penting terlihat sudah 'terkirim' di sistem. Sikap Anda adalah...", options: [{text: "Menuruti saran rekan tersebut agar status laporan di dasbor pimpinan segera berubah menjadi hijau (terkirim).", val: 1}, {text: "Mengunduh panduan format sistem pusat, menyesuaikan data Anda secara mandiri hingga valid, lalu baru mengunggahnya.", val: 5}, {text: "Meminta bantuan unit TIK untuk melakukan proses integrasi data tersebut karena itu adalah kendala teknis sistem.", val: 3}, {text: "Mengirimkan dokumen asli melalui email kepada admin sistem pusat agar mereka yang menyesuaikan formatnya.", val: 2}, {text: "Mencoba menggunakan aplikasi konverter daring (online) untuk mengubah format secara cepat agar segera terunggah.", val: 4}] },
{ text: "Sebagai petugas admin pengelola kanal pengaduan instansi, Anda menerima keluhan dari warga yang menggunakan bahasa kasar dan tidak sopan terkait keterlambatan layanan. Warga tersebut juga mengunggah foto bukti layanan yang secara tidak sengaja memperlihatkan data sensitif milik warga lain. Tindakan Anda...", options: [{text: "Langsung menghapus komentar tersebut karena melanggar etika kesopanan dan mengandung data sensitif orang lain.", val: 2}, {text: "Membalas dengan tegas agar warga tersebut menjaga sopan santun jika ingin keluhannya diproses oleh instansi.", val: 1}, {text: "Mengarsipkan keluhan tersebut, menyamarkan data sensitif pada foto, lalu membalasnya dengan solusi secara profesional.", val: 5}, {text: "Mengabaikan keluhan tersebut hingga warga tersebut mengirimkan ulang aduan dengan bahasa yang lebih santun.", val: 3}, {text: "Melaporkan akun warga tersebut kepada penyedia platform media sosial karena dianggap menyebarkan konten negatif.", val: 4}] },
{ text: "Instansi Anda menerapkan aplikasi absensi berbasis GPS dan pengenalan wajah (face recognition). Beberapa rekan merasa keberatan karena menganggap hal ini melanggar privasi dan sering terjadi error saat melakukan absensi di lokasi lapangan yang sinyalnya lemah. Merespon hal ini, Anda akan...", options: [{text: "Mendukung keberatan rekan-rekan dan mengusulkan agar sistem absensi dikembalikan ke metode manual saja.", val: 1}, {text: "Tetap disiplin menggunakan aplikasi tersebut dan berbagi tips teknis dengan rekan lain cara mendapat sinyal stabil di lapangan.", val: 5}, {text: "Menggunakan aplikasi tambahan untuk memanipulasi lokasi GPS agar tetap bisa absen tepat waktu saat sinyal sulit.", val: 2}, {text: "Menyarankan rekan-rekan untuk absen hanya saat berada di kantor dan meminta dispensasi untuk kegiatan lapangan.", val: 3}, {text: "Melakukan absensi melalui foto manual (titip absen) kepada admin agar tetap tercatat hadir saat sistem sedang error.", val: 4}] },
{ text: "Instansi Anda mewajibkan penggunaan Multi-Factor Authentication (MFA) di mana setiap masuk ke sistem harus memasukkan kode dari ponsel. Suatu hari, Anda sedang terburu-buru menghadiri rapat penting dan tertinggal ponsel di rumah, sementara Anda harus segera mengunduh materi presentasi dari sistem tersebut. Tindakan Anda adalah...", options: [{text: "Meminta bantuan rekan kerja yang sedang di kantor untuk masuk ke sistem menggunakan akun mereka dan mengunduhkan materi untuk Anda.", val: 3}, {text: "Menghubungi unit TIK untuk meminta penonaktifan sementara fitur MFA pada akun Anda agar bisa masuk hanya dengan kata sandi.", val: 2}, {text: "Menggunakan fitur 'Cadangan Kode' atau menghubungi unit TIK untuk verifikasi identitas manual agar mendapatkan akses darurat yang sah.", val: 5}, {text: "Meminta anggota keluarga di rumah untuk membacakan kode MFA yang masuk ke ponsel Anda melalui telepon.", val: 4}, {text: "Menunda presentasi tersebut hingga Anda berhasil mengambil ponsel, meskipun risiko rapat menjadi tidak efektif.", val: 1}] },
{ text: "Di grup WhatsApp resmi kantor yang ditujukan untuk koordinasi pekerjaan, beberapa rekan mulai sering mengirimkan konten hiburan, jualan, hingga perdebatan politik yang tidak relevan. Hal ini membuat informasi penting mengenai instruksi pimpinan sering tertumpuk dan terlewatkan. Sebagai bagian dari grup tersebut, Anda akan...", options: [{text: "Memilih untuk keluar dari grup (left group) agar tidak terganggu dan meminta rekan terdekat mengabari jika ada info penting.", val: 1}, {text: "Menegur rekan-rekan tersebut dengan kalimat keras di dalam grup agar mereka merasa malu dan berhenti mengirim konten non-pekerjaan.", val: 2}, {text: "Secara sopan mengingatkan kembali tujuan awal pembuatan grup dan mengusulkan penggunaan fitur 'Pin Message' atau 'Star' untuk info penting.", val: 5}, {text: "Mengusulkan kepada admin grup untuk mengubah pengaturan agar hanya admin yang bisa mengirim pesan dalam grup tersebut.", val: 3}, {text: "Tetap diam untuk menjaga perasaan rekan kerja namun rajin melakukan scroll ke atas agar tidak ada informasi pekerjaan yang terlewat.", val: 4}] },
{ text: "Anda adalah bagian dari tim pengembang aplikasi layanan mandiri warga. Saat uji coba, ditemukan bahwa warga lansia dan penyandang disabilitas sensorik kesulitan menggunakan aplikasi karena ukuran tombol yang kecil dan kontras warna yang rendah. Sementara itu, tenggat peluncuran aplikasi tinggal dua hari lagi. Posisi Anda adalah...", options: [{text: "Tetap meluncurkan aplikasi sesuai jadwal dan merencanakan perbaikan fitur aksesibilitas pada pembaruan versi tahun depan.", val: 2}, {text: "Mengusulkan penundaan peluncuran satu hari untuk melakukan perbaikan cepat pada aspek kontras warna dan ukuran elemen navigasi.", val: 5}, {text: "Menyarankan penyediaan loket manual khusus bagi lansia dan penyandang disabilitas sebagai alternatif tanpa perlu mengubah aplikasi.", val: 3}, {text: "Mengabaikan masalah tersebut karena jumlah pengguna dari kalangan tersebut dianggap tidak mendominasi total pengguna aplikasi.", val: 1}, {text: "Meluncurkan aplikasi namun menyediakan video tutorial singkat yang menjelaskan cara penggunaan bagi warga yang kesulitan.", val: 4}] },
{ text: "Anda menemukan unggahan lama di media sosial pribadi Anda yang berisi keluhan emosional terhadap kebijakan lama pemerintah dengan bahasa yang kurang pantas. Saat ini, Anda telah menjadi ASN dan sedang dipertimbangkan untuk promosi jabatan yang memerlukan integritas tinggi di mata publik. Sikap Anda adalah...", options: [{text: "Segera menghapus atau mengarsipkan unggahan tersebut untuk menjaga reputasi profesional Anda sebagai ASN.", val: 5}, {text: "Membiarkan saja unggahan tersebut karena itu adalah hak privasi Anda di masa lalu sebelum menjadi ASN.", val: 1}, {text: "Mengubah pengaturan profil menjadi privat agar hanya teman dekat yang bisa melihat sejarah unggahan Anda.", val: 4}, {text: "Mengunggah klarifikasi atau permintaan maaf secara terbuka di media sosial terkait pernyataan masa lalu Anda.", val: 3}, {text: "Menutup akun media sosial tersebut selamanya dan membuat akun baru dengan identitas yang lebih formal.", val: 2}] },
{ text: "Saat sedang bekerja dari rumah menggunakan laptop kantor, Anda harus mengirimkan dokumen rahasia negara melalui sistem internal. Namun, koneksi internet rumah Anda tiba-tiba mati total, sementara tenggat pengiriman tinggal beberapa menit lagi. Tetangga Anda menawarkan penggunaan Wi-Fi miliknya tanpa password agar tugas Anda selesai. Tindakan Anda...", options: [{text: "Menerima tawaran tetangga tersebut agar laporan rahasia bisa terkirim tepat waktu demi kepentingan organisasi.", val: 1}, {text: "Menghubungi pimpinan untuk meminta izin keterlambatan karena adanya kendala teknis pada koneksi internet.", val: 3}, {text: "Menggunakan fitur hotspot/tethering dari ponsel pribadi yang memiliki keamanan sandi meskipun harus keluar biaya kuota.", val: 5}, {text: "Mencari kafe terdekat yang memiliki fasilitas internet cepat untuk mengirimkan dokumen tersebut secepat mungkin.", val: 2}, {text: "Mencoba memperbaiki koneksi internet rumah secara mandiri meskipun memerlukan waktu yang agak lama.", val: 4}] },
{ text: "Unit kerja Anda sering menggunakan aplikasi meeting online gratisan untuk koordinasi rutin. Namun, Anda menyadari bahwa data percakapan dan rekaman rapat mengenai strategi internal sering kali tersimpan di server luar negeri yang kebijakan privasinya tidak sepenuhnya selaras dengan standar keamanan instansi. Respon Anda adalah...", options: [{text: "Tetap menggunakan aplikasi tersebut karena gratis, mudah diakses semua rekan, dan sudah menjadi kebiasaan tim.", val: 1}, {text: "Mengusulkan penggunaan platform kolaborasi resmi milik pemerintah atau aplikasi yang servernya berada di dalam negeri.", val: 5}, {text: "Mengingatkan rekan-rekan agar tidak membicarakan hal-hal yang terlalu rahasia saat sedang melakukan rapat daring.", val: 4}, {text: "Mengikuti saja kemauan mayoritas rekan kerja agar tidak dianggap sebagai penghambat koordinasi tim.", val: 2}, {text: "Mencari aplikasi gratisan lain yang diklaim lebih aman untuk menggantikan aplikasi yang lama.", val: 3}] },
{ text: "Anda menemukan unggahan lama di media sosial pribadi Anda yang berisi keluhan emosional terhadap kebijakan lama pemerintah dengan bahasa yang kurang pantas. Saat ini, Anda telah menjadi ASN dan sedang dipertimbangkan untuk promosi jabatan yang memerlukan integritas tinggi di mata publik. Sikap Anda adalah...", options: [{text: "Segera menghapus atau mengarsipkan unggahan tersebut untuk menjaga reputasi profesional Anda sebagai ASN.", val: 5}, {text: "Membiarkan saja unggahan tersebut karena itu adalah hak privasi Anda di masa lalu sebelum menjadi ASN.", val: 1}, {text: "Mengubah pengaturan profil menjadi privat agar hanya teman dekat yang bisa melihat sejarah unggahan Anda.", val: 4}, {text: "Mengunggah klarifikasi atau permintaan maaf secara terbuka di media sosial terkait pernyataan masa lalu Anda.", val: 3}, {text: "Menutup akun media sosial tersebut selamanya dan membuat akun baru dengan identitas yang lebih formal.", val: 2}] },
{ text: "Saat sedang bekerja dari rumah menggunakan laptop kantor, Anda harus mengirimkan dokumen rahasia negara melalui sistem internal. Namun, koneksi internet rumah Anda tiba-tiba mati total, sementara tenggat pengiriman tinggal beberapa menit lagi. Tetangga Anda menawarkan penggunaan Wi-Fi miliknya tanpa password agar tugas Anda selesai. Tindakan Anda...", options: [{text: "Menerima tawaran tetangga tersebut agar laporan rahasia bisa terkirim tepat waktu demi kepentingan organisasi.", val: 1}, {text: "Menghubungi pimpinan untuk meminta izin keterlambatan karena adanya kendala teknis pada koneksi internet.", val: 3}, {text: "Menggunakan fitur hotspot/tethering dari ponsel pribadi yang memiliki keamanan sandi meskipun harus keluar biaya kuota.", val: 5}, {text: "Mencari kafe terdekat yang memiliki fasilitas internet cepat untuk mengirimkan dokumen tersebut secepat mungkin.", val: 2}, {text: "Mencoba memperbaiki koneksi internet rumah secara mandiri meskipun memerlukan waktu yang agak lama.", val: 4}] },
{ text: "Unit kerja Anda sering menggunakan aplikasi meeting online gratisan untuk koordinasi rutin. Namun, Anda menyadari bahwa data percakapan dan rekaman rapat mengenai strategi internal sering kali tersimpan di server luar negeri yang kebijakan privasinya tidak sepenuhnya selaras dengan standar keamanan instansi. Respon Anda adalah...", options: [{text: "Tetap menggunakan aplikasi tersebut karena gratis, mudah diakses semua rekan, dan sudah menjadi kebiasaan tim.", val: 1}, {text: "Mengusulkan penggunaan platform kolaborasi resmi milik pemerintah atau aplikasi yang servernya berada di dalam negeri.", val: 5}, {text: "Mengingatkan rekan-rekan agar tidak membicarakan hal-hal yang terlalu rahasia saat sedang melakukan rapat daring.", val: 4}, {text: "Mengikuti saja kemauan mayoritas rekan kerja agar tidak dianggap sebagai penghambat koordinasi tim.", val: 2}, {text: "Mencari aplikasi gratisan lain yang diklaim lebih aman untuk menggantikan aplikasi yang lama.", val: 3}] },
{ text: "Saat sedang berbelanja di pasar tradisional yang mulai menerapkan pembayaran via QRIS, Anda didatangi seseorang yang mengaku sebagai petugas bank. Ia menawarkan bantuan untuk memperbarui data akun dompet digital Anda agar mendapatkan promo belanja, lalu ia meminta Anda membacakan 6 digit angka yang baru saja masuk ke SMS ponsel Anda. Sikap Anda...", options: [{text: "Memberikan kode tersebut karena ia terlihat resmi dan Anda ingin segera mendapatkan promo belanja untuk menghemat pengeluaran.", val: 1}, {text: "Menanyakan identitas resminya terlebih dahulu, jika benar ia petugas bank, Anda baru akan memberikan kode tersebut.", val: 2}, {text: "Menolak dengan tegas dan menjelaskan bahwa kode tersebut bersifat rahasia, lalu segera menjauh dari orang tersebut untuk keamanan.", val: 5}, {text: "Mengabaikan orang tersebut dan tetap melanjutkan transaksi belanja Anda menggunakan metode tunai agar lebih aman dari penipuan.", val: 3}, {text: "Memberikan kode tersebut namun segera mengganti kata sandi akun dompet digital Anda setelah sampai di rumah.", val: 4}] },
{ text: "Di grup pesan instan RT/RW, seorang warga mengunggah rekaman CCTV yang memperlihatkan seseorang yang diduga melakukan pencurian di lingkungan Anda. Foto dan identitas orang tersebut disebarkan secara luas dengan ajakan untuk segera melakukan tindakan main hakim sendiri jika menemukannya. Sebagai anggota masyarakat, respon Anda adalah...", options: [{text: "Ikut menyebarkan foto tersebut ke grup lain agar lebih banyak warga yang waspada dan pelaku segera tertangkap.", val: 1}, {text: "Menghubungi pengurus RT secara pribadi untuk menyarankan agar bukti tersebut diserahkan kepada pihak kepolisian secara resmi.", val: 5}, {text: "Mengingatkan warga di grup agar tidak terpancing emosi dan menyarankan untuk menunggu instruksi dari aparat keamanan.", val: 4}, {text: "Tetap diam dan mengamati perkembangan informasi di grup agar tidak terlibat dalam konflik antar warga.", val: 2}, {text: "Menyarankan warga untuk mencari tahu alamat rumah terduga pelaku agar bisa dilakukan klarifikasi secara langsung oleh massa.", val: 3}] },
{ text: "Anda menemukan bahwa kelurahan di tempat tinggal Anda baru saja meluncurkan aplikasi layanan mandiri untuk pengurusan surat pengantar. Namun, banyak warga lanjut usia di sekitar rumah Anda merasa kesulitan dan justru kembali menggunakan cara manual yang memakan waktu lama. Tindakan Anda sebagai warga adalah...", options: [{text: "Membantu para lansia tersebut dengan cara meminjam ponsel mereka dan memasukkan semua data mereka melalui akun Anda.", val: 2}, {text: "Mengusulkan kepada pihak kelurahan untuk tetap membuka layanan manual sepenuhnya agar warga senior tidak merasa terpinggirkan.", val: 3}, {text: "Menawarkan diri untuk memberikan bimbingan singkat cara penggunaan aplikasi kepada warga senior saat pertemuan rutin warga.", val: 5}, {text: "Membiarkan hal tersebut karena merasa digitalisasi memang memerlukan waktu untuk bisa diterima oleh semua kalangan masyarakat.", val: 1}, {text: "Membuat video tutorial sederhana yang dibagikan ke grup warga agar mereka bisa mempelajarinya secara mandiri di rumah.", val: 4}] },
{ text: "Anda sering menggunakan aplikasi transportasi daring untuk mobilitas harian. Suatu hari, pengemudi yang mengantar Anda menghubungi nomor pribadi Anda melalui pesan instan di luar aplikasi untuk mengajak berkenalan karena merasa ada kecocokan saat berbincang di perjalanan. Sikap Anda menghadapi hal ini adalah...", options: [{text: "Membalas pesannya dengan sopan namun tegas bahwa Anda tidak nyaman dihubungi melalui jalur pribadi untuk urusan di luar layanan.", val: 4}, {text: "Mengabaikan dan memblokir nomor tersebut agar tidak mengganggu privasi Anda tanpa perlu memperpanjang masalah.", val: 3}, {text: "Melaporkan kejadian tersebut kepada penyedia layanan melalui fitur pengaduan resmi agar privasi data pengguna lebih terjaga.", val: 5}, {text: "Mengingatkan pengemudi tersebut bahwa tindakannya melanggar kode etik perusahaan dan mengancam akan memberikan bintang satu.", val: 2}, {text: "Menanggapi pembicaraan tersebut secara santai selama tidak ada tindakan yang mengarah pada ancaman keamanan fisik.", val: 1}] },
{ text: "Di perpustakaan daerah yang menyediakan fasilitas Wi-Fi gratis, Anda melihat beberapa pengunjung menggunakan jaringan tersebut untuk mengunduh dokumen berukuran sangat besar dan melakukan streaming video berkualitas tinggi, sehingga pengunjung lain yang ingin mengakses informasi riset merasa terganggu karena koneksi menjadi sangat lambat. Tindakan Anda adalah...", options: [{text: "Ikut melakukan hal yang sama untuk mengunduh kebutuhan Anda mumpung ada fasilitas internet gratis dari pemerintah.", val: 1}, {text: "Menggunakan perangkat lunak tambahan untuk memotong koneksi pengguna lain agar Anda mendapatkan kecepatan internet yang stabil.", val: 2}, {text: "Memberikan saran kepada pengelola perpustakaan untuk menerapkan pembatasan bandwidth atau pemblokiran situs tertentu demi kenyamanan bersama.", val: 5}, {text: "Menegur langsung pengunjung tersebut secara terbuka di dalam perpustakaan agar mereka merasa malu dan menghentikan aktivitasnya.", val: 3}, {text: "Mencari sudut ruangan lain yang memiliki sinyal Wi-Fi lebih kuat agar tetap bisa mengerjakan tugas Anda tanpa mempedulikan orang lain.", val: 4}] },
{ text: "Anda menerima pesan berantai di grup keluarga mengenai tautan pendaftaran bantuan jaminan kesehatan nasional yang mengharuskan pengisian data KTP dan foto selfie memegang identitas untuk mendapatkan pencairan dana instan. Beberapa anggota keluarga Anda yang berusia lanjut sudah bersiap untuk mendaftar. Respon Anda adalah...", options: [{text: "Segera mengecek kebenaran informasi tersebut melalui akun media sosial resmi instansi terkait, lalu menginformasikan hasilnya kepada keluarga.", val: 5}, {text: "Membiarkan anggota keluarga mendaftar terlebih dahulu untuk melihat apakah bantuan tersebut benar-benar cair atau tidak.", val: 1}, {text: "Mengingatkan keluarga untuk berhati-hati namun tidak melarang mereka karena mungkin saja bantuan tersebut memang benar adanya.", val: 3}, {text: "Menghapus pesan tersebut dari ponsel anggota keluarga yang lansia tanpa memberikan penjelasan agar mereka tidak terjebak penipuan.", val: 2}, {text: "Menyarankan keluarga untuk mendaftar menggunakan data palsu terlebih dahulu untuk menguji keamanan situs tersebut.", val: 4}] },
{ text: "Pemerintah mulai mensosialisasikan penggunaan IKD atau KTP Digital di ponsel untuk mempermudah akses layanan publik. Namun, saat Anda sedang mengurus administrasi di sebuah lembaga keuangan, petugas tetap meminta fotokopi KTP fisik sebagai syarat wajib karena mereka belum memiliki pemindai kode QR resmi. Sikap Anda menghadapi hambatan transisi ini adalah...", options: [{text: "Memprotes petugas tersebut karena dianggap tidak mendukung program digitalisasi pemerintah yang seharusnya sudah terintegrasi.", val: 2}, {text: "Mengalah dan segera mencari tempat fotokopi terdekat agar urusan administrasi Anda dapat diselesaikan hari itu juga.", val: 3}, {text: "Menunjukkan KTP Digital Anda, menjelaskan dasar hukumnya secara santun, dan menawarkan untuk mengirimkan tangkapan layar dokumen jika diperlukan.", val: 4}, {text: "Mengusulkan kepada manajemen lembaga tersebut untuk segera mengadopsi sistem pembaca IKD dan sementara itu meminta solusi alternatif tanpa fotokopi fisik.", val: 5}, {text: "Membatalkan urusan di lembaga tersebut dan mencari lembaga keuangan lain yang sudah mendukung penuh penggunaan sistem IKD.", val: 1}] },
{ text: "Anda menemukan sebuah situs web resmi pemerintah yang menyediakan data terbuka mengenai peta sebaran tingkat kesehatan di lingkungan Anda. Anda menyadari bahwa data tersebut sangat detail hingga bisa mengidentifikasi rumah warga tertentu yang memiliki riwayat penyakit sensitif. Mengetahui hal ini, tindakan Anda adalah...", options: [{text: "Mengunduh data tersebut dan membagikannya ke grup warga agar semua orang tahu siapa saja yang perlu diwaspadai di lingkungan tersebut.", val: 1}, {text: "Menggunakan data tersebut sebagai bahan riset pribadi untuk meningkatkan kewaspadaan kesehatan keluarga Anda tanpa memberitahu orang lain.", val: 3}, {text: "Melaporkan temuan tersebut kepada pengelola situs atau otoritas perlindungan data karena adanya potensi pelanggaran privasi individu pada data publik.", val: 5}, {text: "Mengabaikan temuan tersebut karena menganggap data yang dipublikasikan oleh pemerintah pastilah sudah melewati prosedur keamanan.", val: 2}, {text: "Membuat tulisan di blog pribadi mengenai kelemahan sistem keamanan data pemerintah dengan mencantumkan contoh data warga tersebut.", val: 4}] },
{ text: "Anda ingin membeli barang di platform e-commerce, namun penjual meminta Anda untuk melanjutkan percakapan melalui aplikasi pesan pribadi dengan alasan ingin memberikan diskon tambahan di luar sistem platform. Penjual tersebut juga meminta Anda melakukan transfer langsung ke rekening pribadinya. Tindakan Anda adalah...", options: [{text: "Menyetujui tawaran tersebut karena nominal diskon yang diberikan sangat besar dan penjual memiliki ulasan yang cukup baik.", val: 1}, {text: "Meminta penjual untuk tetap bertransaksi di dalam sistem platform meskipun tanpa diskon tambahan demi keamanan jaminan uang kembali.", val: 5}, {text: "Melakukan transfer setengah harga terlebih dahulu sebagai tanda jadi, dan sisanya dibayarkan setelah barang sampai di rumah.", val: 2}, {text: "Melaporkan akun penjual tersebut kepada pihak platform karena mencoba mengarahkan transaksi ke luar sistem resmi.", val: 4}, {text: "Menolak tawaran diskon tersebut dan mencari penjual lain yang tidak meminta komunikasi di luar aplikasi resmi.", val: 3}] },
];
